const RECIPES = [{"id":9,"name":"Stuffed Peppers","cat":"Meat","submittedBy":"Ann Marie VanOostendorp","description":"","time":"-","serves":"","ingredients":[["6 medium","Green Pepper"],["1 lb.","Ground Beef"],["1/3 cup, chopped","Onions"],["to taste x","Salt"],["to taste x","Pepper"],["1 lb. Can","Tomato"],["1/2 cup","Water"],["1/2 cup, uncooked long grain","Rice"],["1 tsp.","Worcestershire Sauce"],["4 oz. sharp srocess (shredded) - 1 cup","Cheese"]],"steps":["Cut off tops of peppers.","Remove seeds.","Pre-cook in salted boiling water for about 5 minutes.","Drain.","Fry ground beef with onion until meat is lightly browned.","Season with salt and pepper.","Add tomatoes, water, rice and Worcestershire sauce.","Cover and simmer until rice is tender (about 15 min.).","Stir in cheese.","Stuff peppers.","Stand upright in baking dish.","Bake uncovered 350 degrees for 20-25 minutes.","Serve."]},{"id":10,"name":"White Bean, Pasta & Sausage Soup","cat":"Soups","submittedBy":"John Shea","description":"Serve with Italian bread.","time":"3-1/2 min","serves":"4-6","ingredients":[["1& 1/2 cups dried Great Northern or other small white beans","Beans"],["12 oz","Hot Italian Sausage"],["1 large chopped","Onions"],["3-4 cloves, minced","Garlic"],["2 large chopped","Carrots"],["1&1/2 tsp.","Dried Basil"],["1&1/2. quarts","Chicken Broth"],["3 cups","Water"],["1 can 28 oz. Pear-shaped","Tomatoes"],["1&1/2 cups dry","Pasta, small shell-shaped"],["as needed (substitute Romano cheese if desired)","Parmesan Cheese"]],"steps":["Sort beans.  Discard debris.  Rinse and drain well.  Set aside.  Remove and discard casings from sausages.  Crumble meat into bite-sized chunks into the bottom of a 5-6 quart pan.  Cook over medium heat, stirring occasionally, until lightly browned (about 3-5 min.).  Discard all but 2 tablespoons of the fat.  (If the sausage does not leave that much fat, add an appropriate amount of olive oil to make 2 tablespoons, or drain all of the fat and add 2 tablespoons of fresh olive oil).  Add onion, garlic and carrot.  Cook, stirring","often, until the onion begins to soften (about 2-3 min).  Stir in beans, basil, broth and water.  Bring to a boil; reduce heat, cover and boil gently until beans are tender to the bite (about 2\u00bd hours).  Pour can of tomatoes with their liquid into a casserole dish.  Break the tomatoes up into smaller pieces with a spoon.  Prepare pasta in boiling water, al dente.  Add cut-up tomatoes and their liquid, to the soup.  Stir in pasta.  Bring back to a boil, and let it boil gently for about 5 minutes.  Serve."]},{"id":11,"name":"Festive Penne","cat":"Pasta","submittedBy":"John Shea","description":"","time":"45 min","serves":"4-6","ingredients":[["1/2 lb.","Ground Sirloin"],["1/2 lb.","Ground Pork"],["2 medium, chopped","Onions"],["4 cloves, minced","Garlic"],["12-14 chopped fresh plum (remove stems).","Tomatoes"],["3/4 cup","Chicken Broth"],["4 Tbsp.Tbsp.","Olive oil"],["2 tsp.","Oregano"],["1&1/2 tsp.","Crushed Red Pepper"],["3 tbsp.","Tomato Paste"],["2 tbsp.","Butter"],["to taste x","Salt"],["to taste x","Pepper"],["1 lb. Dry","Penne Pasta"]],"steps":["In large frying pan (I mean large with high sides) brown the ground sirloin and the ground pork in 1 tablespoon of olive oil over medium heat for about 8 minutes. (Make sure meat is thoroughly browned.)  Add salt and pepper to meat while browning.","Drain oil from pan, remove meat and set aside.","In same frying pan, over medium heat, brown onion and garlic in 3 tablespoons of olive oil for 8 minutes, stirring occasionally.","Then add tomatoes, chicken broth, oregano, crushed red pepper and tomato paste to frying pan.","Cook for an additional 8 minutes, stirring occasionally.","Add meat and butter to frying pan and cook for another 8 minutes, stirring occasionally.","Meanwhile, cook pasta (al dente, of course) and drain.","Place the drained pasta into a large serving dish.","Pour the meat sauce over the pasta and mix well.","Serve with grated Parmesan or Romano cheese and Italian bread."]},{"id":12,"name":"Italian Sausage Pasta with Basil","cat":"Pasta","submittedBy":"John Shea","description":"","time":"40 min","serves":"4-6","ingredients":[["1 lb. Casings removed","Hot Italian Sausage"],["1 large, chopped","Onions"],["2 medium, seeded and chopped","Green Bell Pepper"],["4 cloves, minced or pressed","Garlic"],["1 35 oz. Can (plum tomatoes) with liquid","Tomatoes"],["1 lb. Dry (not coiled, straight)","Vermicelli Pasta"],["3-4 tbsp.","Dry Basil"],["1/3 cup chopped, fresh","Parsley"],["3/4 cup grated (or Romano cheese or a mixture of both)","Parmesan Cheese"],["2/3 cup","Olive oil"]],"steps":["Crumble the sausage into bite-sized pieces into a wide and deep frying pan.  Cook the sausage over medium heat, stirring often until the meat is lightly browned.  Add onion and bell pepper; continue to cook, stirring until onion is soft, but not brown (about 5 minutes).  Spoon off and discard excess fat, if any.  Put the tomatoes into a dish and break them up with a spoon into smaller pieces.  Stir the tomatoes, their liquid, and garlic into the pan.","Increase heat to medium-high and bring the mixture to a boil.  Once boiling, reduce the heat and boil gently, uncovered, stirring often, until slightly thickened (about 10-15 minutes).  Meanwhile, cook the Vermicelli.  While the Vermicelli water is boiling or while the pasta is cooking, place a large, oven-proof serving bowl into your oven, set at a low temperature (150 degrees) to get the bowl warm.  Remove the bowl from the oven and combine the basil, parsley, cheese and olive oil in the bowl.  Add the cooked Vermicelli to the","bowl and mix it lightly with those ingredients (This will require 2 forks).  Top this mixture with the sausage-tomato sauce from the frying pan and mix well.  Serve with freshly grated Parmesan or Romano cheese and Italian bread.  Serves 4-6."]},{"id":14,"name":"Zucchini Soup","cat":"Soups","submittedBy":"Angie Dellos","description":"I discovered this when I had a garden with more zucchini than I knew what to do with!  Very tasty.","time":"-","serves":"6","ingredients":[["3 lbs., cup up (Remove soft inner part, if large)--about 5 small zucchini","Zucchini"],["1 medium","Onions"],["2 cubes","Bouillon"],["2 cups","Water"],["1 tsp.","Dry Basil"],["4 slices (uncooked) cut in pieces","Bacon"],["to taste","Pepper"]],"steps":["Place all ingredients in a 3 quart sauce pan and boil for 30 minutes.","Cool.","Puree a small amount at a time (so it doesn't overflow) in a food processor.","Return to saucepan.","Heat.","Serve with croutons and Parmesan cheese."]},{"id":15,"name":"Calamari (Stuffed Squid)","cat":"Fish","submittedBy":"Angie Dellos","description":"Pronounced (kahl-a-mod).  This is the way I remember my mother making this!  Serve over Linguine pasta.","time":"","serves":"","ingredients":[["3 lb. Box (about 20 pieces)","Squid"],["2","Eggs"],["1/3 cup","Cheese"],["1/3 cup","Breadcrumbs"],["1/4 tsp.","Salt and Pepper"],["to taste","Parsley"],["","Onions"],["1 clove, crushed","Garlic"],["1 tsp.","Parsley"],["1 can (1 lb. 12 oz.)","Tomatoes"],["1 Tbsp. (optional)","Pignoli (peen yoh lee) Nuts"]],"steps":["Wash and clean squid (including tentacles).","Set aside.","Make the filling of eggs, cheese, bread crumbs, garlic, salt, pepper, parsley and nuts.","This filling will be soft and loose.","Stuff squid only half onion, garlic, and parsley.","Add tomatoes.","Cook 30 to 45 minutes.","Add stuffed squid to sauce and cook 30 minutes more.\\r"]},{"id":16,"name":"Mexican Chili Bean Salad","cat":"Salads","submittedBy":"Angie Dellos","description":"Low in Fat!  Makes a large amount--good for a crowd.  If you like a more Italian flavor, substitute parsley for cilantro.","time":"-","serves":"","ingredients":[["1 large (about 8 oz.), seeded and coarsley chopped","Red Bell Pepper"],["1/3 cup chopped, fresh","Cilantro"],["1/2 cup chopped","Green Onion"],["1 can (15-17 oz.) whole kernel corn","Corn"],["1 can (15-17 oz.)","Pinto Beans"],["1 can (15-17 oz.)","Kidney Beans"],["1 can (15-17 oz.)","Garbanzo Beans"],["1 can (4 oz.)","Diced Green Chilies"],["1/4 cup","Red Wine Vinegar"],["2 tbsp.","Salad Oil"],["1/4 tsp.","Pepper"],["1 tsp.","Chili Powder"],["1 tsp.","Ground Cumin"]],"steps":["In a colander, rinse Garbanzo, Kidney and Pinto beans.  Drain well.  Mix beans and corn together with green onion, cilantro, red bell pepper, and green chilies.  Add dressing of wine vinegar, salad oil, pepper, chili powder and ground cumin.  Cover and chill at least 1 hour or until the next day.  Stir occasionally.  Serve.",";"]},{"id":17,"name":"Eggplant Casserole","cat":"Meat","submittedBy":"Angie Dellos","description":"","time":"","serves":"","ingredients":[["1","Eggplant"],["1 clove, crushed","Garlic"],["1/2 tsp.","Salt and Pepper"],["1 lb.","Ground Beef"],["1 clove, crushed","Garlic"],["2","Eggs"],["2 Tbsp.","Parmesan Cheese"],["2 Tbsp.","Breadcrumbs"],["2 Tbsp.","Parsley"],["1/2 tsp.","Salt and Pepper"],["to cover bottom of frying pan","Oil"],["homemade or bought","Spaghetti Sauce"],["1/2 pound, cut in slices","Mozzarella Cheese"]],"steps":["Peel eggplant and cut in 1\" cubes.","Fry eggplant in a small amount of oil with garlic,  salt and pepper.","Blot on paper towel after frying.","Fry ground beef until done.","Remove from heat.","In a large bowl, add crushed garlic, eggs, cheese, bread crumbs, parsley, salt and pepper to the cooked ground beef.","Add eggplant and mix together.","Line a 1\u00bd-qt. casserole with Spaghetti sauce.  (Bottled or canned Spaghetti sauce works fine--if too thick, thin with water.).","Add a layer of eggplant/meat mixture.","Top with Mozzarella cheese.","Repeat layers until mixture is used up.","End with meat on top.","Sprinkle with Parmesan cheese.","Bake 350 degrees for 1 hour.\\r"]},{"id":18,"name":"Easy Cobbler","cat":"Desserts","submittedBy":"Bette Ann DiFulvio","description":"This is great served WARM with vanilla ice cream or whipped cream!  Easy--a family favorite in our home.\\r\\n","time":"","serves":"","ingredients":[["1/4 cup","Oil"],["1 White","Cake Mix"],["2 slightly beaten","Eggs"],["1/2 cup","Water"],["1 can (your favorite)","Pie Filling"]],"steps":["Pour oil into a 9x13\u201d cake pan.","Add cake mix, water, and eggs.","Mix with fork so all is wet -- no need to mix vigorously.","Spoon pie filling over cake and bake according to cake mix directions.\\r"]},{"id":19,"name":"Lemonade Pie","cat":"Desserts","submittedBy":"Bette Ann DiFulvio","description":"A great friend and cook gave me this recipe because it's fast and easy.  I make it all the time, and my family loves it.  Very refreshing!\\r\\n","time":"-","serves":"","ingredients":[["2 small tubs (Lite)","Cool Whip"],["1 small can","Frozen Lemonade"],["5 cups","Ice Cream"],["1","Graham Cracker Pie Crust"]],"steps":["Combine and mix cool whip, lemonade and ice cream until softened.","Turn into pie crust.","Freeze and eat!\\r"]},{"id":20,"name":"Lasagna with Spinach and Sausage","cat":"Pasta","submittedBy":"Bette Ann DiFulvio","description":"I have made this for 25 years!!  Serve with garlic bread, Italian salad and a hearty red wine.","time":"-","serves":"","ingredients":[["3 lbs.","Ricotta Cheese"],["2 boxes, chopped (thawed and drained thoroughly)","Frozen Spinach"],["4","Eggs"],["1 pound, cooked and drained","Pork Sausage"],["1 cup","Mozzarella Cheese"],["1/2 cup","Parmesan Cheese"],["to taste","Salt and Pepper"],["6 sheets (available at Roma","Fresh Pasta Lasagna"],["2 quarts (your own homemade or bought)","Spaghetti Sauce"]],"steps":["Mix ricotta, spinach, eggs, sausage, cheeses, salt and pepper.","In a lasagna pan, layer Spaghetti sauce, pasta sheets (or cooked lasagna strips) and ricotta  mixture alternately.","End layering with sauce.","Bake 350 degrees for 1.5 hours.","Let stand for 30 minutes (minimum) before cutting and serving."]},{"id":21,"name":"Fried Bow Ties","cat":"Desserts","submittedBy":"Minnie DiFulvio","description":"","time":"-","serves":"","ingredients":[["3","Eggs"],["1 tbsp.","Sugar"],["1 tsp.","Vanilla"],["as much as it takes to make a medium dough mix","Flour"],["fill deep pan half way to top","Cooking Oil"],["Enough to roll cookies into","Powdered Sugar"]],"steps":["Mix eggs, sugar and vanilla.","Add flour.","Start with 2 cups and add \u00bd cup at a time until you can knead the dough.","Place in a lightly greased bowl and cover for 1 hour.","Cut dough in pieces and put each piece through macaroni machine until the piece is long and thin.  (If you don't have a machine, use a rolling pin to roll the dough paper thin.)  Place on board, and cut with a pastry wheel (to make a fluted edge) into 6\" strips.","Tie each strip into a loose single knot and deep fry quickly in a pan of hot oil.","Remove knot-cookie from oil, and place on paper towel to absorb oil.","Roll in powdered sugar.\\r"]},{"id":22,"name":"Cod Fish","cat":"Fish","submittedBy":"Minnie DiFulvio","description":"I like this better fried, but you could bake it if you wish.  Garnish with lemon wedges.","time":"-","serves":"","ingredients":[["1 pound","Cod Fish"],["1","Eggs"],["2 Tbsp.","Parmesan Cheese"],["1/4 tsp.","Garlic Powder"],["1/4 tsp.","Salt and Pepper"],["1/2 cups","Italian-Seasoned Breadcrumbs"],["to cover bottom of frying pan","Vegetable Oil"],["wedges (optional)","Lemon"]],"steps":["Cut fish in squares.","Scramble egg.","Add grated cheese, garlic powder, salt and pepper.","Marinate fish in this mixture.","Dip each marinated piece of fish into bread crumbs and deep fry.  \\r \\r Option: Bake 350 degrees for \u00bd hour.\\r"]},{"id":23,"name":"Caramel Peanut Bars","cat":"Desserts","submittedBy":"Anne Romanowski","description":"This recipe came from \"Taste of Home\", my favorite home-cooking magazine.  These are as rich as a candy bar, so you can cut them small.\\r\\n","time":"-","serves":"4","ingredients":[["1 14 ounce bag","Caramels"],["3/4 cups melted","Butter or Margarine"],["3/4 tsp.","Baking Soda"],["1&1/4 cups packed","Brown Sugar"],["1&1/2 cups","Flour"],["1&1/2 cups","Quick Cooking Oats"],["1/2 cup","Whipping Cream"],["1&1/2 cups (9 oz.)","Semi-sweet Chocolate Chips"],["3/4 cups, chopped","Peanuts"]],"steps":["In a bowl, combine oats, flour, brown sugar and baking soda.","Stir in melted butter.","Set aside 1 cup of this mixture for topping.","Press remaining mixture into a greased 13x9\u201d pan.","Bake 350 degrees for 10 minutes or until lightly browned.","Meanwhile, combine caramels and cream in a heavy saucepan, and cook over low heat until melted, stirring often.","Sprinkle chocolate chips and peanuts over the baked crust.","Top with caramel mixture.","Sprinkle with reserved oat mixture.","Bake for 15 more minutes or until topping is golden brown.","Cool completely before cutting."]},{"id":24,"name":"Ranger Cookies","cat":"Desserts","submittedBy":"Anne Romanowski","description":"This is one of my favorite recipes from my mom. (Lorraine Coughlin).  It may take some experimenting, but you can eat all the rejects!","time":"-","serves":"","ingredients":[["1&1/3 cups","Margarine"],["1 cup","Sugar"],["1 cup","Brown Sugar"],["2","Eggs"],["2 cups","Flour"],["1/2 tsp.","Salt"],["1 tsp.","Vanilla"],["1 tsp.","Baking Soda"],["1/2 tsp.","Baking Powder"],["2 cups","Oatmeal"],["2 cups","Rice Krispies"]],"steps":["Mix ingredients by hand, adding oatmeal last.","Then fold in rice krispies gently, at the end.","Drop from spoon onto baking sheet.","Bake 350 degrees about 9 minutes.  (They are done when the edges are golden brown and the center is slightly wet looking.)  Let them cool another few minutes so that the center will dry, making the cookie more chewy."]},{"id":25,"name":"Mom's Sponge Cake","cat":"Desserts","submittedBy":"Anne Romanowski","description":"This is a cake my mom (Lorraine Coughlin) made often.  She got it from her Godmother.  I know Aunt Marie and Aunt Carol make it too.  I remember my mom telling me HER mom (Anna Roma) made it too, and she would be allowed to have big scoopfuls of the batter to taste.  Terry and I would fight over who got to lick the bowl.  Terry would usually get the small bowl (the egg yolk mix) and I got the larger one (from after the egg yolk mix was added to the white).  I also remember that if you eat the cake too fast, it's guaranteed to give you hiccups.  I guess it's because it's so light and airy!  Serve alone or with strawberries and whipped cream.\\r\\n","time":"-","serves":"","ingredients":[["1&1/4 cups","Flour"],["1 cup","Sugar"],["1/2 tsp.","Baking Powder"],["1/4 cup","Water"],["1 tsp","Vanilla"],["1/2 tsp.","Salt"],["1 tsp.","Cream of Tartar"],["1/2 cups","Sugar"]],"steps":["Sift together flour, sugar and baking powder.","Using a small mixing bowl, beat together egg yolks, water and vanilla.","Slowly add sifted ingredients to this.","Set aside.","In larger bowl, beat egg whites with salt and cream of tartar until they become stiff.","Continue to beat adding sugar one teaspoon at a time until stiff.","Pour the yellow mixture into the whites.","Fold gently with spatula until batter is all one color.","Bake 350 degrees for 40-50 minutes in a sponge-cake (2 piece) pan.","DO NOT GREASE THE PAN.  (This I learned from experience.) Turn upside-down to cool.\\r"]},{"id":26,"name":"Orange Creamsickle Dessert","cat":"Desserts","submittedBy":"Ann Marie VanOostendorp","description":"","time":"-","serves":"","ingredients":[["1 large package (Orange)","Jell-O"],["1 cup, boiled","Water"],["1 cup (undiluted) partially defrosted","Frozen Orange Juice"],["1 medium can (with juice)","Crushed Pineapple"],["1 container (9 oz.)","Cool Whip"],["1 can (drained and cut up)","Mandarin Oranges"],["1 (4 oz. Size) vanilla flavor","Instant Pudding"],["2 cups, cold","Milk"]],"steps":["Boil water.","Add jello until well dissolved.","Add orange juice and mix well.","Add pineapple (with juice) and oranges.","Mix well and put aside, stirring occasionally.","Prepare pudding according to package directions using 2 cups cold milk.","Fold in Cool Whip.","Fold this mixture into orange mixture, blending thoroughly.","Chill at least 3 hours.\\r"]},{"id":27,"name":"Herb-Baked Fish","cat":"Fish","submittedBy":"Ann Marie VanOostendorp","description":"","time":"-","serves":"","ingredients":[["1&1/2 cups hot chicken","Bouillon"],["1/2 cup uncooked regular","Rice"],["1/4 tsp.","Italian Seasoning"],["1/4 tsp.","Garlic Powder"],["1 (10 oz. Package) frozen, thawed and drained","Broccoli"],["1 can","Fried Onions"],["1 tbsp.","Parmesan Cheese"],["1 lb.","Fresh Fish Fillets"],["to taste","Paprika"],["","Cheddar Cheese"]],"steps":["Combine hot bouillon, rice, seasoning, and garlic powder in an 8x12\u201d baking dish.","Bake uncovered for 10 minutes.","Top with broccoli, \u00bd can onions and Parmesan cheese.","Place fish (I usually use Orange Roughy or Haddock.) diagonally down center of dish, sprinkle with paprika, and bake covered 375 degrees for 20-25 minutes.","Loosen rice with fork, top with cheddar cheese and the rest of the onions.","Bake 3 more minutes (uncovered) until golden brown.\\r"]},{"id":28,"name":"Vincy's Raised Dough Knots","cat":"Desserts","submittedBy":"Lillian Pisani","description":"I got this recipe from my mother-in-law.  It's been in the family for generations.   These are good cookies for dunking!","time":"-","serves":"","ingredients":[["1 cake (or 1 dry packet)","Yeast"],["1/4 cup","Shortening"],["6 beaten","Eggs"],["1/2 cup","Sugar"],["1 tsp.","Salt"],["5 cups","Flour"],["","Unknown"],["1/2 cup, melted","Butter or Margarine"],["1 cup, chopped","Walnuts"]],"steps":["Dissolve yeast in water.","Add shortening, eggs, sugar and salt.","Add flour gradually until you can work with the dough--(approx. 5 cups).","Place in a bowl and cover until dough doubles.","Punch down.","Raise 15 more minutes.","Cut dough in 1/2\" pieces, roll each piece and tie in a single knot.","Place knots on cookie sheet and raise again for one hour.","Bake 425 degrees for 15 minutes.","Brush with melted butter and nuts.","Sprinkle cinnamon and sugar on top or frost with light confectionery sugar frosting."]},{"id":31,"name":"Italian Cheesecake","cat":"Desserts","submittedBy":"Lillian Pisani","description":"","time":"-","serves":"","ingredients":[["","Graham Cracker Crumbs"],["1 lb.","Ricotta Cheese"],["1 lb.","Cream Cheese"],["1 pint","Sour Cream"],["3","Eggs"],["1&1/2 cups","Sugar"],["3 Tbsp.","Flour"],["1 Tbsp.","Vanilla"],["3 Tbsp.","Corn Starch"],["1/4 lb, Melted","Butter"]],"steps":["Grease a spring-form pan and sprinkle with graham cracker crumbs.","Mix remaining ingredients and pour into greased pan.","Do not pre-heat oven.","Bake 350 degrees for 1 hour.","Leave in oven until cool.\\r"]},{"id":32,"name":"Pasta with Artichokes","cat":"Pasta","submittedBy":"Diane Randesi","description":"This couldn't be easier--takes 20 minutes from start to finish! It looks and tastes like you fussed.","time":"15 min","serves":"4-6","ingredients":[["3 Tbsp.","Wine Vinegar"],["3 cut up","Green Onion"],["1/2 jar (8.5), cut up (packed in oil--include the oil)","Sun-dried tomatoes"],["2 jars (6.5 oz.), cut up (packed in oil - include the oil)","Artichoke Hearts"],["5-6 cut up pieces (optional)","Pepperoni"],["3/4 lb.","Farfalle (Far fall leh) Bow Tie Pasta"],["6-7 bunches flowerets","Broccoli"],["1/2 cup","Parmesan Cheese"]],"steps":["While you are cooking the pasta in salted water (20 minutes--al dente), combine the first five ingredients in your pasta serving bowl.","Set aside.","During the last two minutes of cooking the pasta, add the broccoli flowerets.","Drain pasta and broccoli together.","Add cooked pasta and broccoli to the serving bowl.","Top with Parmesan cheese.","Toss and serve.\\r"]},{"id":33,"name":"Potato Casserole","cat":"Non-Meat","submittedBy":"Gail Dellos","description":"","time":"1 min","serves":"6-8","ingredients":[["2 pounds with onions & peppers","Frozen O'Brien Potatoes"],["2 cups, grated","Cheddar Cheese"],["1 can","Cream of Chicken Soup"],["1 pint","Sour Cream"],["1/2 cup, chopped (only include if frozen potatoes do not contain onions)","Onions"],["2 cups","Corn Flakes"],["1 cup","Butter or Margarine"]],"steps":["Defrost and separate potatoes.","Mix potatoes, cheese, soup, sour cream, 1/2 cup of margarine and onion.","Spread into buttered 3 qt. baking dish.","Top with Cornflakes soaked in the other 1/2 cup margarine.","Bake 350 degrees for 45 minutes.\\r"]},{"id":34,"name":"Smoothie","cat":"Miscellaneous","submittedBy":"Joey Randesi","description":"Makes one serving.  That's all you need.","time":"5 minutes","serves":"one","ingredients":[["1","Banana"],["2&1/2 cups","Orange Juice"],["","Frozen Stawberries"],["1 tbsp.","Sugar"]],"steps":["In a blender, place banana and orange juice.","Blend.","Add 3 or 4 frozen strawberry at a time and mix at \"grind\" speed until smooth.","Continue adding berries until smoothie is desired consistency.","If too tart, add sugar and blend well."]},{"id":35,"name":"Autumn Butternut Casserole","cat":"Non-Meat","submittedBy":"Joyce Delorey","description":"Delicious with Thanksgiving Dinner!","time":"-","serves":"8","ingredients":[["3 cups, mashed","Butternut Squash"],["1/4 cup","Butter or Margarine"],["1 Tbsp.","Brown Sugar"],["1/4 tsp.","Salt"],["dash","White Pepper"],["6 cups (about 2 pounds), sliced unpared","Apples"],["1/4 cup","Sugar"],["1&1/2 cups, coarsely crushed","Cornflakes"],["1/2 cup, chopped","Pecans"],["1/2 cup","Brown Sugar"],["2 Tbsp.","Butter or Margarine"],["1/2 cup","Brown Sugar"],["2 Tbsp.","Butter or Margarine"]],"steps":["Season squash with butter, brown sugar, salt and white pepper.  \\r Heat 1\u00bd additional tablespoons of butter in skillet.","Add apples.","Sprinkle with sugar.","Cover and simmer over low heat until barely tender (about 5 minutes).  \\r Spread in 3-quart casserole.","Spoon mashed squash evenly over apples.","Mix Cornflakes with pecans, brown sugar and butter.","Sprinkle over squash.","Bake 350 degrees for 15 minutes.\\r"]},{"id":36,"name":"Cinnamon Twists","cat":"Desserts","submittedBy":"Joyce Delorey","description":"This is a recipe that I got from my mother (Kay English).","time":"-","serves":"","ingredients":[["2 cups","Sour Cream"],["6 Tbsp.Tbsp.","Sugar"],["1/4 tsp.","Baking Soda"],["2 packages","Yeast"],["2","Eggs"],["4 tsp.","Shortening"],["6 cups","Flour"],["as needed to cover the 12x6 rectangle","Butter"],["as needed","Cinnamon"],["as needed","Sugar"],["Mix with small amounts of water for thin frosting","Confectioner's Sugar"]],"steps":["Heat sour cream.","Add sugar, baking soda, yeast, eggs, shortening and flour.","Knead dough and let rise for 1 hour.","Divide dough in half.","Roll each half into a 12x6\u201d rectangle.","Butter and sprinkle with cinnamon and sugar.","Fold rectangle in half and cut into strips.","Twist strips and place on greased cookie sheet.","Let rise for 1 more hour.","Bake 375 degrees for 8-10 minutes.","Drizzle with thin powdered sugar frosting."]},{"id":37,"name":"Frying Pan Cookies","cat":"Desserts","submittedBy":"Joyce Delorey","description":"Another recipe from my mom.","time":"-","serves":"","ingredients":[["1&1/2 cups","Dates"],["2","Eggs"],["1 cup","Sugar"],["1 Tbsp.","Butter"],["3 cups","Rice Krispies"],["1 cup","Coconut"]],"steps":["In a saucepan, heat dates, eggs, sugar and butter.","Remove from heat.","Add Rice Krispies.","Roll into 1\" balls.","Roll into coconut or powdered sugar.","Let cool."]},{"id":38,"name":"Crustless Ricotta Pie","cat":"Desserts","submittedBy":"Joyce Delorey","description":"Ricotta is pronounced (rdi-gaut'-a).  A recipe from my mother (Kay English).","time":"-","serves":"","ingredients":[["3 pounds","Ricotta Cheese"],["12","Eggs"],["1&1/2 cups","Sugar"],["2 Tbsp.","Flour"],["1/2 cup","Milk"],["2 tsp. (may substitute your favorite flavoring)","Vanilla"]],"steps":["Combine and mix all ingredients.","Place in a 9x13\u201d greased pan.","Bake 350 degrees for 1 hour."]},{"id":39,"name":"Nana's Irish Bread","cat":"Miscellaneous","submittedBy":"Joyce Delorey","description":"","time":"-","serves":"","ingredients":[["3 Tbsp.","Sugar"],["2 cups","Flour"],["1 scant tsp.","Salt"],["5 tsp.","Baking Powder"],["1/4 cup","Shortening"],["1 cup","Raisins"],["1 Tbsp.","Caraway Seeds"],["1","Eggs"],["as needed so that dough is not too stiff","Milk"]],"steps":["Mix all ingredients together.","Place in a greased loaf pan and bake 350 degrees for 1 hour."]},{"id":40,"name":"Granola","cat":"Miscellaneous","submittedBy":"Joyce Delorey","description":"Serve with milk, or as a snack!","time":"-","serves":"","ingredients":[["4 cups","Rolled Oats"],["2 cups","Wheat Germ"],["1 cup (may substitute chopped nuts)","Coconut"],["1 tsp.","Cinnamon"],["2 Tbsp.","Brown Sugar"],["1/2 cup","Honey"],["1/3 cup","Salad Oil"],["1 tsp.","Vanilla"],["1/2 cup (optional)","Raisins"]],"steps":["Mix the 5 dry ingredients together (include raisins, if desired).","Add honey and mix well.","Add oil and vanilla and mix thoroughly.","Spread in ungreased 9x13 pan.","Bake 325 degrees for 20 minutes.","Stir occasionally.","When cool, store in a covered container."]},{"id":41,"name":"Peanut Butter Chicken","cat":"Meat","submittedBy":"Joyce Delorey","description":"Moist and delicious!  Serve with rice pilaf and salad.","time":"-","serves":"","ingredients":[["1/2 cup","Peanut Butter"],["1/2 cup","Peanut Oil"],["1/4 cup","White Wine Vinegar"],["1/4 cup","Soy Sauce"],["1/4 cup, fresh","Lemon Juice"],["4 cloves, minced","Garlic"],["1 minced","Dried Red Chili Pepper"],["2 tsp., fresh, chopped","Ginger"]],"steps":["Marinate chicken overnight.","Place on skewers and barbecue.","Serve."]},{"id":42,"name":"Spinach Salad","cat":"Salads","submittedBy":"Joyce Delorey","description":"Serve with French Bread","time":"-","serves":"","ingredients":[["1 package, cleaned and dried","Spinach"],["1 can, slivered","Almonds"],["2 chopped","Hard-cooked eggs"],["4 slices, cooked, finely chopped","Bacon"],["1 cup","Vegetable Oil"],["1 tsp.","Worcestershire Sauce"],["1/3 cup","Catsup"],["1/2 cup","Sugar"],["2 tsp.","Salt"],["1 small, chopped","Red Onion"]],"steps":["Mix first four ingredients together.","Mix next six ingredients to make the dressing.","Combine.","Serve with French Bread."]},{"id":43,"name":"Jeweltoned Fruitcake","cat":"Desserts","submittedBy":"Joyce Delorey","description":"If you like fruitcake, this is the BEST!","time":"-","serves":"","ingredients":[["2 cups (8 oz.)","Dried Apricots"],["2 cups (8 oz.)","Pitted Dates"],["1 cup","Red Candied Cherries"],["1 cup","Green candied Pineapples"],["3/4 cup","Flour"],["3/4 cup","Sugar"],["1/2 tsp.","Baking Powder"],["1/2 tsp.","Salt"],["3","Eggs"],["1&1/2 tsp.","Vanilla"]],"steps":["Heat oven to 300 degrees.","Line loaf pan with aluminum foil.","Grease.","Leave apricots, dates, cherries, pineapples and nuts whole.","Combine all ingredients in a large bowl and mix thoroughly.","Spoon into prepared pan and spread evenly.","Bake 350 degrees for 1\u00be hours or until toothpick in center of cake comes out clean.","Remove from pan and cool.\\r"]},{"id":44,"name":"Molasses Ginger Snaps","cat":"Desserts","submittedBy":"Joyce Delorey","description":"","time":"-","serves":"","ingredients":[["3/4 cup","Margarine"],["1 cup","Sugar"],["1/4 cup","Molasses"],["2 cups","Flour"],["1 tsp.","Baking Soda"],["1/4 tsp.","Salt"],["1 tsp.","Cinnamon"],["1 tsp.","Cloves"],["1 tsp.","Ginger"]],"steps":["Combine and mix together all the ingredients.","Shape into 1\u00bd\" balls.","Roll in sugar.","Place wide apart on slightly greased cookie sheet.","Bake 375 degrees for 8-10 minutes.\\r"]},{"id":45,"name":"Macaroons","cat":"Desserts","submittedBy":"Diane Randesi","description":"Simple, fast, good, low fat.","time":"30 min","serves":"","ingredients":[["1&1/3 cups","Coconut"],["1/2 cup","Sugar"],["2 Tbsp.","Flour"],["1/2 tsp.","Salt"],["2","Egg Whites"],["1/2 tsp.","Almond Extract"]],"steps":["Combine and mix coconut, sugar, flour and salt.","Stir in unbeaten egg whites and almond extract.","Drop by teaspoonful onto a greased and floured cookie sheet.","Bake 350 degrees for 20 minutes.","Option: Add crushed almonds.\\r"]},{"id":46,"name":"Parmesan Dijon Chicken","cat":"Meat","submittedBy":"Diane Randesi","description":"","time":"45 min","serves":"12","ingredients":[["2-4 slices","White Bread"],["1 cup, lightly packed","Parmesan Cheese"],["1/3 cup, melted","Butter or Margarine"],["1 cup","Dijon Mustard"],["5 Tbsp.","Dry White Wine"],["12 Boned and skinned (3-4 oz. Each)","Chicken Breasts"]],"steps":["Tear bread in pieces.","Whirl in a blender or food processor until coarse crumbs form.","Pour crumbs into a 9\" pan.","Toss with cheese and butter.","In another 9\" pan, mix mustard and wine.","Coat chicken with mustard mixture.","Dip rounded side of each chicken breast into crumb mixture.","Set chicken, crumb side up, slightly apart, in a greased 10x15\u201d pan.","Bake at 500 degrees (yes, 500!) until golden, and chicken is white in the thickest part Cut into one to test it\u2014about 15 minutes.\\r"]},{"id":47,"name":"Crispy Pork Chops","cat":"Meat","submittedBy":"Anne Romanowski","description":"I got this recipe from a friend at my bridal shower, and it has been a favorite for 8 years.  The coating has a very surprising tangy flavor, and it' moist the pork chops are when you cut into them.  My brother, Kevin, gave it his seal of approval; whenever I make it, I make sure I make extras for him to take home when he visits.  An instant dinner, but nice enough for company!  Double or triple recipe for larger gatherings.\\r\\n","time":"35 min.","serves":"4","ingredients":[["4 boneless, center-cut","Pork Chops"],["1 beaten","Eggs"],["1 cup, plain  (Jim Roma","Breadcrumbs"],["3 Tsp.","Olive oil"],["1 Tsp.","Wine Vinegar"],["3 Tsp.","Lemon Juice"],["1/2 cup, grated","Parmesan Cheese"],["1 Tbsp. (Grey Poupon)","Dijon Mustard"],["1 clove, minced","Garlic"],["1 Tbsp., dried","Parsley"],["dash","Salt"],["dash","Pepper"]],"steps":["Trim fat from chops.","Dip in egg and then bread crumbs and place on a rack in the broiler for 7 minutes.  (MAKE SURE THE BREADING DOESN\u2019T BURN.)  In a bowl, mix the remaining ingredients.","Flip the chops and broil another 5-7 minutes.","Take chops out and spoon half the mixture over chops, and broil another 5 minutes.","Make sure the coating gets golden brown but doesn't burn.","Flip them again and spoon the rest of the mixture on the other side.","Broil another 5 minutes.","Serve with rice or egg noodles and a veggie.\\r"]},{"id":48,"name":"Cajun Gumbo","cat":"Soups","submittedBy":"Anne Romanowski","description":"This favorite came from a Southern friend of mine.  She said her mom has made it forever, and it comes from their local community cookbook.  Its got a little zip, but not too much for the faint of heart.  This is a meal in itself.  Great for parties, too!  Best if eaten the next day.  Enjoy!\\r\\n","time":"1&","serves":"4-6","ingredients":[["2 Tbsp.","Oil"],["1 small, chopped fine","Red Onion"],["2 chopped","Scallions"],["2 cloves, minced","Garlic"],["3 ribs, with leaves, chopped","Celery"],["2 cans (28 oz.)","Crushed Tomatoes"],["1&1/2 cups","Water"],["1 Tbsp.","Salt"],["1&1/4 tsp.","Pepper"],["1 Tbsp.","Sugar"],["1/2 tsp.","Chili Powder"],["1 Tbsp. (Lea & Perrins)","Worcestershire Sauce"],["1 bag (10 oz. Size)","Frozen Sliced Okra"],["1 lb., medium, uncooked and shelled","Shrimp"],["2 tsp. (Paul Prudomme","Gumbo file' (spice)"],["1/2","Boneless Chicken Breasts"],["2-3 links, andouille (found at Wegman","Sausage"],["if desired for extra spice","Tiger Sauce"]],"steps":["Cut up chicken and sausage into small bite-size pieces and cook together in a non-stick pan.  Set aside.  Saut\u00e9 onion, scallions, garlic and celery in the oil, until tender.  Add remaining ingredients, except shrimp, file' and meat.  Cover and cook on low-medium for 30 minutes.  Add shrimp and meat.  Boil gently (10 minutes or more).  Remove from heat and add gumbo file'.  Let","stand.  Refrigerate overnight, if possible.  To serve, make white rice while heating the soup, and place a scoop of rice in each soup bowl.  Top with a generous ladle of gumbo.  Use Tiger Sauce if you want extra spice."]},{"id":49,"name":"Penne Alla Vodka","cat":"Pasta","submittedBy":"Christine Sheehy","description":"Since moving to Long Island almost 10 years ago, I was dying to get this recipe since it is such a common dish in all the Italian restaurants.  It's also an easy dish to make for company, and they always think you fussed!","time":"25 min","serves":"4","ingredients":[["4 Tbsp.","Butter"],["1 small, diced","Onions"],["1 clove, choped","Garlic"],["3 leaves, chopped","Basil"],["1/2 cup (cheaper is better)","Vodka"],["1 1 can (14 oz.)","Crushed Tomatoes"],["1/2 pint","Heavy Cream"],["1 lb. (may substitute Rigatoni)","Penne Pasta"],["1 lb. Precooked (optional)","Chicken or Shrimp"],["(optional)","Basil Leaves"]],"steps":["In a medium saut\u00e9 pan, melt the butter over medium heat.","DO NOT LET IT BROWN!","Over medium-low heat, cook the onion, garlic and basil until the onionpieces are soft (about 8-10 minutes).","Add vodka to the pan.","Raise heat to boil, stirring the mixture frequently.","Lower heat to simmer and cook sauce for about 8 minutes or until about 1/4 of the mixture has evaporated and the aroma of the vodka has subsided.","Add the tomatoes.","Continue cooking 5 minutes longer.","Add heavy cream and cook 5 minutes longer.","You may add \\r shrimp or chicken, if you prefer.","Cover the pan and cook an additional 5-8 minutes.","Cook the pasta al dente.","When pasta is ready, drain and transfer to a large bowl.","Add the vodka sauce and toss well.","Garnish with basil leaves, if desired.\\r"]},{"id":50,"name":"California Crab Salad","cat":"Salads","submittedBy":"Gloria Greco","description":"I got this recipe from a friend who is a caterer.  For the best taste, chill overnight, but at least for 3 hours!  The flavors blend nicely, and no one believes that there are so few ingredients in it!\\r\\n","time":"-","serves":"","ingredients":[["3-4 stalks, tops off, deveined and sliced","Celery"],["1 small bunch, thinly sliced, white part only.","Scallions"],["1 pound (frozen or fresh)","Broccoli Flowerets"],["1 pound (from Trader Joes-Louis Rich brand)","Imitation Crab"],["enough to cover mixture (Real, Low or No Fat)","Mayonnaise"],["to taste","Salt and Pepper"]],"steps":["Break up crab pieces by hand into smaller pieces.  Place in a large bowl.  Set aside.  If using frozen broccoli, arrange on large platter and zap in microwave for about 10 minutes (more or less depending on the power of the microwave).  Be sure the frozen brand does not include too many stems.  If using fresh broccoli, drop into boiling water until broccoli changes color--needs to be on the","crunchy side (about 5 minutes).  Allow to cool.  Add broccoli to the crab.  Add sliced scallions and celery.  Toss.  Add enough mayonnaise to lightly cover the mixture and season with salt and pepper to taste.  Mix thoroughly.  Serve."]},{"id":51,"name":"Chicken Chablis","cat":"Meat","submittedBy":"Lillian Pisani","description":"","time":"-","serves":"","ingredients":[["6 pounded","Chicken Breasts"],["","Eggs"],["","Parsley"],["","Parmesan Cheese"],["","Milk"],["","Salt and Pepper"],["","Garlic Powder"],["","Oil"],["","Breadcrumbs"]],"steps":["Mix ingredients for marinade.","Place chicken in marinade and mix.","Refrigerate for two hours.","Bread each chicken breast and fry in oil.","To the oil remaining from frying, add a little water, wine, salt, pepper, parsley and canned mushrooms.","Pour this mixture over cooked chicken.","Serve."]},{"id":52,"name":"Mashed Potatoes with Parmesan Cheese","cat":"Non-Meat","submittedBy":"Lillian Pisani","description":"","time":"-","serves":"","ingredients":[["1&1/2 pounds, boiling type","Potatoes"],["4 Tbsp. (1/2 stick)","Unsalted Butter"],["1/3 cup","Heavy Cream"],["to taste","Salt"],["1/3 cup, freshly grated","Parmesan Cheese"]],"steps":["Put unpeeled potatoes in a large saucepan.","Fill with cold water to cover the potatoes.","Bring the water to a boil over medium heat and cook until tender.  (45 minutes to 1 hour)  Drain the potatoes and peel them as soon as they are cool enough to handle.","Mash through a food mill or potato masher.  (Do not use a food processor.)  Heat the butter and the cream in a medium-size saucepan over medium heat.","When butter melts, add mashed potatoes.","Season with salt and add cheese.","Mix potatoes with a wire whisk or a wooden spoon until everything is well combined.","Taste and adjust.\\r"]},{"id":53,"name":"Roasted Cod with Roasted Potatoes","cat":"Fish","submittedBy":"Lillian Pisani","description":"","time":"-","serves":"","ingredients":[["2 cloves","Garlic"],["1/3 cup","Olive oil"],["2 Tbsp., fresh, chopped","Rosemary"],["4 1\\","Cod Fillets"],["3 medium","Potatoes"],["1/2 cup","Breadcrumbs"]],"steps":["Preheat oven to 375 degrees.","Make a mixture of garlic, oil and rosemary in a large baking dish and mix with a wooden spoon.","Place the cod fillets in the baking dish and coat them with the mixture on both sides.","Peel and slice potatoes into very thin rounds.","Briefly boil slices (about 1 minute).","Place the potatoes around the codfish and toss with a spoon until coated.","Season with salt and pepper.","Bake 4-5 minutes.","Sprinkle the cod and potatoes with bread crumbs and bake 4-5 minutes longer.","That's it--it is ready when the \\r potatoes and cod are lightly golden and the inside of the fish is opaque.","Serve at once.","Makes 4 servings.\\r"]},{"id":54,"name":"Cranberry Sauce","cat":"Miscellaneous","submittedBy":"Lillian Pisani","description":"This is very good, and it's easy!  Uncle Joe will not eat turkey unless he has this cranberry sauce with it.  I usually make a large quantity.","time":"-","serves":"","ingredients":[["2 cans","Cranberry Sauce"],["seedless, chopped (may substitute mandarin oranges in can)","Oranges"],["crushed","Walnuts"]],"steps":["Mash cranberry sauce in a bowl.","Add oranges and crushed walnuts.","Mix.","That's it!"]},{"id":55,"name":"Corn Fritters","cat":"Non-Meat","submittedBy":"Lillian Pisani","description":"One Thanksgiving, we were invited to Lorraine Coughlin's home for dinner.  She \\r\\nmade these, and I've made them every Thanksgiving since.  My family loves them!    \\r\\n","time":"-","serves":"","ingredients":[["1&1/3 cup","Flour"],["1&1/2 tsp.","Baking Powder"],["1/4 tsp.","Salt"],["2/3 cup","Milk"],["1 well beaten","Eggs"],["(if desired)","Pepper"],["","Corn"]],"steps":["Combine all ingredients in a mixing bowl.","Drop by tablespoonful onto grill or frying pan (as in making pancakes).","Flip each corn fritter to grill the top side.","Place on serving plate.","Enjoy with dinner.","Serve with maple syrup."]},{"id":56,"name":"Frittata with Zucchini and Pecorino Cheese","cat":"Non-Meat","submittedBy":"Lillian Pisani","description":"Pronounced (Fre-tah-d), meaning a mixture of eggs and veggies, like an omelet.","time":"-","serves":"","ingredients":[["1/3 cup","Olive oil"],["1/2 pound, small and sliced","Zucchini"],["1 clove, freshly minced","Garlic"],["1/3 cup, freshly grated (may substitute Romano or Parmesan)","Pecorino Cheese"],["6 large, lightly beaten","Eggs"],["as needed (freshly ground pepper)","Salt and Pepper"],["2 Tbsp., fresh, chopped","Parsley"]],"steps":["Heat oil in an 8\" non-stick skillet over medium heat.","Add zucchini and cook, stirring until zucchini is lightly golden (4-5 minutes).","Add the garlic and stir once or twice.","In a bowl, beat together the eggs, cheese, parsley, salt and pepper.","Remove the zucchini from the skillet with a slotted spoon and stir them into the beaten egg mixture.","Return all to the skillet and cook over medium heat until the bottom of the frittata is set and lightly browned\\r (5-6 minutes).","Place a large plate over the skillet and turn the frittata onto the plate.","Slide it back into skillet to cook the other side.","Cook until the bottom is lightly browned (3-4 minutes) longer.","Serve.\\r"]},{"id":57,"name":"Ciamelles (Large Italian Bagels)","cat":"Desserts","submittedBy":"Lillian Pisani","description":"Pronounced (chum-els).  Makes 12-14 large bagels.","time":"-","serves":"","ingredients":[["1 cake (or dry packet*)","Yeast"],["2/3 cup, warm","Water"],["12 cups","Flour"],["2&1/2 tsp.","Salt"],["1 tsp.","Anise Seeds"],["2 cup","Milk"]],"steps":["In a cup or small bowl, dissolve yeast packets with sugar, flour and  warm water.","Mix together until foamy.","Mix together flour, salt, and anise seeds.","Using a lightly-floured board, form a ring (with a hole in the middle) of the flour mixture.","Into the middle of the ring, add water, yeast mixture and milk (adding milk slowly).","Mix and work dough until smooth.","Cover the dough with a large bowl, and let it set for 15 minutes.","Work the dough again, and again cover dough with a bowl for 15 more minutes.","Work dough again and form into a log.","Slice 1\" pieces from the log.","Roll each piece into a smaller log.  (A small amount of water may be added as needed to make rolling easier).","Pressing ends together, form a ring (bagel) with each piece.","For variation, you may \"twist\" each piece before pressing ends together.","You may also \"pinch\" here and there around the ring to create creases.","In a large pan of boiling water, drop 3 formed ciamelles (the size of bagels) at a time.","They will sink to the bottom of the pan, but will rise as the water begins to boil again.","Cook about 5 minutes, and then flip onto the other side, and cook for another 2 minutes.","Remove each ciamelle from the water with a strainer, and flip onto a dishtowel to dry and cool (about 15-20 minutes).","Preheat oven to 350 degrees.","Bake on cookie sheet for 30 minutes.","If the ciamelles are starting to brown, remove from cookie sheet and bake directly on the oven racks for an additional 30 minutes.","Total baking time: 1 hour."]},{"id":58,"name":"Cheese Balls","cat":"Appetizers","submittedBy":"Lillian Pisani","description":"I make these at Christmas time. This recipe makes three cheese balls.  I freeze each one wrapped in waxed paper and tin foil.  Then i remove them as needed to serve with crackers.  Very festive looking for the holidays!","time":"-","serves":"","ingredients":[["1 8 oz. pkg.","Blue Cheese"],["1 8 oz. pkg.","Cream Cheese"],["1 8 oz. pkg., shredded","Cheddar Cheese"]],"steps":["Combine all ingredients.","Form into three balls.","On a piece of waxed paper, roll balls into mixture of chopped nuts and dried parsley.","With your finger, make a small hole in the center of each cheese ball and fill it with a maraschino cherry.;;;"]},{"id":59,"name":"Snow Ball Cookies","cat":"Desserts","submittedBy":"Lillian Pisani","description":"Good Christmas cookies!","time":"-","serves":"","ingredients":[["1 cup","Butter or Margarine"],["4 Tbsp.","Brown Sugar"],["4 Tbsp.","Sugar"],["2 cups","Flour"],["1 cups, chopped","Walnuts"],["1 cup, chopped","Semi-sweet Chocolate Chips"]],"steps":["Combine and mix all ingredients.","Chill.","Shape into 1\" balls.","Bake at 350 degrees for 15 minutes.","After cooled, shake them in powdered sugar."]},{"id":60,"name":"Puff Desserts","cat":"Desserts","submittedBy":"Lillian Pisani","description":"","time":"-","serves":"","ingredients":[["1/2 cup","Margarine"],["1 cup","Water"],["1 cup, sifted","Flour"],["1/4 tsp.","Salt"],["","Eggs"],["1 box chocolate or vanilla","Instant Pudding"],["4 oz.","Cream Cheese"],["2 cups","Milk"],["","Cool Whip"],["","Confectioner's Sugar"]],"steps":["Boil margarine and water.","Add flour and salt.","Remove from stove.","Beat in one egg at a time.","Place cream puffs close together.","Bake ?","After cooled, slit and fill with pudding-cream cheese-milk mixture.","Top with Cool Whip.","Sprinkle with confectioner's sugar."]},{"id":61,"name":"Belgian Pastry","cat":"Desserts","submittedBy":"Lillian Pisani","description":"Makes two loaves.","time":"-","serves":"","ingredients":[["1 cup","Flour"],["1 stick","Margarine"],["2 Tablespoon, cold","Water"],["","Unknown"],["1 cup","Water"],["1 stick","Margarine"],["1 Tbsp. (may substitute with lemon or almond)","Vanilla Flavoring"],["1 cup","Flour"],["4","Eggs"],["","Unknown"],["2 cups","Confectioner's Sugar"],["1 tsp.","Butter"],["1 tsp.","Vanilla Flavoring"],["as desired","Nuts"]],"steps":["Make a bottom crust of flour, margarine and water.","Top crust is same recipe as cream puff dough--Bring water, margarine, and flavoring to a boil.","Remove from stove.","Add flour and stir.","Cool.","Add eggs one at a time.","Frost with mixture of confectionery sugar, butter and vanilla flavoring.","Frost cooled pastry and sprinkle with nuts."]},{"id":62,"name":"Rice Pudding","cat":"Desserts","submittedBy":"Lillian Pisani","description":"","time":"-","serves":"","ingredients":[["1/2 gallon","Milk"],["1/2 tsp.","Salt"],["1 cup","Vanilla Ice Cream"],["1/2 box (1 cup - River rice)","Rice"],["1/2 cup","Sugar"],["1 tsp.","Vanilla Flavoring"],["","Unknown"],["2","Eggs"],["hot","Milk"]],"steps":["Pudding Mixture:  Combine all ingredients in a sauce pan.","Cook until rice is done.","Stir in sugar and vanilla.","Egg Mixture:  In a bowl, beat eggs.","Add hot milk.","Milk will rise to the top.","Beat eggs and milk.","Pour egg mixture into pudding mixture.","If too thin, cook longer to thicken."]},{"id":63,"name":"Linguine with Clam Sauce","cat":"Pasta","submittedBy":"Lillian Pisani","description":"","time":"-","serves":"","ingredients":[["1/4 tsp.","Salt and Pepper"],["1/4 cup","Breadcrumbs"],["1/2 tsp.","Pepper"],["1/2 tsp.","Garlic Salt"],["1/2 ounce","Olive oil"],["1 ounce","White Wine"],["1 ounce","Butter"],["1 cup","Water"],["1 dozen (canned clams may be used)","Steamed Clams"],["to taste","Garlic Powder"],["fresh","Parsley"],["","Romano Cheese"],["1 lb.","Linguine Pasta"]],"steps":["In a large pot, steam clams in 1 cup of water.","Remove clams and strain juice in pot.","Remove a few clams from the shells and add to juice.","Simmer juice with butter, wine, oil, garlic salt and pepper.","To the bread crumbs, add salt, pepper, garlic powder, parsley, and cheese.","Add more bread crumbs to the seasoned juices to thicken the juices into a sauce; then add clams.","Cook pasta al dente.","Drain.","Top with clam sauce.\\r  ;"]},{"id":64,"name":"Meat Loaf","cat":"Meat","submittedBy":"Diane Randesi","description":"Aunt Kay gave me this recipe when I got married.  I made it every week for years!","time":"-","serves":"","ingredients":[["1 lb.","Ground Chuck"],["1/2 cup","Breadcrumbs"],["1/4 cup","Parmesan Cheese"],["1 chopped","Onions"],["1/4 tsp.","Garlic Salt"],["1 tsp.","Salt"],["dash","Pepper"],["2 stalks, chopped","Celery"],["2","Eggs"],["1/2 cup","Catsup"]],"steps":["Combine all ingredients.","Place in a loaf baking pan.","Cook 350 degrees for 1 hr."]},{"id":65,"name":"Pizza Fritelle  (Fried Dough)","cat":"Miscellaneous","submittedBy":"Diane Randesi","description":"Pronounced (pizza-fde\u00e9-t)  Aunt Kay gave me this recipe.  We ate these as fast as they could be made, while waiting for Christmas Eve dinner to be served.  Other times, they are eaten as a snack or in place of bread.  You can use this yeast recipe for the dough, or you can buy frozen bread dough instead.","time":"-","serves":"","ingredients":[["2 cups, warm","Water"],["3 Tbsp.","Oil"],["1 package, dry","Yeast"],["1 tsp.","Salt"],["5 cups","Flour"],["1","Eggs"],["as desired","Sugar"],["(optional)","Parmesan Cheese"],["cooked (optional)","Sausage"]],"steps":["Dissolve yest in about 1/2 cup of the water.","Combine and mix remainder of water, oil, salt and eggs.","Add yeast mixture.","Gradually add flour.","Place in a covered bowl to rise.","When it has doubled in size, punch it  down and let rise again.","Cut and shape 2 X 6\" pieces  Drop in hot oil until lightly brown.","Drain on paper towel.","Roll in granulated sugar.","Eat warm.","If desired, you can wrap the dough around a piece of parmesan cheese or cooked sausage or both;  then fry, drain, roll in sugar and enjoy!"]},{"id":66,"name":"Easter Pena Bread","cat":"Desserts","submittedBy":"Angie Dellos","description":"Pronounced (pe\u00e9-nah).  I make several of these breads every year during the Easter season.  Often it is braided with hard-boiled eggs nestled between the braids.  This recipe makes 3 loaves.  It is delicious toasted, with butter, any day, but especially on Easter morning.","time":"-","serves":"","ingredients":[["3/4 cup","Sugar"],["2 tsp.","Salt"],["1/4 pound","Butter or Margarine"],["1&1/2 milk, scalded","Milk"],["2 small packages","Yeast"],["2 eggs","Eggs"],["1/2 cup, luke warm","Water"],["6-7 cups","Flour"],["1/3 cup","Anise Seeds"],["1 tsp.","Rum Flavor"],["some","Yellow Food Color"],["1 cup, (optional)","Raisins"],["1 white","Eggs"]],"steps":["Soak yeast in warm water for a few minutes.","In a separate bowl, pour scalded milk over sugar and salt.","Stir until dissolved.","When lightly cooled, add half of the flour and beat until smooth.","Beat in butter, eggs, and yeast mixture.","Add rum flavoring, anise seeds, and raisins.","Add remaining flour and mix to soft dough.  (A small amount of yellow food coloring can be added if you like a more yellow look to the bread.)  Turn dough onto lightly floured board.","Knead 5 to 10 minutes until smooth and \"satiny.\u201d  Place dough in greased, covered bowl and let raise until doubled.","Punch down.","Separate into three sections.","Divide each section into three parts and shape into ropes.","Pinch ends of 3 ropes together and braid.","Pinch again at end of braid.","Then shape braid into a circle and place in a greased pie tin, or straight into a loaf pan.","Let raise another hour in the pan.","Brush top with beaten egg white for shiny finish, and sprinkle with non-pareils decorative candies.","Bake 350 degrees for 30-35 minutes.","Option: Another popular way to shape the dough is in the form of the number 8, placing a hard-boiled egg in each of the open areas of the 8.\\r"]},{"id":67,"name":"Hard Biscotti","cat":"Desserts","submittedBy":"Angie Dellos","description":"My grown children and grandchildren ask me to make these all the time.  They have grown to appreciate them when they see how expensive they are sold singly in coffee shops around town.  Warning: These are really hard, and best \"dunked\" in coffee or milk!","time":"-","serves":"","ingredients":[["5","Eggs"],["2&1/2 cups","Sugar"],["1 tsp.","Baking Powder"],["1/2 tsp.","Baking Soda"],["1 tsp. (may substitute lemon)","Vanilla"],["4 cups","Flour"],["1 pound","Almonds"]],"steps":["In a bowl, beat sugar, eggs and vanilla.","Add flour, baking powder, and baking soda.","Dough will be stiff.","Add almonds.","Separate into 4 pieces.","Shape into 4 logs (about 2x15\").","Beat 1 whole egg.","Brush the top of each log with egg and sprinkle with granulated sugar.","Bake 375 degrees for 20 minutes, or until light brown.","Remove from oven onto a cutting board.","For each log, while warm, slice at an angle to make into cookies.","Arrange on cookie sheet and re-bake until lightly brown, turning, if necessary to brown both sides.  (BE CAREFUL NOT TO BURN.)"]},{"id":68,"name":"Italian Cookies","cat":"Desserts","submittedBy":"Angie Dellos","description":"These are one of my son-in-law's favorites.  They're not too fancy and not too sweet--just a plain, but tasty.","time":"-","serves":"","ingredients":[["4-5 cups","Flour"],["1 cup","Sugar"],["1 cup","Margarine"],["5 tsp.","Baking Powder"],["4 large","Eggs"],["1 tsp. (may substitute lemon)","Vanilla Flavoring"],["","Unknown"],["to be added to confectionery suger for frosting","Water"],["as desired","Confectioner's Sugar"]],"steps":["Place flour, sugar and baking powder in a bowl.","Add margarine and blend with fork (as in making pie crust).","Make a well in the center of this mixture.","Add beaten eggs and vanilla.","Knead dough.","Chill.","Cut dough into approx. 2\" (bite size) pieces.","Roll each piece into about a 6\" strip.","Shape each piece of dough by tying into a single knot.","Place on baking sheet.","Bake 350 degrees until golden brown (10 minutes).","Using a pastry brush, ice with mixture of confectionery sugar and water"]},{"id":69,"name":"Chicken or Veal Piccata","cat":"Meat","submittedBy":"Angie Dellos","description":"Makes 4 servings.","time":"-","serves":"","ingredients":[["1 lb.whole, 1/4\\","Chicken Breasts"],["1/3 cup","Flour"],["2 Tbsp.","Oil"],["2 Tbsp.","Butter"],["2 Tbsp.","Shallots"],["1/4 cup, fresh","Mushrooms"],["1/2 cup","Chicken Broth"],["1/2 cup","White Wine"],["1 Tbsp.","Lemon Juice"],["2 tsp.","Parsley"],["as desired_x000d_\nas desired","Lemon Slices"]],"steps":["Salt and pepper chicken.","Cut two breasts into 8 pieces.","Press chicken firmly into flour to coat.","Shake off excess flour and chill.","Brown chicken in oil and butter.","Set aside.","Add shallots and mushrooms to skillet.","Saut\u00e9 until brown.","Add chicken broth, wine and lemon juice mixing well.","Add chicken to skillet.","Simmer until piping hot.","Serve with lemon slices on top, if desired."]},{"id":70,"name":"Easter Soda Cracker Cookies","cat":"Desserts","submittedBy":"Angie Dellos","description":"This is more like candy than a cookie--good any time of year when you need something sweet!","time":"-","serves":"","ingredients":[["24","Saltine Crackers"],["3/4 cup","Brown Sugar"],["2 sticks","Margarine"],["12 oz. package","Chocolate-chips"],["3/4 cups, chopped","Walnuts"]],"steps":["Line cookie sheet (with sides) with foil.","Place 24 or more saltine crackers side by side to cover bottom of pan.","In a saucepan, combine brown sugar and margarine.","Boil 3 minutes.  (BE CAREFUL NOT TO BURN!)  Pour this syrup mixture over crackers until they are completely covered.","Bake 400 degrees for 5 minutes.","Remove from oven and immediately sprinkle with chocolate chips.","Place back into oven for a few minutes until chocolate chips get soft and start to melt.","Remove from oven and smooth evenly across pan.","Sprinkle chopped walnuts on top and press them into the melted chocolate.","Place the pan in the freezer for \u00bd hour.","Remove.","Pull off foil, and break (not cut) into cookie-size pieces.  (They will be uneven.) \\r"]},{"id":71,"name":"Capellini and Broccoli","cat":"Pasta","submittedBy":"Angie Dellos","description":"","time":"-","serves":"","ingredients":[["1 bunch, fresh","Broccoli"],["1/4 cup","Olive oil"],["5 Tbsp.","Butter"],["3 chopped","Scallions"],["1 clove, crushed","Garlic"],["1/4 cup","White Wine"],["1/2 lb. ( may substitute vermicelli pasta)","Capellini Pasta"],["grated to taste","Parmesan Cheese"]],"steps":["Cut broccoli into flowerets.","Peel and chop stems.","Set aside.","Saut\u00e9 scallions and garlic in 1 tablespoon of the butter.","Add wine.","Cook 5 minutes.","In microwave, melt the rest of the butter and the oil.","Add this to wine sauce.","Cook pasta in salted water, al dente.","During the last 3 minutes, add broccoli to pot of pasta.","Strain.","Add butter and oil sauce and mix well.","Add Parmesan cheese.","Serves 4."]},{"id":72,"name":"Blueberry Muffins","cat":"Desserts","submittedBy":"Joyce Delorey","description":"Yields about 16 muffins.","time":"-","serves":"","ingredients":[["6 Tbsp.","Butter or Margarine"],["1&1/4 cups","Sugar"],["2 large","Eggs"],["2 cups","Flour"],["1/2 tsp.","Salt"],["2 tsp.","Baking Powder"],["1/2 cup","Milk"],["1 pint, washed (divided into 2 half cups)","Blueberries"],["2 tsp.","Sugar"],["","Unknown"],["3 Tbsp.","Butter or Margarine"],["1/4 cup","Flour"],["1/4 cup","Sugar"],["1 tsp.","Cinnamon"]],"steps":["Cream butter and sugar very well.","Add eggs one at a time and beat well.","Sift flour, salt, baking powder, and sugar together.","Add this mixture alternately with the milk.","Set aside \u00bd cup blueberries.  (Dry remaining blueberries very well with paper towels.)  Crush the \u00bd cup blueberries with a fork and mix them into the batter by hand.","Add remainder of blueberries and mix in by hand.","Grease top of the muffin tins well and place paper cups in each well.","Fill cups 7/8 full.","Bake 375 degrees for 20 minutes.","Remove.  \\r \\r Topping: Cream together margarine, flour, sugar and cinnamon for a crumbly texture.","Sprinkle with this toppping.","Bake 5-10 minutes more.","Remove from oven to cool.\\r"]},{"id":73,"name":"Pizzelle","cat":"Desserts","submittedBy":"Diane Randesi","description":"This cookie is made with an electric iron.  This recipe makes a lot of cookies, but they stay fresh a long time in a sealed container.  Even though all the Recipe4 say not to use oil as a substitute for margarine, my mother makes the BEST ones, and she uses oil--they turns out less \"cake-like\" and more light and crispy.","time":"-","serves":"","ingredients":[["2 sticks (Oil may be substituted for a lighter cookie)","Margarine"],["6","Eggs"],["3&1/2-4 cups","Flour"],["1&1/3 cups","Sugar"],["4 tsp.","Baking Powder"],["2 Tbsp. (optional)","Anise Seeds"],["2 Tbsp.  (Vanilla may be substituted)","Anise Flavoring"]],"steps":["Combine all ingredients, adding flour slowly until batter is just short of \"sticky\"--(not too dry).","Drop by teaspoonful onto electric grill.","Close grill tightly for 30 seconds.","Remove cookie.  (It will be limp.)  Cookie firms up as it cools.","You can form the cookie into a funnel while it is limp.","It will cool in whatever shape you form it.","Fill with cream or ice cream."]},{"id":74,"name":"Raisin Cinnamon Rolls","cat":"Desserts","submittedBy":"Julia Greco","description":"Serves 12","time":"-","serves":"","ingredients":[["1 lb. (loaf), thawed","Frozen Bread Dough"],["1/2 cup, melted","Butter or Margarine"],["1/2 cup","Sugar"],["2 tsp.","Ground Cinnamon"],["1/2 cup (optional)","Raisins"],["2 Tbsp., chopped and toasted (may substitute walnuts)","Almonds"],["2 tsp., grated peel","Lemon"],["","Unknown"],["1/2 tsp.","Powdered Sugar"],["2 tsp.","Lemon Juice"]],"steps":["Roll thawed dough on floured surface into a 14 x 18 inch rectangle.","Reserve 2 tablespoons butter for later use.","Brush remaining butter over dough.","Combine sugar and cinnamon.","Sprinkle over buttered dough along with raisins, almonds and lemon peel.","Starting from 14\" side, roll up jelly-roll style.","Cut into 12 rolls.","Arrange in 9\" greased pie plate or baking pan.","Allow to rise in refrigerator overnight.","Brush with remaining butter and bake in 350 degree oven for 30 minutes.","Allow to cool 10 minutes.","Combine powdered sugar and lemon juice until smooth to make glaze.","Brush glaze over rolls."]},{"id":75,"name":"Easter Bread","cat":"Desserts","submittedBy":"Julia Greco","description":"My mother used to make a bread similar to this one.  She would shape it into dolls for my sisters and me, and a rocking horse for my brother.  It was a gift to us on Easter Sunday morning.  In recent years, I make about 32 loaves of this bread to give to family, friends, and to shut-ins at Easter time.","time":"-","serves":"","ingredients":[["2 packages","Dry Yeast"],["1/2 cup, warm","Water"],["1& 1/2 cup, scalded","Milk"],["2 packages lemon","Instant Pudding"],["1/2 cup","Sugar"],["1/2 cup","Margarine"],["8&1/2-9 cups","Flour"],["","Eggs"]],"steps":["Soften yeast in warm water.","In separate bowl, blend together scalded milk, pudding, margarine and sugar.","Add 2 cups of flour and mix well.","Stir in yeast mixture and beaten eggs.","Gradually add remaining flour to make a soft dough.","Place onto a lightly floured board.","Cover dough with bowl and let rest for 10 minutes.","Knead until smooth and elastic (10 minutes).","Place in a lightly greased large bowl.","Let rise until it doubles in size.","Place onto a lightly floured board.","Divide dough in half.","Let rest 10 more minutes.","Divide each half in 3 pieces and roll into equal length strands.","Braid and arrange in a well-greased loaf pan.","Cover and let rise 30-45 minutes until almost double.","Before baking, brush each loaf with a mixture of beaten egg and 1 tablespoon of water.","Bake 350 degrees until top is golden brown (about 25-30 min.).","Option: Braid and arrange (in a circle) into a well-greased pie tin.","This recipe makes 2 loaves.\\r"]},{"id":76,"name":"Egg Bake","cat":"Meat","submittedBy":"Julia Greco","description":"","time":"-","serves":"","ingredients":[["6-7 slices, cubed","Bread"],["1 cup, cubed","Ham"],["1 cup, shredded (may substitute cheddar)","Mozzarella Cheese"],["","Unknown"],["6","Eggs"],["2 cups","Milk"],["1 tsp.","Dry Mustard"],["1 tsp.","Salt"],["","Unknown"],["1/2 stick","Margarine"]],"steps":["Grease a 9x13\" pan.","In a baking dish, combine bread, ham and cheese.","In a separate bowl, mix eggs, milk, dry mustard and salt.","Pour this mixture over bread, ham and cheese in baking dish.","Melt margarine and pour over entire mixture.","Cover with foil and refrigerate overnight.","Bake 325 degrees for 1 hour.","Uncover the last 15 minutes."]},{"id":77,"name":"Nono's Capalete","cat":"Pasta","submittedBy":"Julia Greco","description":"\u201cNono\u201d (pronounced no-no) refers to Grandma Greco.  Capalete (pronounced cap-a-let-e), which is sometimes called \"little hats\u201d, is a special pasta dish we had on holidays or for Sunday dinner.","time":"-","serves":"","ingredients":[["6","Eggs"],["6 cups","Flour"],["pinch","Salt"],["if needed to make a workable dough","Water"]],"steps":["Combine all ingredients.","Mix on floured board.","Knead.","Cover the dough with a bowl, and let stand for about 10 minutes.","Knead again until smooth and easy to work with. \\r \\r This is one of those times when you have to \u201cfeel\u201d the right amount of  water to add.","Italian pasta dough should not be sticky.","Rule of thumb: If too crumbly, add water, if too sticky, add flour.\\r \\r Cut dough into slices and roll each slice into a 6\" rope.","Cut this rope into small pieces (about the size of your thumb).  \"Dig\" each piece with your finger or a knife; then turn each piece over your thumb to make a small hat.","Cook immediately, or freeze on a cookie sheet, making sure pieces do not touch.","After frozen, place into plastic bag for storing in the freezer until ready to cook.\\r"]},{"id":78,"name":"Ceci Chiata - Mardi Gras Wreath","cat":"Desserts","submittedBy":"Julia Greco","description":"Pronounced (Chick-a-la-chod).  Nonno always served this as dessert after a special, large meal on the day before Lent (Fat Tuesday).  A special big dinner on this day marked the last meal before the Lenten season began.  Very good.\\r\\n","time":"-","serves":"","ingredients":[["3","Eggs"],["1/2 cup","Canola Oil"],["1/2 cup","Sugar"],["3 tsp.","Baking Powder"],["1 tsp.","Lemon"],["1 tsp.","Almond Extract"],["2-3 cupscups","Flour"],["","Unknown"],["","Honey"]],"steps":["Combine all ingredients, except honey.","Knead dough and roll into a six-inch rope.","Cut into small pieces.","Roll pieces round in the shape of a small marble.","Deep fry these pieces in Canola oil until brown.  (Oil should be very hot.)  The dough pieces will come to the top when done.","Remove with slotted spoon and drain.","In a bowl, mix the fried dough pieces with whole almonds.","Cook honey in a large pan.","When honey is hot and stringy, add the mixture of fried dough and almonds.","Mix until they are well coated with the honey.","Spoon onto a large round serving dish (it will be sticky) and shape into a wreath.","Refrigerate.  \\r \\r Option: Honey balls can be shaped into a beehive or a mound instead of a wreath.","Sprinkle top with colored sprinkles.\\r"]},{"id":79,"name":"Polenta - Corn Meal","cat":"Meat","submittedBy":"Julia Greco","description":"this is a good meal in cold weather!","time":"-","serves":"","ingredients":[["2 cloves, crushed","Garlic"],["small amount in frying pan","Olive oil"],["","Sausage"],["1 can","Tomato Sauce"],["1 quart (plus 1 cup)","Water"],["1 cup","Fine Corn Meal"],["","Parmesan Cheese"]],"steps":["Sauce Mixture: Fry garlic in a small amount of olive oil.","Add sausage and cook well.","Add tomato sauce.","Let simmer until sauce is done.  \\r \\r Polenta Mixture: In a medium-sized pan, bring 1 quart of water to a boil.","In a separate bowl, combine cornmeal and 1 cup of cold water.","Stir until smooth.","Add this mixture to the boiling water.","Reduce heat and let simmer very \\r slowly stirring until it is thick and coats the stirring spoon (about 15-30 minutes).  \\r \\r To serve: On a serving platter, layer sauce, polenta, and Parmesan cheese alternately ending with sauce.","Top with Parmesan cheese.\\r"]},{"id":80,"name":"Cousin Millie Ricotta Pie","cat":"Desserts","submittedBy":"Julia Greco","description":"Pronounced (rdig-gaut\u2019-a).  I got this recipe from our \u201cNew York City cousin\u201d, Millie.","time":"-","serves":"","ingredients":[["12","Eggs"],["3 pounds","Ricotta Cheese"],["3 Tbsp.","Flour"],["1&1/4 Sugar","Sugar"],["2 tsp. (may substitute lemon)","Anisette Flavor"]],"steps":["Combine and mix all ingredients.","Grease a 9 x 12\" cake pan.","Bake 350\u00ba for 1 hr."]},{"id":81,"name":"Amaretto Cookies","cat":"Desserts","submittedBy":"Julia Greco","description":"","time":"-","serves":"","ingredients":[["5 cups","Flour"],["6 heaping tsp.","Baking Powder"],["4 tsp.","Almond Extract"],["1 cup","Orange Juice"],["1 cup","Crisco"],["2 cups","Sugar"]],"steps":["In a bowl, beat eggs, sugar and Crisco.","Add juice, almond extract, baking powder and flour.","Mix.","Batter will be soft and sticky.","Drop by teaspoonful into a bowl of powdered sugar.","Roll each teaspoonful into a ball and cover with sugar.","Place on greased cooking sheet.","Let stand on cookie sheet a few minutes before baking.","Bake 350 degrees for 10-15 minutes.","Finished cookie will be light in color."]},{"id":82,"name":"Holiday Soup - Variation of Chicken Soup","cat":"Soups","submittedBy":"Angie Dellos","description":"The little meatballs, spinach, eggs, and cheese added to regular chicken soup make it a \u201cspecial\u201d  or \u201choliday\u201d  soup.  Served whenever soup is part of a holiday meal.","time":"-","serves":"","ingredients":[["1 whole","Chicken"],["small amount","Vinegar"],["small amount","Salt"],["","Unknown"],["1","Onions"],["4 stalks (include leaves)","Celery"],["4","Carrots"],["1/4 cup (or to taste)","Salt"],["","Unknown"],["2 bunches (may substitute endive)","Spinach"],["6 beaten","Eggs"],["3 Tbsp.","Romano Cheese"],["1/2 lb. Shaped into size of marbles","Meatballs"]],"steps":["Instructions for basic chicken:","Wash chicken thoroughly.  Cut at joints.  Place chicken into an 8-quart stock pot and cover with water.  Boil at a fast pace (for a few minutes).  Skim off excess foam until there is no foam left.  Reduce heat.  Add salt.  Let simmer about \u00bd hour.  Add onion, celery leaves, stewed tomatoes and carrots.  Simmer for 1 hour or more until chicken is tender.  Turn off heat and set aside.  When slightly cooled, remove chicken and vegetables.  Shred chicken and cut vegetables into small pieces.  Return to soup broth.  Ready to eat!","For special occasions: Clean escarole or spinach.  Steam.  Squeeze out excess water, chop, and add to broth.  Little (marble-sized) meatballs (made from ground chuck) may be added directly to broth, if desired.  Cook until meatballs are done.  When ready to serve soup, beat eggs, cheese, salt and pepper and drizzle into boiling soup.  This mixture will immediately come to the surface cooked.  Ready to serve."]},{"id":83,"name":"Pixies (Chocolate/Powder Sugar Cookies","cat":"Desserts","submittedBy":"Carol Zayac","description":"","time":"-","serves":"","ingredients":[["4 one-ounce squares","Chocolate squares"],["2-2&1/2 cups","Flour"],["2 tsp.","Baking Powder"],["1/2 tsp.","Salt"],["1/2 cup (may substitute oil)","Crisco"],["2 cups","Sugar"],["4","Eggs"],["2 tsp.","Vanilla"]],"steps":["Melt chocolate.","Let cool.","Combine and mix flour, baking powder and salt.","Set aside.","Combine and mix Crisco (or oil), chocolate, sugar, eggs and vanilla.  (Use mixer.)  Add dry ingredients to make a sticky dough.","Refrigerate 3-4 hours.","Roll cookies into a ball (about a teaspoonful each).","Coat entire cookie with confectioners sugar before baking.","Place on lightly greased cookie sheet.","Bake 350 degrees for 10-12 minutes."]},{"id":84,"name":"Best Cake Ever","cat":"Desserts","submittedBy":"Johnny Dellos Jr.","description":"","time":"-","serves":"","ingredients":[["1 Chocolate (may substitute White)","Cake Mix"],["1 jar (may substitute coconut*)","Caramel Toping"],["1 large","Cool Whip"],["4-5 bars (crunched-up) (may substitute coconut)","Heath Bars"]],"steps":["Make cake according to directions on box.","While still warm, poke with tines of a fork.","Smooth the entire jar of caramel topping on the cake.","Let cool.","Cover \\r \\r *Note: If you substitute white cake mix, use coconut topping (found in the Liqueur department--used for pin\u00e1 coladas) instead of caramel and use coconut instead of Heath bars.\\r"]},{"id":85,"name":"Coated Olive Cheese Balls","cat":"Appetizers","submittedBy":"Lillian Pisani","description":"","time":"-","serves":"","ingredients":[["2 cups, grated","Cheddar Cheese"],["1/2 cup, soft","Butter"],["1 cup","Flour"],["1/2 tsp.","Salt"],["1 tsp.","Paprika"],["48 medium","Medium Stuffed Green Olives"]],"steps":["Mix cheese and butter until soft.","Mix flour, salt and paprika together.","Add to cheese mixture.","Wrap dough around each stuffed olive.","It should be about the size of a walnut.","Bake 400 degrees for 15 minutes."]},{"id":86,"name":"Artichoke Dip","cat":"Appetizers","submittedBy":"Lillian Pisani","description":"Serve with crackers","time":"-","serves":"","ingredients":[["2 cans, drained","Artichoke Hearts"],["2 tsp.","Garlic Powder"],["3 Tbsp.","Lemon Juice"],["1 cup","Parmesan Cheese"],["cup","Mayonnaise"]],"steps":["Crush artichokes with potato masher or blender.","In a baking dish, combine all ingredients.","Bake at 350 degrees for 20 minutes.","Serve with crackers."]},{"id":87,"name":"Nut Roll","cat":"Desserts","submittedBy":"Lillian Pisani","description":"At Christmas time, I get calls from family and friends to be sure to make this.  This same message from two other families with the same nut roll recipe.  Makes 4 large nut rolls.","time":"-","serves":"","ingredients":[["1 package","Dry Yeast"],["1 tsp.","Sugar"],["1 tsp.","Flour"],["1/4 cup, lukewarm","Water"],["3 Tbsp.","Sugar"],["1 tsp.","Salt"],["4 cups","Flour"],["1 5 oz. can (add water to make 1 cup)","Evaporated Milk"],["1/4 lb.","Margarine"],["3 beaten","Egg Yolks"],["1 lb., crushed","Walnuts"],["1/4 lb.","Margarine"],["1 5 oz. Can","Evaporated Milk"],["1 cup","Sugar"]],"steps":["Dough: Dissolve 1st four ingredients in water.","Let stand until mixture foams.","Measure 4 cups flour, sift with sugar and salt.","Cut in the margarine (as you would for a pie crust).","Mix egg yolks and milk.","Add foaming yeast.","Make a dent in flour and add mixture.","Knead into a smooth dough.","Place in a bowl.","Grease the top and place in refrigerator overnight.","Filling: Place milk, sugar and margarine in saucepan.","Bring to a boil.","Remove from heat.","Combine with nuts and beaten egg white.","Separate dough into 4 sections.","Roll each section as if you were making pizza, in the shape of a rectangle.","Spread filling over top (about 4 heaping tablespoons on each section).","Roll up as in jellyroll.","Place on a greased cookie sheet with seam down.","Pinch sides.","Let raise about 2 hours on the baking sheet before baking.","Bake 325 degrees for 20-25 min. until brown.","Cool and sprinkle with powdered sugar or make a light powdered sugar frosting.","Slice and serve."]},{"id":88,"name":"Puppy Chow Snack","cat":"Miscellaneous","submittedBy":"Olivia and Phillip Schofield","description":"Delicious!  A great snack.","time":"-","serves":"","ingredients":[["1 12 oz. Bag","Chocolate-chips"],["1 stick","Margarine"],["1 cup","Peanut Butter"],["12 oz.","Rice Chex Cereal"],["2 cups","Powdered Sugar"]],"steps":["Melt chocolate chips, margarine and peanut butter.","Pour over rice chex cereal.","Place powdered sugar in a brown bag.","Add chex mix and shake.","Store in tupperware."]},{"id":89,"name":"Ziti with Broccoli","cat":"Pasta","submittedBy":"Mary Beth Schofield","description":"This dish is best served with a loaf of Jim Roma's Italian bread.  It is a great main dish or side dish.  It comes in handy during the Lenten season when you run out of meatless dishes to serve.\\r\\n","time":"-","serves":"","ingredients":[["1&1/2 lb.","Broccoli"],["8 sprigs, fresh","Parsley"],["2 large, mashed","Garlic"],["3/4 lb.","Ziti Pasta"],["1/4 cup","Olive oil"],["2 Tbsp.","Butter"],["1/4 cup, freshly grated","Parmesan Cheese"],["1/2 tsp., freshly ground","Pepper"]],"steps":["Cut stems off broccoli and wash thoroughly.","Chop parsley and garlic \\r together.","Steam broccoli.","In another pot, cook Ziti in boiling salted water (al dente) about 20 minutes.","Combine olive oil, butter, parsley and garlic.","Mix.","Warm this sauce for 2 minutes.","DO NOT COOK OR BURN.","Drain broccoli and Ziti as soon as cooked.","Place pasta and broccoli in the hot pot that the Ziti was cooked in, and pour the sauce over both.","Sprinkle with cheese and black \\r pepper.","Stir.","Transfer to serving dish and serve immediately.\\r"]},{"id":90,"name":"Scaloppini di Vitello ala Francese","cat":"Pasta","submittedBy":"Mary Beth Schofield","description":"In other words, \u201cBattered-Fried Veal with Lemon.\u201d  This is one of Oaks Inn's most popular dishes.  The Oaks Inn was one of the favorite hangouts on the north side of Endicott.  Our parents talk about how they hung out there, and drank birch beer (yea, right!).  By the time I was of age, it became more of a dining restaurant instead of a \"pizza place\".  At one time, they served the best round \"hot pies\" (pizzas).  The sign in front still reads \"Hot pies\".\\r\\n","time":"-","serves":"","ingredients":[["1&1/2 pounds, thin slices (scallopini)","Veal"],["1/4 tsp. (freshly ground pepper is best.)","Salt and Pepper"],["1/4 cup","Flour"],["1","Eggs"],["2 Tbsp.","Milk"],["6 Tbsp.","Butter"],["1 Juice only","Lemon"],["1 cut into 8 thin, seeded slices","Lemon"],["1 Tbsp.","Parsley"]],"steps":["Pound the veal with a mallet until very thin.","Sprinkle with salt and pepper, and dredge in flour on both sizes.","Beat egg well.","Add milk, salt and pepper.","Blend.","Dip veal in egg to coat both sides.","Note: (Dredging in flour first before dipping in egg mixture gives the veal a nice puffy texture when fried.)  Heat butter in a very heavy skillet (or electric frying pan).","Add veal.","Cook about 2 minutes on one side, or until golden.","Turn and cook on the second side until golden.","Remove veal.","Add lemon juice to skillet.","Pour this over veal.","Garnish with lemon slices and sprinkle with parsley.\\r"]},{"id":91,"name":"Spaghetti with Marinara Sauce","cat":"Pasta","submittedBy":"Mary Beth Schofield","description":"Goes well served as side dish to Veal Scaloppini.","time":"-","serves":"","ingredients":[["4 cups","Imported Italian tomatoes"],["1/4 tsp.","Salt"],["1/4 tsp., freshly ground","Pepper"],["2 Tbsp.","Olive oil"],["1 clove, finely chopped","Garlic"],["1 Tbsp., fresh, chopped (may substitute 1 teaspoon dried basil)","Basil"],["1 lb.","Spaghetti"],["1/4 cup","Parmesan Cheese"]],"steps":["Empty tomatoes with their liquid into saucepan.","Bring to boil and simmer until tomatoes reduce to three cups.  (For a thicker sauce, reduce to 2 cups.)  Add salt and pepper to taste.","Heat olive oil in saucepan.","Add garlic and cook for a few seconds.","Add tomato sauce and basil.","Pour over cooked Spaghetti.","Add grated cheese."]},{"id":92,"name":"Trifle","cat":"Desserts","submittedBy":"Mary Beth Schofield","description":"For best results, make this at least a few hours before serving.","time":"-","serves":"","ingredients":[["1 (9x5) (may substitute sponge cake)","Pound Cake"],["1 pkg.","Vanilla Pudding"],["1 pkg. (may substitute Cook Whip)","Whipping Cream"],["1 cup (may substitute any other fruit--bananas are good!","Blueberries"],["1 cup (may substitute any other fruit--strawberries are good!","Peaches"],["1/8 cup, (optional)","Liqueur"]],"steps":["Cut cake into 1\" squares and sprinkle with liqueur (amaretto is good).","Layer cake squares, blueberries, pudding, whipped cream, cake squares, peaches and whipped cream in a glass trifle serving bowl.","Garnish with more fruit pieces."]},{"id":93,"name":"Chicken Breasts in White Wine","cat":"Meat","submittedBy":"Mary Beth Schofield","description":"Makes 2-4 servings","time":"-","serves":"","ingredients":[["2 cloves, crushed","Garlic"],["1/4 cup","Butter"],["1 lb., skinned and boned","Chicken Breasts"],["2/3 cup","Dry White Wine"],["3/4 tsp.","Salt"],["1/4 tsp.","White Pepper"],["1 bunch of sprigs for garnish","Parsley"],["1 cut into wedges for garnish","Lemon"]],"steps":["In a hot skillet, saut\u00e9 chicken and garlic in butter until golden (3-4 minutes on each side).","Add wine, salt and pepper.","Bring to boil.","Reduce heat.","Simmer covered for 20 minutes or until tender.","Remove chicken to a heated dish.","Add pan drippings mixed with 1/3 cup wine and more salt, if needed.","Pour wine sauce over chicken.","Garnish with lemon and parsley.","Juice of a lemon may be squeezed over chicken, if you wish.","Makes 2-4 servings. \\r"]},{"id":94,"name":"Milky Way Wonder Cake","cat":"Desserts","submittedBy":"Mary Beth Schofield","description":"","time":"-","serves":"","ingredients":[["6 (or 13 miniature bars)","Milky Way Candy Bars"],["1 cup","Margarine"],["2 cups","Sugar"],["1 cup","Walnuts"],["2&1/2 cups","Flour"],["1/2 tsp.","Baking Soda"],["1&1/4 cup","Buttermilk"],["1 tsp.","Vanilla"]],"steps":["Melt candy bars with \u00bd cup margarine over very low heat.","Set aside.","Beat remaining \u00bd cup margarine and sugar until fluffy.","Add eggs, one at a time.","Add flour, baking soda and nuts with buttermilk and vanilla.","Beat until smooth.","Add melted chocolate bars and mix well.","Pour into greased 9\" tube pan.","Bake 350 degrees for 1 hour and 20 minutes.","Cool in pan for 10 minutes before removing.\\r"]},{"id":95,"name":"Greens alla Rumble","cat":"Non-Meat","submittedBy":"Mary Beth Schofield","description":"This recipe is from the Pastor of St. Anthony's Church.  He loves to cook, and this is a good one!\\r\\n","time":"-","serves":"","ingredients":[["3-4 cloves","Garlic"],["2-3 bunches (may substitute other type of greens)","Spinach"],["5-6 slices","Prosuitto"],["506 (more or less to taste)","Hot Cherry Peppers"],["1/4 cup","Breadcrumbs"],["1/4 cup","Parmesan Cheese"],["","Olive oil"]],"steps":["Cut and clean spinach.","Cook in salted boiling water until tender.","Place olive oil in pan and saut\u00e9 crushed garlic, chopped prosciutto, and peppers until brown.","Drain spinach and add to pan.","Sprinkle with bread crumbs and cheese.","Mix and enjoy!\\r"]},{"id":96,"name":"Roasted Peppers with Onions","cat":"Miscellaneous","submittedBy":"Diane Randesi","description":"Peppers and onions can be served with cooked hot sausage.  We like to add them to any sandwich of cold meat.","time":"-","serves":"","ingredients":[["10","Green Pepper"],["to taste","Salt and Pepper"],["1/4 cup","Olive oil"],["1-2 large","Onions"],["to taste","Salt and Pepper"]],"steps":["Place as many peppers as you can fit on a cookie sheet.","Broil in the oven for about 10 minutes.  (Keep checking so as not to burn.)  Turn the peppers to another side and continue broiling (about 5-10 more minutes).","Continue doing this until you have broiled as much of each pepper as possible.  (They will be limp and falling over.)  Remove from oven.","Place peppers in a brown paper bag while they cool completely.  (This makes peeling easier).","Remove from bag, peel peppers, remove pith and seeds, and break into strips.","Place in serving dish.","Add oil, garlic, salt and pepper.","Meanwhile, in a skillet, saut\u00e9 onion until limp and brown.","Add salt and pepper.","Set aside.","Combine onions with peppers in the serving dish"]},{"id":97,"name":"Filled Cupcakes","cat":"Desserts","submittedBy":"Mary Beth Schofield","description":"","time":"-","serves":"","ingredients":[["3 cups","Flour"],["2 cups","Sugar"],["1/2 cup","Cocoa"],["2 tsp.","Baking Soda"],["2/3 cup","Vegetable Oil"],["2 cups","Water"],["2 Tbsp.","White Vinegar"],["2 tsp.","Vanilla"],["1 tsp.","Salt"]],"steps":["Combine and mix all ingredients.","Fill cupcake tins 2/3 full.\\r \\r Filling: Make mixture of cream cheese, egg, sugar, and chocolate chips.","Drop 1 teaspoonful of this mixture into each filled cupcake tin.","Bake 350 degrees for 25 minutes.\\r"]},{"id":98,"name":"Nut Mallow Goodies","cat":"Desserts","submittedBy":"Mary Beth Schofield","description":"Makes 64 one-inch squares","time":"-","serves":"","ingredients":[["1/2 large package (1 cup)","Chocolate-chips"],["1 cup","Butterscotch Chips"],["1/2 cup","Peanut Butter"],["3 cups, miniature","Marshmallows"],["1 cup","Salted Peanuts"]],"steps":["Combine chocolate chips, butterscotch chips, and peanut butter in top of a  double boiler until morsels melt.","Add marshmallows and salted peanuts.","Mix.","Spread in lightly-greased 8\" square pan.","Chill until firm.","Cut into 1\" squares. \\r  \\r"]},{"id":99,"name":"Buttermilk Puffs","cat":"Desserts","submittedBy":"Mary Beth Schofield","description":"","time":"-","serves":"","ingredients":[["2 cups, sifted","Flour"],["1/4 cup","Sugar"],["1 tsp.","Baking Powder"],["1 tsp.","Nutmeg"],["3/4 cup","Buttermilk"],["1/4 cup","Cooking Oil"],["1","Eggs"]],"steps":["Sift together flour, sugar, baking powder, baking soda, and nutmeg.","Stir buttermilk, oil and egg with fork.","Combine and beat until smooth.","Drop by teaspoonful into hot oil and fry.","Remove from oil when done and sprinkle with powdered sugar.","Light & delicious."]},{"id":101,"name":"Rye Bread and Dip","cat":"Appetizers","submittedBy":"Mary Beth Schofield","description":"Served at many family gatherings as a \"pickie\" before main dishes.","time":"-","serves":"","ingredients":[["2 tsp., chopped","Onions"],["","Unknown"],["1 smaller loaf to cut into squares","Bread"],["1 large (Rye or Pumpernickle or Marble)","Bread"],["2 Tbsp.","Dill Weed"],["2 cups","Mayonnaise"],["3 cups","Sour Cream"],["1 large, chopped into small pieces","Dried Beef"]],"steps":["Mix onions, dill, mayonnaise, sour cream and dried beef together and refrigerate overnight.","Carve center out of a round loaf of bread.","Fill with dip.","Cut pieces from a small loaf of bread for dipping.  (Raw vegetables can also be used for dipping.);"]},{"id":102,"name":"Yellow Squash","cat":"Non-Meat","submittedBy":"Mary Beth Schofield","description":"Great for a Thanksgiving side dish","time":"-","serves":"","ingredients":[["4 pkgs., frozen (may substitute 6-8 fresh)","Summer Squash"],["1 medium","Onions"],["1 stick","Margarine"],["1 grated","Carrots"],["1 cup","Sour Cream"],["to taste","Salt and Pepper"],["1 8 ounce package (Pepperidge Farm)","Corn Bread Stuffing"]],"steps":["Cook squash and drain.","Add all other ingredients to squash.","Place in Pyrex baking dish.","Bake 350 degrees for 30 minutes."]},{"id":103,"name":"Crockpot Beans","cat":"Non-Meat","submittedBy":"Gail Dellos","description":"This is great for a barbecue!","time":"-","serves":"","ingredients":[["1 lb.","Ground Beef"],["1 lb.","Bacon"],["1 large, chopped","Onions"],["2 cans (15 oz.)","Pork 'n Beans"],["1 can (15 oz.), undrained","Kidney Beans"],["1 can","Butter Beans"],["1 cup","Catsup"],["1/2 cup","Brown Sugar"],["2 Tbsp.","Liquid Smoke"],["3 Tbsp.","Vinegar"],["to taste","Salt and Pepper"]],"steps":["Brown ground beef and onion.","Drain.","Cook bacon.","Drain and \\r crumble.","Combine all ingredients in crockpot and cook on low for 5-6 hours.\\r"]},{"id":104,"name":"Mixed Greens & Mandarin Orange Salad","cat":"Salads","submittedBy":"Gail Dellos","description":"","time":"-","serves":"","ingredients":[["1/2 head, washed and torn apart","Iceberg Lettuce"],["1/2 head, washed and torn","Romaine Lettuce"],["1/2 bag, washed, with stems removed","Spinach"],["1 small head","Boston Lettuce"],["2 cups, thinly sliced","Celery"],["3 Tbsp., minced","Parsley"],["6 washed and chopped","Scallions"],["2 cups, drained","Mandarin Oranges"],["3/4 cups","Almonds"],["","Unknown"],["1&1/2 tsp.","Salt"],["3/4 tsp.","Hot pepper sauce"],["3/4 cups","Salad Oil"],["6 Tbsp.","Sugar"],["6 Tbsp.","Tarragon Vinegar"]],"steps":["Combine lettuces and spinach in large bowl.","Toss with celery, parsley and scallions.  (To this point, you can prepare ahead of time.)  Just before serving, add oranges and almonds.","Toss with dressing.","Serve."]},{"id":105,"name":"Spaghetti with Pesto Sauce","cat":"Pasta","submittedBy":"Diane Randesi","description":"","time":"-","serves":"","ingredients":[["1 lb.","Spaghetti"],["2 cups, fresh, washed and drained","Basil Leaves"],["1 cup, freshly grated","Parmesan Cheese"],["1/2 cup","Olive oil"]],"steps":["While cooking pasta, blend fresh basil in a blender.","Add cheese and oil.","Whirl at high speed until it makes a coarse puree.","Pour on Spaghetti, cooked al dente.","Toss.","Serve.","Option: Add crushed pine nuts."]},{"id":106,"name":"Roasted Potatoes","cat":"Non-Meat","submittedBy":"Jeff Randesi","description":"My favorite potato recipe is my Aunt Gail\u2019s (above); my second favorite is below:","time":"-","serves":"","ingredients":[["8","Potatoes"],["1/2 cup","Breadcrumbs"],["1/2 cup","Parmesan Cheese"],["to taste","Salt and Pepper"],["3 Tbsp.","Parsley"],["enough to drizzle over potatoes","Olive oil"]],"steps":["Peel and cut potatoes into thick slices.","Rinse.","Add potatoes to a plastic bag containing mixture of cheese, bread crumbs, salt, pepper and parsley.","Shake to cover potatoes with mixture.","Empty potatoes into baking dish.","Drizzle with olive oil.","Bake 450 degrees for 30 minutes or until golden brown."]},{"id":107,"name":"Spaghetti Sauce with Meatballs","cat":"Meat","submittedBy":"Diane Randesi","description":"This sauce can be made without meat.  I like it better served the day after making it.","time":"-","serves":"","ingredients":[["1 lb.","Ground Chuck"],["2","Eggs"],["3 Tbsp.","Parsley"],["3 Tbsp.","Parmesan Cheese"],["to taste","Salt and Pepper"],["2 slices soaked in water","Bread"],["3 large cans (whole tomatoes)","Tomatoes"],["3 small cans","Tomato Paste"],["2","Bay leaves"],["1 large","Onions"],["1","Green Pepper"],["1 crushed","Garlic"],["","Salt and Pepper"]],"steps":["Empty one can of tomatoes at a time into blender and liquify.","Pour into large sauce pan.","Add tomato paste directly from the can to the sauce pan.","Simmer.","Meanwhile, in a skillet with a little oil, fry one onion, one green pepper, a crushed garlic, salt and pepper to taste.","When limp, add to blender (with about 1/2 cup of water) and liquify.","Add this to tomatoes in the sauce pan.","Stir with wooden spoon.","Add approx. 1-1&1/2 cups of water, (depending on how thick you  like the sauce).","Drop in whole bay leaves.","Simmer (partially covered) for 1&1/2 hours or more.","If you are are making a meat sauce:  While the tomato sauce is simmering,  mix meatball  ingredients.","Roll into 1&1/2\" balls and brown. (One pound should make about 12 meatballs.)  Add to simmering sauce and cook at least 1 hour.","If you prefer loose meat in sauce, mix ingredients and fry loose, then add to simmering sauce.","Hot sausage or braciola may be added to sauce in the same way after browning them.","Cook macaroni (spaghetti, penne, rotelli, ziti, rigatoni, whatever).","Top macaroni with sauce and parmesan cheese.","Serve."]},{"id":109,"name":"Pasta Italiano Salad","cat":"Salads","submittedBy":"Diane Randesi","description":"A family favorite, especially at a summer barbecue.  Colorful.  Serves 6.","time":"-","serves":"","ingredients":[["3/4 cup","Olive oil"],["1/4 cup","Wine Vinegar"],["1/4 cup","Green Onion"],["1/2 cup, fresh with stems removed","Basil Leaves"],["3 Tbsp.","Parmesan Cheese"],["1 tsp.","Salt"],["1/4 tsp.","Pepper"],["12 oz.","Rotelle (Sprial) Pasta"],["1 small, cut in 2\\","Zucchini"],["1 pint","Broccoli Flowerets"],["1 cut in thin strips","Green Bell Pepper"],["1 cut in thin strips","Red Bell Pepper"],["1/2 cup, sliced","Pitted Black Olives"],["9 oz.","Feta Cheese"],["1/2 tsp.","Oregano"]],"steps":["In a blender, process oil, vinegar, green onion, basil, cheese, salt and pepper until smooth.","Refrigerate.","Cook pasta (al dente).","During the last 45 seconds of cooking, add zucchini and broccoli.","Drain.","Rinse in cold water.","Drain again.","In a large serving bowl, combine pasta, zucchini, broccoli, pepper strips, olives and cheese.  (Keep dressing and salad separately if you prepare ahead of time.)  When ready to serve, pour dressing over salad and toss.","Sprinkle oregano over top.","Serve at room temperature."]},{"id":110,"name":"Ciamelles","cat":"Desserts","submittedBy":"Minnie DiFulvio","description":"This ciamelle (pronounced chum-el) recipe does not use yeast\u2014it is more of a plain cookie than a bagel (see p. 117).","time":"-","serves":"","ingredients":[["6 at room temperature","Eggs"],["6 Tbsp.","Vegetable Oil"],["8 Tbsp.","Sugar"],["1 tsp.","Lemon Flavoring"],["4 cups","Flour"],["","Confectioner's Sugar"],["","Water"],["","Lemon Juice"]],"steps":["Combine and mix all ingredients to a medium dough.","Break off a small amount of dough  (enough to form a rope about the size of a cigar).","Cut into 1\u00bd to 3\" pieces.","Drop pieces into boiling water one by one.","Do not crowd.","When they rise to the top, remove and dry on dishtowel for about 1 hour.","Cut a slit down the middle of each cookie.","Heat oven to 375 degrees.","Bake cookies directly on oven rack (not on a cookie sheet) for 15 minutes or until golden brown.","Ice with powdered sugar mixed with water and the juice of\\r a lemon.","Frost cookies with a pastry brush.\\r"]},{"id":111,"name":"No-Cook Tomato Sauce for Fettuccini","cat":"Pasta","submittedBy":"Angie Dellos","description":"A wonderful sauce when tomatoes are in season.  The tomatoes MUST be very ripe  This is best if made early in the day.  Serves 6","time":"-","serves":"","ingredients":[["4 medium, peeled, seeded & cut in cubes","Tomatoes"],["1/2-3/4 pounds cut in 1/2\\","Mozzarella Cheese"],["1/4 cup","Fresh Basil"],["3/4 cup (or less if you","Olive oil"],["3 cloves, crushed","Garlic"],["to taste","Salt and Pepper"],["1 lb.","Fettuccini Pasta"]],"steps":["Mix all ingredients (except pasta) and let stand at room temperature.","Cook fettuccini pasta al dente.","Spoon sauce over pasta.","Enjoy!"]},{"id":112,"name":"Oven-Fried Fish","cat":"Fish","submittedBy":"Angie Dellos","description":"One of my favorites.  Recommended by the Heart Association.  Makes 4 servings.  300 calories","time":"-","serves":"","ingredients":[["1/4 cup, melted","Margarine"],["1 Tbsp.","Lemon Juice"],["1/4 tsp.","Pepper"],["1/4 tsp.","Paprika"],["1/4 tsp.","Dry Basil"],["1/8 tsp.","Garlic Powder"],["1 lb. (may substitute red snapper)","Fillet of Flounder"],["1/4 cup","Breadcrumbs"],["2 Tbsp.","Oil"]],"steps":["Combine melted margarine, lemon juice, pepper, paprika, basil and garlic powder.","Dredge fish in margarine/herb mixture, and roll in bread crumbs.","Spread oil in shallow baking dish and arrange fish in one layer.","Spoon remaining herb mixture over fish.","Bake uncovered 475 degrees for 15 minutes or until the fish flakes easily with a fork.\\r"]},{"id":113,"name":"Date Rolled Oat Bars","cat":"Desserts","submittedBy":"Sabina Greco","description":"","time":"-","serves":"","ingredients":[["1/2 cup","Shortening"],["1 cup, packed","Brown Sugar"],["1&1/2 cup","Flour"],["1/4 tsp.","Salt"],["1 tsp.","Baking Soda"],["1&3/4 cup","Rolled Oats"],["1 lb.","Dates"],["1 cup","Sugar"],["1 cup","Water"]],"steps":["In a bowl, add brown sugar to shortening.","Mix.","Add flour, salt, baking soda and oats.","Mix well, with fingers, if needed (like a pie crust).","Separate dough into two equal pieces.","Press \u00bd of the dough into bottom of greased pan.","Meanwhile, make Filling: Place dates, sugar and water into a saucepan.","Stir over low heat until consistency for spreading.","Cool mixture.","Spread \\r filling over bottom dough.","Top with remaining \u00bd of the dough.","Bake 350 degrees for 15-20 minutes or until brown.","Cut into bars.  \\r"]},{"id":114,"name":"Gnocchi","cat":"Pasta","submittedBy":"Lillian Pisani","description":"Pronounced (nyok-key).  Makes about 5 batches.","time":"-","serves":"","ingredients":[["1 lb.","Ricotta Cheese"],["1 tsp","Salt"],["1 large, lightly beaten","Egg Yolks"],["1&1/2-2 cups, unbleached, all purpose","Flour"]],"steps":["Mix all ingredients in food processor.","Remove.","Separate the dough into 5 batches, each the size of an orange.","Flour your hands lightly.","Using both hands, roll out each piece of dough with a light back and forth motion (knead it) until about the thickness of your thumb.","Let dough rest.","Knead again.","Cut each roll (batch) into 1\" pieces.","To form Gnocchi pieces, hold a fork, its tines against a work board, the curved part of fork facing away from you.","Starting from the outside bottom of the curve, press each piece of dough with your index finger, firmly upward along the length of the tines.  (This gives the pasta appealing, fancy lines.)  Let the gnocchi fall back on surface.","They can be cooked immediately or kept in refrigerator overnight.","Freeze them on a cookie sheet, making sure they do not touch each other.","When frozen, place into a plastic bag for storing in the freezer until ready to use."]},{"id":115,"name":"Peanut Brittle","cat":"Desserts","submittedBy":"Lillian Pisani","description":"All the kids like this, especially my grandson, Matthew.","time":"-","serves":"","ingredients":[["1 cup","Sugar"],["1/2 cup","White Corn Syrup"],["","Roasted Peanuts"],["1 tsp.","Vanilla Flavoring"],["1 tsp.","Butter"],["1 tsp.","Baking Soda"]],"steps":["Combine sugar and corn syrup.","Stir for 4 minutes in microwave.","Stir roasted peanuts 3-5 minutes in microwave.","Add vanilla and butter.","Mix for 2 minutes.","Add baking soda and mix.","Pour onto a greased pan.","When cooled, break into pieces."]},{"id":116,"name":"Southern Pound Cake","cat":"Desserts","submittedBy":"Lillian Pisani","description":"I got this recipe from my sister, Kay.","time":"-","serves":"","ingredients":[["1/2 lb.","Margarine"],["1/2 cup","Crisco"],["3 cups","Sugar"],["3 cups","Flour"],["1 cup","Milk"],["2 tsp.","Vanilla Flavoring"],["1/2 tsp.","Baking Powder"],["1 tsp.","Salt"],["1/2 cup","Walnuts"]],"steps":["Cream together Crisco and sugar.","Add eggs and vanilla.","Combine dry ingredients and alternate with milk to creamed mixture.","Turn into long pound cake pan.","Sprinkle with chopped walnuts.","Bake 350 degrees for 1 hour."]},{"id":117,"name":"Banana Bread","cat":"Desserts","submittedBy":"Lillian Pisani","description":"Easy to make and very good.","time":"-","serves":"","ingredients":[["1/2 cup","Vegetable Oil"],["1 cup","Sugar"],["2 beaen","Eggs"],["3 mashed","Banana"],["2 cups","Flour"],["1 tsp.","Baking Soda"],["1/2 tsp.","Baking Powder"],["1/2 tsp.","Salt"],["3 Tbsp.","Milk"],["1/2 tsp.","Vanilla Flavoring"],["1/2 cup (optional)","Walnuts"]],"steps":["In a mixing bowl, cream together oil, sugar, eggs, milk vanilla and bananas.","Add dry ingredients (except walnuts).","Mix.","Add walnuts.","Turn into a baking dish.","Bake 350 degrees for 1 hour.\\r"]},{"id":118,"name":"Really Meaty Pasta","cat":"Pasta","submittedBy":"DJ Dellos","description":"This is a quick and easy meal for a college student.  It is my favorite, but then, it's the only thing I know how to make!  My grandma (Angie Dellos) promised to teach me how to make some good meals, and I guess I\u2019ll experiment with this cookbook when I get it for Christmas.","time":"-","serves":"","ingredients":[["1 pound","Ziti Pasta"],["1 can (Ragu flavored with meat)","Spaghetti Sauce"],["1 pound","Ground Beef"]],"steps":["Fry the meat.","Mix into the sauce, and it's ready to go!;"]},{"id":119,"name":"Pizza (Hot Pie)","cat":"Non-Meat","submittedBy":"Diane Randesi","description":"","time":"-","serves":"","ingredients":[["1 lb. (Bridgeford)","Frozen Bread Dough"],["1/2 can","Pizza Sauce"],["","Parmesan Cheese"],["","Mozzarella Cheese"],["","Salt and Pepper"],["","Parsley"],["","Olive oil"],["","Unknown"]],"steps":["Pour a little oil on the bottom of a cookie sheet or pizza pan.","Place one frozen loaf of dough on the cookie sheet, and allow it to defrost.  (I usually leave it out all day, but a couple of hours will work.)  When thawed, spread bread dough to cover bottom of cookie sheet.","Layer with pizza sauce, Parmesan and Mozzarella cheese, salt, pepper, and parsley.","At this point, you can add any other toppings, such as pepperoni, cooked sausage, green peppers, mushrooms, etc.","Allow the pizza to stand for about 30 minutes--it will probably raise a little more.","Before placing in oven, drizzle with a little olive oil, and press into the dough with your fingers, making sure to cover the entire top of the pizza, (This is done so that the drizzled oil has grooves to settle into.)  Place in oven.","Cook 350 degrees for 20 minutes."]},{"id":120,"name":"Arroz Con Pollo De Cuba","cat":"Soups","submittedBy":"Barbara Dellos","description":"This is an old family recipe from my adopted \u201cCuban side\u201d of the family.  From as\\r\\n\tfar back as I can remember the aroma of simmering rice and chicken meant \\r\\nthat there was a \u201cspecial occasion\u201d to be celebrated.  It has become one of my own family's special request, and a regular main course for holidays that our family spends together.  AS A TRIBUTE to my adoptive mother and my \\r\\nadoptive father's mother: This is FOR YOU so that your tradition will forever go down in the history of the Dellos and Greco families!\\r\\n","time":"-","serves":"","ingredients":[["1 large, whole","Chicken"],["","Rice"],["","Variety of Vegetables"],["","Salt and Pepper"],["2 large, chopped","Tomatoes"],["1 bunch, (may substitute parsley)","Cilantro"]],"steps":["Wash chicken.  Add chicken to pot of water.  Cook on high heat.  Cover tightly until boiling.  Lower heat and simmer for 45 minutes, with lid still on.  Remove and break up chicken pieces into small shreds.  Discard bones, skin and gristle.  Reserve 1/3 of the broth for rice and the rest is your soup base.","Prepare the veggies: They are not pre-cooked.  Chop into small pieces.  Suggestions of veggies for flavor and color are listed above.  Set aside to be added to the chicken broth, when it is combined with rice.","Prepare the rice: Pour 2-3\" deep of white rice into a deep pot.  Wash and rinse several times until the water is no longer milky.  Add enough of chicken broth to cover the rice (at least two inches) and stir well on medium heat.  Add salt and pepper (to taste) to the broth and stir.  Add uncooked, small diced veggies to broth and rice, once again stirring.  Add more chicken broth to cover rice by two inches before you begin to simmer.  Add at least \u00bd of the shredded chicken to your pot of rice, leaving the remainder for the soup.  Uncovered, heat on high until boiling.  Continue to stir rice, chicken, veggies and broth until it comes to a full boil.  IMMEDIATELY lower flame to simmer, cover pot tightly, and allow to slow cook/simmer for 45 minutes.  Be careful to cook on lowest heat or you will burn bottom of rice, which will give a burned flavor to the entire pot!  DO NOT PEEK IN OR REMOVE THE POT LID WHILE STEAMING!  THIS WILL RUIN YOUR RICE!  (More than once I was scolded for this!)  After 45 minutes, uncover the pot and gently stir.","Transfer to a decorative plate or baking dish.  Top with additional chicken and edible greenery.","Variation: Adding fish to this recipe makes it \u201cPaella\u201d (pie-a-ahh).  Use shrimp (fully cooked and shelled), mussels, octopus or tuna.  All fish must be pre-cooked and seasoned and added to the top of the finished dish for decoration and color.","Barb\u2019s Complete-Meal Nutritious Soup: Whatever is left over from your boiled and de-boned chicken becomes the perfect soup base for a first course.  Bring broth to boil and drop in 4 whipped eggs (just stir and break them up with a fork), stirring while they cook.  Add diced cilantro to taste, red, green and yellow peppers, yellow onions, pre-cooked diced Russet potatoes, baby carrots and fresh spinach.  Season with onion or garlic salt, pepper, and a crushed clove of garlic.  Additional soup fillers could be rice, barley, or small elbow macaroni, fresh tomatoes, cabbage and celery.  Serve soup steaming hot, adding fresh Parmesan cheese to top.  Voil\u00e0!"]},{"id":121,"name":"Momma Eggs","cat":"Non-Meat","submittedBy":"Barbara Dellos","description":"Okay, so it\u2019s a corny name for a breakfast plate, but it has always been an appropriate description of our family's special morning requests.  Both Dove and DJ make these for themselves and have told their friends how to make them, so the simple \u201cDellos Breakfast Special\u201d is now circulating our immediate neighborhood!  You only need a few ingredients, but they MUST be the ones listed.  Substitutes do not work!  This recipe serves one.","time":"-","serves":"","ingredients":[["2","Eggs"],["2 may substitute Sheephearders, butter loaf, all purpose white, or sourdough, plain English muffins","White Bread"],["enough to cover bottom of frying pan","Butter"]],"steps":["Place butter in bottom of frying pan.","Warm slowly.","DON\u2019T ALLOW TO BURN.","Take both slices of bread and tear out a small hole (size of a 50 cent piece) from the center.","Eat or discard.","Dip both sides of bread in melted butter, being sure to cover the whole thing.","Lay the two pieces of bread next to each other in the frying pan and break both of the eggs, placing them whole, with yolks in center hole of the bread.","Cooking on medium heat, season with salt and pepper to taste until done.","For more well-done eggs, gently flip with a spatula.","Momma eggs taste best when their bread is slightly burned (like a grilled cheese sandwich) and the eggs are a little crusty.","Yumm.","For variety, add String or Monterey Jack cheese to the top of the almost-cooked egg.  (DON\u2019T FLIP IF YOU USE CHEESE!)  \\r Option: Add chopped bacon, pepperoni, diced chives or sausage to the half-cooked yolks, which makes this a complete breakfast meal that is easy to take along with you (eats like a sandwich).","Re-heats deliciously.\\r"]},{"id":122,"name":"Chocolate Turtle Cheesecake","cat":"Desserts","submittedBy":"Michelle Roma","description":"Only 5 minutes to prepare.  Serves 12.","time":"-","serves":"","ingredients":[["1 (14 oz.) package","Caramels"],["1 (5 oz.) can","Evaporated Milk"],["1 9\\\"_x000d_","Chocolate Crumb Piecrust"],["1 (3 oz.)","Cream Cheese"],["1/2 cup","Sour Cream"],["1/4 cup","Milk"],["1 package, chocolate","Instant Pudding"],["1/2 cup","Fudge Topping"]],"steps":["Place caramels and evaporated milk into heavy saucepan.","Heat on medium.","Stir constantly until smooth (about 5 minutes).","Stir in 1 cup of pecans.","Pour into pie crust.","Combine cream cheese, sour cream and milk in blender until smooth.","Add pudding mix, and blend 30 seconds more.","Pour pudding mixture over caramel layer, covering evenly.","Chill loosely covered (15 minutes).","Drizzle fudge topping over pudding layer in a decorative pattern.","Sprinkle one quarter cup chopped pecans.","Chill loosely-covered until ready to serve.\\r"]},{"id":123,"name":"Chicken Souffle","cat":"Meat","submittedBy":"Alice Kocik","description":"This is a recipe that my dear sister gave me years ago.  It is a favorite of mine.","time":"-","serves":"","ingredients":[["1&1/2 cups","Milk"],["2","Eggs"],["to cover bottom of pan","Breadcrumbs"],["to taste","Salt and Pepper"],["1/2 cup","Mayonnaise"],["1/2 cup, chopped","Celery"],["1/4 cup, chopped","Onions"],["4 cups","Cooked, Diced Chicken"],["1 can (may substitute mushroom soup)","Cream of Chicken Soup"],["1 cup","Cheddar Cheese"]],"steps":["Mix cooked chicken, onion, celery, mayonnaise, salt and pepper as for a salad.","Grease 13x9\" pan and spread bread crumbs in thin layer.  (I use Pepperidge Farms Stuffing Mix.)  Spread chicken salad over bread crumbs.","Beat together eggs and milk.","Pour over chicken mixture.","Let stand 1/2 hour.","Pour undiluted cream of mushroom or chicken (I use mushroom) soup over top.","Cover with foil and refrigerate overnight.","Bake 325 degrees for 50 minutes covered.","Remove foil and add grated cheddar cheese.","Bake 10 minutes more until cheese melts.","Cut and serve.\\r"]},{"id":124,"name":"Madeleines","cat":"Desserts","submittedBy":"Alice Kocik","description":"I've been making these pretty shell-like cookies for some of the family special occasions.  My granddaughter, Danielle and my daughter-in-law, Nancy love these cookies.  Makes 24 cookies.","time":"-","serves":"","ingredients":[["1/2 tsp.","Vanilla"],["1/2 tsp., finely shredded peel","Lemon"],["1 cup, sifted","Powdered Sugar"],["2/3 cup, all-purpose","Flour"],["1/4 tsp.","Baking Powder"],["1/2 cup, melted & cooled","Butter"]],"steps":["Grease and flour 24 - 3\" Madeleine molds.","Set aside.","In medium bowl, beat eggs, vanilla and lemon peel with electric mixer on high speed for about 5 minutes.","Gradually beat in powdered sugar for 5-7 minutes or until mixture is thick and satiny.","Sift together flour and baking powder.","Sift one quarter of flour mixture over egg mixture.","Gently fold in.","Fold in remaining flour by fourths.","Fold in butter.","Spoon into the prepared molds, filling 3/4 full.","Bake 375 degrees for 10-12 minutes or until edges are golden and tops spring back.","Cool in rack for 1 minute.","Loosen cookies with a knife.","Invert cookies onto rack and cool.","Sift additional powdered sugar over tops.","Store in freezer.\\r"]},{"id":125,"name":"Linguine with Chicken & Peanut Sauce","cat":"Pasta","submittedBy":"Kathy Langevin","description":"We love this dish because it's quick, unique and tasty.   It's definitely out of the norm.  Be brave--I think you'll enjoy it!","time":"-","serves":"","ingredients":[["1 medium, (sliced)","Onions"],["2 tsp.","Ginger"],["2 cloves, minced","Garlic"],["2 Tbsp.","Cooking Oil"],["1/2 cup","Peanut Butter"],["1/4 tsp.","Crushed Red Pepper"],["1 Tbsp.","Cornstarch"],["2 Tbsp.","Water"],["2 Tbsp.","Soy Sauce"],["1 can (14&1/2 oz.)","Chicken Broth"],["1 pound, bonelesspound, boneless","Chicken Breasts"],["1 poound, cooked and drained","Linguine Pasta"],["2 sliced","Green Onion"]],"steps":["Cut chicken into bite-size pieces.","Preheat large skillet.","Add oil.","Brown chicken on one side.","Add garlic, onion and ginger.","Cook until onion is tender and chicken is done.  \\r  \\r  Sauce: In a large bowl, mix broth, soy sauce, water, cornstarch and red pepper.","Blend in peanut butter.","Add sauce to chicken.","Cook and stir until thickened.","Serve atop hot cooked Linguine.","Sprinkle with sliced green onion.\\r  ;"]},{"id":126,"name":"Mexican Pita Pockets","cat":"Meat","submittedBy":"Kathy Langevin","description":"","time":"-","serves":"","ingredients":[["1 lb.","Ground Beef"],["1/2 cup, chopped","Onions"],["1 can (16 oz.)","Pork 'n Beans"],["1/2 cup","Salsa"],["to taste","Garlic Salt"],["to taste","Pepper"],["anykind","Pita Pockets"],["","Lettuce"],["","Tomato"],["","Cheddar Cheese"]],"steps":["Brown ground beef with onion.","Drain.","Season with garlic and pepper to taste.","Add beans and salsa.","Heat through.","Prepare like a taco, stuffing pita pocket with ground beef mixture, lettuce, tomato and cheese.","Enjoy!\\r"]},{"id":127,"name":"Apple Crisp","cat":"Desserts","submittedBy":"Katy Dellos","description":"Serve warm with ice cream or whipped cream.","time":"-","serves":"","ingredients":[["6 cups (3 apples), pared and sliced","Apples"],["1 Tbsp.","Lemon Juice"],["1/4 cup","Water"],["3/4 cup, firmly packed","Brown Sugar"],["3/4 cup","Flour"],["1 tsp.","Cinnamon"],["1/3 cup","Margarine"]],"steps":["Peel apples.","Cut in half, then quarters.","Cut out the core.","Slice into bite-size pieces.","Place apples in a buttered baking dish.","Mix water and lemon juice.","Sprinkle over apples in baking dish.","In mixing bowl, combine brown sugar, flour, and cinnamon.","Using a pastry blender, cut in margarine until mixture is crumbly.  \\r Sprinkle crumb mixture over apples in baking dish.","Refrigerate overnight.","Bake 375 degrees about 30 minutes or until apples are soft and \"pudding\" bubbly.","Topping will be crisp.\\r"]},{"id":128,"name":"Ratatouille with Polenta","cat":"Non-Meat","submittedBy":"Ann Delorey","description":"This is one of my favorite vegetarian main dishes.  I like to make a big pot of \\r\\n\tRatatouille on the weekend and have it for lunch throughout the week.  The \\r\\n\tpolenta should be made freshly at each serving, but the Ratatouille keeps in therefrigerator for a week  As the week progresses, the stew gets more savory!  \\r\\nServes 4-6.\\r\\n","time":"-","serves":"","ingredients":[["1 medium","Onions"],["2","Green Bell Pepper"],["2","Zucchini"],["1 small","Eggplant"],["4 cloves","Garlic"],["2","Tomatoes"],["1","Bay leaves"],["1 tsp.","Basil"],["1 tsp.","Majoram"],["1/2 tsp.","Oregano"],["1/2 tsp.","Rosemary"],["3 Tbsp.","Dry Red Wine"],["1/2 cup","Tomato Juice"],["1/4 cup","Olive oil"],["1&1/2 cup","Yellow Corn Meal"],["1 cup","Water"],["1 tsp.","Salt"],["1 cup, cold","Water"],["1 tsp.","Salt"],["4 cups, boiling","Water"],["1 cup","Cheddar Cheese"]],"steps":["Ratatouille: Heat oil.","Saut\u00e9 garlic, bay leaf, onion and salt slightly.","Add eggplant, wine, and tomato juice.","Add herbs.","Stir well and simmer covered for 15 minutes.","Add zucchini and peppers.","Simmer 10 minutes.","Add salt, pepper and tomatoes.","Mix and stew until all the vegetables are tender.","Serve over polenta.","Polenta: Combine corn meal, cold water, and salt.","Mix into a smooth paste.","Add corn meal paste to boiling water.","Stir with a whisk while it cooks to keep it smooth.","Once mixture thickens, lower heat and add cheese.","Stir until cheese melts.","Serve immediately with Ratatouille.\\r"]},{"id":129,"name":"Antipasto","cat":"Appetizers","submittedBy":"Diane Randesi","description":"Romaine, Escarole, Red, Butter or Iceberg Lettuce, Dandelion greens, Canned tuna, Black green, and/or Spanish-style olives, Strips of salami, Radishes, Marinaded artichoke hearts, marinaded mushrooms, tomato wedges, Roasted red peppers, Chopped green onion, 1/4\" chunks or strips of provolone cheese, and Freshly grated parmasean cheese.","time":"-","serves":"","ingredients":[],"steps":["Into a wide shallow bowl, place a bed of lettuce.","Atop the greens, group separately in an attractive arrangement some (or all) of the above toppings.","Sprinkle with freshly grated Parmesan cheese.","Dressing: 1 part red or wine vinegar and 2-3 parts olive or salad oil\u2014(about 1 tablespoon per one cup of lettuce.)  Salt & pepper to taste.","Drizzle over top of antipasto.","After everyone has complimented you on the pretty display, toss & serve.","In a wide shallow bowl, place a bed of lettuce."]},{"id":130,"name":"Maccheroni al Forno","cat":"Pasta","submittedBy":"Rose Greco","description":"In other words, Baked Macaroni.  Serves 4-6","time":"-","serves":"","ingredients":[["","Tomato Sauce"],["quickly browned, not overcooked","Meatballs"],["may substitute salami","Chopped Italian Ham"],["cut in small pieces","Mozzarella Cheese"],["","Romano Cheese"],["4-5 hard boiled, sliced","Eggs"]],"steps":["Cook macaroni (Rigatoni or Penne) in salted boiling water.","Cook until firm, not tender.","In a baking dish, layer:\\r \\r \t\ttomato sauce (4 oz.)\\r \t\thalf of the partially-cooked macaroni\\r \t\tprosciutto or salami (4 or 5 slices)\\r \t\tcheeses (4 oz.)\\r \t\thalf of the crumbled meatballs\\r \t\thalf of the crumbled hard-boiled eggs\\r \t\tRepeat with the remainder of the ingredients  \\r \\r Top with tomato sauce and Romano cheese.","Cover with foil.","Bake 325 degrees about 40-45 minutes.  (Rigatoni takes a little longer.)  Allow to cool slightly.","Serve with more hot sauce.\\r"]},{"id":131,"name":"Salmariglio","cat":"Miscellaneous","submittedBy":"Rose Greco","description":"In other words, Italian steak or fish dressing.","time":"-","serves":"","ingredients":[["1/2 cup","Water"],["1/2 cup","Olive oil"],["1 chopped or minced finely","Garlic"],["1/2 tsp.","Parsley"],["1 tsp.","Oregano"],["pinch","Salt"],["to taste_x000d_\nto taste","Lemon Juice"]],"steps":["Combine and mix all ingredients.","Serve as a dressing for steak.","As a dressing for fish, add lemon juice to taste."]},{"id":132,"name":"Carrot Cake","cat":"Desserts","submittedBy":"Rose Greco","description":"","time":"-","serves":"","ingredients":[["1 cup","Coconut"],["1 stick","Margarine"],["1 box","Powdered Sugar"],["1 8 oz. pkg.","Cream Cheese"],["1 cup","Coconut"],["1 cup","Walnuts"],["1 cup, crushed","Pineapple"],["1 cup, grated","Carrots"],["2 tsp.","Vanilla"],["2 tsp. (less, if desired)","Cinnamon"],["1/2 level tsp.","Salt"],["2&1/2 cups","Flour"],["1&1/2 cups","Sugar"],["2","Eggs"],["1&1/2 cup","Salad Oil"],["1 cup","Walnuts"]],"steps":["In a large bowl, mix oil, eggs and sugar.","Add remaining ingredients.","Bake in greased and floured cake pan, 350 degrees for 40-45 minutes or until done.","Frost with cream cheese icing.","Refrigerate\\r"]},{"id":133,"name":"Party Time Jello","cat":"Desserts","submittedBy":"Rose Greco","description":"","time":"-","serves":"","ingredients":[["1 8 oz., strawberry","Jell-O"],["2 cups, boiling","Water"],["1&1/2 cups, cold","Water"],["2 pints (may substitute fresh)","Frozen Strawberries"],["1 8 oz. pkg., softened","Cream Cheese"],["1/4 cup","Sugar"],["2 Tbsp.","Milk"],["1&1/2 cup, thawed","Cool Whip"],["2 cups, finely crushed","Pretzels"],["1/3 cup","Sugar"],["2/3 cup","Margarine"]],"steps":["Mix Jell-O mixture.","Refrigerate until slightly thickened.","Add strawberries.","Refrigerate until slightly thickened (egg-white consistency).","Mix pretzels with sugar and margarine.","Press firmly in baking pan.","Bake 10 minutes.","Cool.","Beat cream cheese mixture until smooth.","Spread cream cheese mixture over cooled crust.","Refrigerate.","Spoon Jell-O mixture over cream cheese layer.","If Jell-O is too thick, allow to stand out of refrigerator to soften slightly.","Refrigerate until firm.","May add more cool whip if desired.","Cut into squares.;"]},{"id":134,"name":"Pan Cookies","cat":"Desserts","submittedBy":"Rose Greco","description":"","time":"-","serves":"","ingredients":[["1 cup","Sugar"],["1 cup","Shortening"],["1 tsp.","Vanilla"],["5+ cups","Flour"],["1/2 tsp.","Salt"],["1 level tsp.","Baking Soda"],["2 tsp.","Baking Powder"],["1 cup","Milk"]],"steps":["Mix sugar, shortening, eggs, and vanilla.","Add salt, baking soda, baking powder, milk and flour, adding 1 cup of flour at a time.","Mix.","Dough will be sticky.","Freeze overnight (or at least for 5-6 hours).","Remove from freezer a few minutes before ready to use.","Cut in 4 sections.","Flour board generously.","Roll one section into a rectangular greased pan.","Dough will be very soft and sticky.  (Add flour to make rolling easier.)  Filling: Spread strawberry jelly (thickened with cornstarch or flour) on top of dough.","Roll out another quarter of the dough and layer over filling.","It is delicate and may break in process.","Just patch it with dough.","Continue for four layers.","When finished, poke the entire top layer with a fork.","Bake 350 degrees for 10-12 minutes.","Should be light and not browned.","Shake powdered sugar over top.","Cool.","Cut into diamond shapes."]},{"id":136,"name":"Maggie's Zucchini Patties","cat":"Non-Meat","submittedBy":"Rose Greco","description":"Great for a crowd.","time":"-","serves":"","ingredients":[["1 cup","Breadcrumbs"],["1 cup, grated","Romano Cheese"],["1/2 cup","Flour"],["2 medium-size, grated","Zucchini"],["to taste","Garlic Powder"],["1/4 tsp.","Pepper"],["","Baking Powder"],["enough to cover bottom of frying pan","Oil"]],"steps":["Combine breadcrumbs, cheese and flour.","Dough will  be hard or stiff.","Add zucchini, garlic powder, pepper and baking powder.","Mix.","Drop by spoonfuls into frying pan of hot oil.","Eat while hot."]},{"id":137,"name":"Polenta with Broccoli & Sausage","cat":"Meat","submittedBy":"Rose Greco","description":"Makes 4 servings.","time":"-","serves":"","ingredients":[["1 cup","Yellow Corn Meal"],["4 cups, total","Water"],["1 tsp.","Salt"],["2 Tbsp. (optional)","Olive oil"],["4 cups, (homemade or bought)","Tomato Sauce"]],"steps":["Boil broccoli in 2 cups salted water.","Remove broccoli and set aside.","Keep the same water boiling.","In a separate bowl, mix cornmeal with 1 cup of cold water.","When dissolved, add to the boiling water from the broccoli, stirring well and often.","Lower heat (has tendency to stick), and cook until thickened (about 15-20 minutes).","Add more water if needed.","Add oil.  (It should be the consistency of mashed potatoes.)  In a serving dish, layer tomato sauce, chopped cooked sausage, cooked cornmeal and grated cheese.","Layer a second time ending with tomato sauce and grated cheese.","Top with cooked broccoli.","Makes 4 servings.\\r \\r"]},{"id":138,"name":"Sausage & Pepper Sauce","cat":"Meat","submittedBy":"Rose Greco","description":"Serve with sliced toasted Italian Bread.  Good for parties where you have a crowd.  \"Dunking\"  bread into this sauce is great!","time":"-","serves":"","ingredients":[["1 lb.","Sausage"],["1 large can, chopped or pured","Tomatoes"],["2 cut into 1/2\\","Green Pepper"],["1 chopped","Onions"],["1 minced","Garlic"],["to taste","Oregano"],["to taste","Basil"],["if desired","Crushed Red Pepper Flakes"],["","Tomato Sauce"]],"steps":["In a frying pan, cook sausage until lightly browned.","Remove from heat and cut into slices.","Place pureed tomatoes in a saucepan.","Add sausage slices, pepper slices and seasonings to taste.","Cook sauce slowly on stove for 40-45 minutes.","Add more tomato sauce if desired."]},{"id":139,"name":"Shrimp with Angel Hair Pasta","cat":"Pasta","submittedBy":"Rose Greco","description":"","time":"-","serves":"","ingredients":[["1 lb. Medium sized, peeled","Shrimp"],["1 large can (may substitute pureed tomatoes)","Tomato Sauce"],["1/2 small","Onions"],["1 lb.","Angel Hair Pasta"]],"steps":["While you are boiling salted water to cook pasta, peel shrimp and save the skins.","Set shrimp aside.","Simmer the skins with 1&1/2 cup water for 10 minutes.","Strain the skins, save the water, and discard the skins.","To make sauce, sautee onion in oil.","Add tomato sauce or pureed tomatoes.","Cook for about 10-15 minutes.","Add the water from the shrimp skins to the sauce.","Add shrimp to sauce the last 3 or 4 minutes of cooking.  (Shrimp will harden and be rubbery if cooked too long.)  Cook pasta, strain.","Top with shrimp sauce."]},{"id":140,"name":"String Bean and Egg Dish","cat":"Non-Meat","submittedBy":"Rose Greco","description":"","time":"-","serves":"","ingredients":[["1 crushed","Garlic"],["1 can, crushed whole or puree","Tomatoes"],["pinch, (optional)","Basil"],["fresh or canned, cooked","String Beans"],["5-6","Eggs"],["pinch, to taste","Salt and Pepper"],["pinch, if desired","Crushed Red Pepper Flakes"]],"steps":["After breaking off each end of the string beans, steam them, and set aside.","Saut\u00e9 garlic.","Add tomatoes, basil, and crushed red pepper.","Simmer about 6 minutes.","Add cooked string beans.","Cook a few minutes with the sauce.","In a separate bowl, beat eggs, salt and pepper.","When beans are bubbling, add egg mixture to string bean sauce.","Stir until blended and cooked.  \\r \\r Mangia (pronounced mon-ga, meaning \u201ceat\u201d).\\r"]},{"id":142,"name":"Lentils (A Meal or Soup)","cat":"Soups","submittedBy":"Rose Greco","description":"Eat plain with cooked rice or small shell macaroni.  Also good with Roma's Italian Bread!","time":"-","serves":"","ingredients":[["2 cups","Lentils"],["1/2","Onions"],["2-3 sliced or shredded","Carrots"],["1-2 cloves, minced","Garlic"],["to taste","Oregano"]],"steps":["Place lentils in saucepan.  Cover lentils with water.  Bring to a boil.  Remove from heat.  Strain and rinse.  Discard water.  Place lentils in a pot.  Cover lentils with fresh water.  Add tomatoes, onion, carrots, garlic and oregano.  Cook  2\u00bd hours or until tender.  Add salt when almost done.  Ready to eat.","Option: You may puree into a soup, or eat as is.","Option: You may add chopped potato or lightly-browned sausage while cooking.  Option: You may cook lentils with a ham bone."]},{"id":143,"name":"Sweet Dough Cinnamon Rolls","cat":"Desserts","submittedBy":"Rose Greco","description":"","time":"-","serves":"","ingredients":[["2 cups, warm","Milk"],["1/2 cup","Sugar"],["1 tsp.","Salt"],["2 pkgs.","Dry Yeast"],["3","Eggs"],["1/2 cup","Shortening"],["7 cups","Flour"],["1 grated, if desired","Orange or Lemon Rind"],["3/4 cup","Sugar"],["2 tsp.(less if desired)","Cinnamon"],["chopped","Walnuts"],["","Powdered Sugar"],["","Maple Flavoring"],["","Butter"],["","Milk"]],"steps":["Dissolve yeast in warm water and sugar sprinkled over yeast.","Add remaining ingredients to yeast mixture, adding the flour in small amounts.","Mix into dough.","It should be soft and easy to handle.","Let raise for about 30 minutes.","Punch down and let raise once again (about 30 more minutes)  Make filling mixture.","Roll half of the dough on a floured board.","Spread softened butter on dough and use half of the filling mixture.","Roll up tightly (as in a jelly roll).","Repeat with the other half of the dough.","Cut the roll into 1&1/2\" slices.","Place on cookie sheet and let rise (about 30-35 minutes) again.","Bake 375 degrees for 25-30 minutes.","For frosting, mix  powdered sugar, maple flavoring, butter, and milk to a spreading consistency.","When cooled, frost and sprinkle with chopped walnuts."]},{"id":144,"name":"Pasta with Tuna Sauce","cat":"Pasta","submittedBy":"Angie Dellos","description":"","time":"-","serves":"","ingredients":[["1/4 cup","Olive oil"],["1/2 chopped","Green Pepper"],["1/2 chopped","Onion Flakes"],["2 cloves, sliced or mashed","Garlic"],["1 Tbsp.","Parsley"],["to tasteto taste","Salt and Pepper"],["1 small can","Tomato Paste"],["1 can (28 oz.), about 3 1/2 cups","Tomatoes"],["1/2 can, or more (drain oil)","Tuna"],["1 lb. (may substitute Linguine)","Spaghetti"]],"steps":["In a frying pan, saut\u00e9 oil, pepper, onion and garlic until limp or light brown.","Add parsley, salt and pepper.","Remove all but the oil and set aside.","To the oil, add tomato paste.","Cook about 5 minutes on medium.","Meanwhile, whirl the tomatoes in the food processor so that all the tomatoes are broken up.","Place in a saucepan and add the above ingredients to it.","Cook for about 1 hour or until thickened, stirring occasionally.  (You may add a little water if it gets too thick.)  When the sauce is done, drain the oil from a can of tuna and add to the sauce.","Cook another 5 minutes.","Serve over Spaghetti or Linguine.\\r"]},{"id":145,"name":"Artichokes","cat":"Non-Meat","submittedBy":"Angie Dellos","description":"","time":"-","serves":"","ingredients":[["3","Artichoke Hearts"],["2","Eggs"],["1 Tbsp., grated","Parmesan Cheese"],["1 Tbsp.","Breadcrumbs"],["2 crushed or finely chopped","Garlic"],["to taste","Salt and Pepper"],["to taste","Parsley"],["4 Tbsp.","Olive oil"],["2 cups","Water"]],"steps":["Cut off stems of the artichokes, close to the leaves.","Remove outside leaves and cut off the prickly tops with scissors.","Wash in cold water and drain.","Meanwhile, make a mixture of eggs, cheese, bread crumbs, garlic, salt, pepper and parsley.","Set aside.  (Filling will be very loose).","Place artichokes in a deep \\r saucepan.","Pry artichokes open, and pour mixture between leaves.","Drizzle olive oil on top.","Add 2 cups water.","Cover (use a tight fitting lid), and simmer for 45 minutes to 1 hour, or until the leaves pull away easily.\\r"]},{"id":146,"name":"Lupine","cat":"Miscellaneous","submittedBy":"Angie Dellos","description":"A Christmas tradition","time":"-","serves":"","ingredients":[["2 lbs.","Dried Lupine"],["","Water"],["","Salt"]],"steps":["Place lupine in a large pot (6 qt.).","Cover the lupine with water at least 4 inches above the lupine.","Bring to boil and cook on a low boil for about 45 minutes or until skin pops when you pinch them.  (Beans dowbe?","When cooked.)  Remove from fire and rinse in cold water.","Place lupine back in the pot and cover them with fresh water and add about a hand full of salt.","Change water every day, always keeping them covered with clear water.","Add a little salt every day.","It will take about 2 weeks for them to cure and be ready to eat!"]},{"id":147,"name":"Spaghetti al'Olio e Aglio","cat":"Pasta","submittedBy":"Angie Dellos","description":"Pronounced (ahlya-oolya) or \u201cSpaghetti with Oil and Garlic\u201d sauce.  Makes about 1 cup of sauce.  Easy, fast and good--a nice side dish when serving fish.","time":"-","serves":"","ingredients":[["1/2 cup","Olive oil"],["4 cloves","Garlic"],["1/2 cup","Water"],["1/8 tsp.","Parsley"],["1/2 lb.","Spaghetti"]],"steps":["In a 1-quart saucepan, heat olive oil and garlic.  (BE CAREFUL NOT TO BURN.)  While stirring, add water slowly.","Add chopped dried parsley and pepper.","Simmer about 10 minutes.","Serve over cooked Spaghetti."]},{"id":148,"name":"Basic Butter Cookies","cat":"Desserts","submittedBy":"Lillian Pisani","description":"I use this cookie recipe as a base for \u201cItalian Seed Cookies.\u201d  It is more buttery and very good!","time":"-","serves":"","ingredients":[["1 cup","Butter or Margarine"],["1 cup","Sugar"],["1","Eggs"],["1/2 tsp.","Cream of Tartar"],["1/2 tsp.","Baking Powder"],["2&1/2 cups","Flour"],["1 tsp. (may substitute any other flavoring)","Vanilla Flavoring"]],"steps":["Cream together the butter, sugar, egg and cream of tartar.","Add baking powder, flour and vanilla.","Mix well.","If too sticky, add a small amount of flour.","Cookie can be molded and decorated, as you like.","Cookie will be light in color.  \\r \\r *Option: To make cookies with jelly and coconut, shape into a small ball and flatten slightly with a fork.","When cookies are cool, put strawberry jam on top of one cookie and place another cookie atop the jam making a sandwich.","Roll in coconut.  \\r \\r *Option: For Italian seed cookies, roll dough into individual \"logs\" (about 2\" long).","Dip first in water, then in sesame seeds before baking.","Bake 350 degrees until brown.\\r"]},{"id":149,"name":"Candied Fruit Cake","cat":"Desserts","submittedBy":"Lillian Pisani","description":"I make this at Christmas time.  If you like fruit cake, this is delicious!","time":"-","serves":"","ingredients":[["3 pkgs. (8 oz.), or 1&1/2 lbs.","Dates"],["1 lb.","Candied Pineapple"],["1 lb., whole","Candied Cherries"],["2 cups","Flour"],["2 tsp.","Baking Powder"],["1/4 tsp.","Salt"],["4","Eggs"],["1 cup","Sugar"],["2 lbs.","Pecans"],["?","White Corn Syrup"]],"steps":["Use two 9x5x3\u201d loaf pans or two 9\" spring-form pans, or use one of each.","Grease pans well with butter or margarine and line bottoms with waxed paper, cut to fit.","Grease paper.","Set oven to 275 degrees.","In a large bowl, cut dates and pineapple.","Add whole candied cherries.","Mix together flour, baking powder and salt.","Sift onto fruit.","Mix fruits and dry ingredients well with fingers, separating pieces of fruit so that all are well coated with dry ingredients.","With an electric mixer or rotary beater, beat eggs until frothy.","Gradually beat in sugar.","Add to fruit mixture.","Mix well with large spoon.","Add pecans.","Mix with hands until nuts are evenly distributed and coated with batter.","Pack into baking pans, pressing down with spoon.","If necessary, rearrange pieces to fill any empty spaces.","Decorate tops with whole candied cherry and pecans reserved from mixture.","Bake in spring-form pans about 1\u00bc hrs. (loaf pans 1\u00bd hours).  (Tops of cakes should look dry, but will not be brown.)  When cakes are done, remove from oven and place on cake racks.","Let stand 5 minutes.","Turn out on racks and carefully peel off paper.","Turn top-side up.","Brush with corn syrup.","Cool.","Wrap loosely in foil and store airtight in a cool place.\\r"]},{"id":150,"name":"Zapoli","cat":"Miscellaneous","submittedBy":"Lillian Pisani","description":"meaning (pizza fritto) or \"fried dough\"","time":"-","serves":"","ingredients":[["2 pkgs.","Yeast"],["1 qt., warm","Water"],["8-8&1/2 cups","Flour"],["pinch","Salt"]],"steps":["Mix ingredients.","Cover dough and let it raise.","Knead and raise again.","Break dough off into \"little breads\" about 3\" long and an inch wide.","Drop in hot oil to cook.","Remove.","Roll in granulated sugar, if you wish."]},{"id":151,"name":"Chocolate Cake","cat":"Desserts","submittedBy":"Angie Dellos","description":"This recipe was requested by my niece, Gloria Greco.  I made this cake once a week for years when my children were growing up.  Maybe that\u2019s why, to this day, they all have chocolate cravings!","time":"-","serves":"","ingredients":[["1/4 lb.","Margarine"],["1 cup","Water"],["4 Tbsp.","Cocoa"],["2","Eggs"],["2","Sugar"],["1&1/2 tsp.","Baking Soda"],["2 cups","Flour"],["1/2 cup, sour","Milk"],["1 tsp.","Vanilla"]],"steps":["Melt, then cool the margarine, water and cocoa.","In a mixing bowl, combine eggs, sugar, baking soda, flour, sour milk and vanilla.","Mix.","Pour into greased 9x13\" baking dish and bake 350 degrees for 40 minutes.\\r \\r *To make sour milk, add: \t1 Tbsp.","Vinegar to regular milk, or\\r \t\t\t\t1 Tbsp.","Lemon juice, or\\r \t\t\t\t1-and one quarter tsp.","Cream of tartar\\r \\r Frosting:  Mixture of powdered sugar, cocoa and milk to desired consistency.\\r"]},{"id":152,"name":"Calginetti (Stuffed Fritters)","cat":"Desserts","submittedBy":"Angie Dellos","description":"Pronounced (cowl\u2019-gin-eat).  This is a deep-fried Easter cookie.  It looks like a ravioli.","time":"-","serves":"","ingredients":[["1 can (chick peas)","checi"],["pinch","Salt"],["1/2 cup, chopped","Walnuts"],["1 cup, soaked and cut fine","Raisins"],["1 Rind","Orange Juice"],["1/2 cup","Honey"],["6","Eggs"],["1/2 cup","Sugar"],["1/2 cup (less 2 Tbsp.","Oil"],["4-4&1/2 cups","Flour"],["to deep fry","Oil"],["to roll cookies","Powdered Sugar"]],"steps":["Remove skins from chickpeas.","Wash chickpeas in clear water.","Mash and add salt, chopped nuts, raisins, orange rind and honey.","Let stand overnight.  \\r \\r Crust: Mix eggs, sugar, oil, baking powder and flour.","Roll dough and place 1 heaping tablespoon of filling, an inch apart, on the dough.","Fold dough over, cut around the filling with a pastry wheel (as in making a ravioli), press the open edges down with a fork.","Deep-fry in oil until golden brown.","Sprinkle with powdered sugar.\\r"]},{"id":153,"name":"Taco Salad","cat":"Salads","submittedBy":"Yvonne (Roma) DelVecchio","description":"","time":"-","serves":"","ingredients":[["1 lb.","Ground Beef"],["1","Onions"],["1","Green Pepper"],["3","Tomatoes"],["1 11 oz. bag","Dorito Cheese Chips"],["1 head, Romaine","Lettuce"],["1 8 oz. bottle","Kraft Catalina French Dressing"],["(optional)","Red Kidney Beans"],["grated (optional)","Cheddar Cheese"]],"steps":["In a frying pan, brown ground beef.","Let cool and drain oil.","Chop onion and pepper.","Dice tomatoes.","Break lettuce into pieces.","Crush chips in a bag.","In a serving bowl, mix together onion, peppers, tomatoes, and lettuce.","When ready to serve, add all ingredients together with the French dressing.  (Kidney beans and shredded cheddar cheese may be added, if desired)."]},{"id":154,"name":"No Fail Microwave Fudge","cat":"Desserts","submittedBy":"Yvonne (Roma) DelVecchio","description":"","time":"-","serves":"","ingredients":[["1/2 cup","Cocoa"],["1 pound","Powdered Sugar"],["1/4 cup","Milk"],["1/4 tsp.","Salt"],["1 tsp.","Vanilla"],["1/2 cup","Butter or Margarine"],["1 cup, chopped (optional)","Walnuts"]],"steps":["Place all ingredients in a medium-size bowl.","Microwave one minute on high temperature.","Stir.","Microwave one more minute on high.","Stir in nuts until smooth.","Pour into 9x9\" pan lined with waxed paper.","Chill.","Cut."]},{"id":155,"name":"Cherry Cake","cat":"Desserts","submittedBy":"Amy Roma","description":"","time":"-","serves":"","ingredients":[["1 cup","Sugar"],["1 cup","Shortening"],["2","Eggs"],["1 cup'","Sour Cream"],["2&1/2 cups","Flour"],["1 tsp.","Baking Soda"],["1 tsp.","Baking Powder"],["1 tsp.","Vanilla"],["2 cans, cherry","Pie Filling"]],"steps":["Mix sugar, shortening, vanilla and eggs.","Add dry ingredients, alternating with sour cream.","Set aside 1\u00bd cups of the batter.","Spread remaining batter in bottom of a greased pan.","Hint: Use a broiler pan.","Spread 2 cans of cherry pie filling over batter.","Drop the remaining batter by spoonfuls to the top.","Bake 350 degrees for 30 minutes."]},{"id":156,"name":"Reese Bars","cat":"Desserts","submittedBy":"Amy Roma","description":"","time":"-","serves":"","ingredients":[["1&1/2 cups","Peanut Butter"],["3/4 cups, melted","Butter"],["3/4 cups","Brown Sugar"],["3/4 Tbsp.","Vanilla"],["1 lb.","Powdered Sugar"],["1 cup","Chocolate-chips"],["1/2 cup","Butter"]],"steps":["Mix peanut butter, butter, brown sugar, vanilla and powdered sugar together.","Melt chocolate chips with buttter.","Pour over the peanut mixture.","Chill.","Cut into bars.","Serve."]},{"id":157,"name":"Potato Salad","cat":"Non-Meat","submittedBy":"Connie Roma","description":"","time":"-","serves":"","ingredients":[["5 lb. Bag","Potatoes"],["1 doz.","Eggs"],["1 cup (Hellmann","Mayonnaise"],["2 cups","Kraft Miracle Salad Dressing"]],"steps":["Boil potatoes in salted water.","Hard-boil the eggs and cool.","Mix together diced potatoes and diced eggs.","Add mayonnaise and salad dressing.","Mix all together.","If too dry, add more mayonnaise or salad dressing.","If needed, add salt."]},{"id":158,"name":"Meat Loaf","cat":"Meat","submittedBy":"Connie Roma","description":"","time":"-","serves":"","ingredients":[["1 lb.","Ground Beef"],["1","Eggs"],["1/8 cup, chopped","Onion Flakes"],["1 cup, (Roma","Breadcrumbs"],["to taste","Salt and Pepper"],["1 can, DelMonte","Stewed Tomatoes"]],"steps":["Mix together ground beef, egg, onion, bread crumbs, salt, pepper and juice from stewed tomatoes.","Place in a shallow baking dish.","Place remaining stewed tomatoes on top of this mixture.","Bake 350 degrees for 1 hour. \\r"]},{"id":159,"name":"Yum Yum Cake","cat":"Desserts","submittedBy":"Cindy Roma","description":"","time":"-","serves":"","ingredients":[["1 can","Crushed Pineapple"],["1 box, yellow","Cake Mix"],["2 packages, instant","Vanilla Pudding"],["1 8 oz., room temperature","Cream Cheese"],["2 cups","Milk"],["to cover top of cake","Cool Whip"]],"steps":["Drain pineapple well and set aside.","Bake according to directions on cake mix.","Set aside.","Beat vanilla pudding, cream cheese and milk until smooth.","Spread over top of cooled cake.","Sprinkle crushed pineapple on top of pudding.","Top with Cool Whip."]},{"id":160,"name":"Broccoli Casserole","cat":"Non-Meat","submittedBy":"Cindy Roma","description":"","time":"-","serves":"","ingredients":[["1 cup","Mayonnaise"],["1 cup, sharp","Cheddar Cheese"],["2 well beaten","Eggs"],["1 can","Mushrooms"],["1 medium","Onions"],["1 bag, cooked","Broccoli"]],"steps":["Mix all ingredients together.","Top with Roma's Bread Crumbs.","Bake\\r 350 degrees for 25 minutes.\\r"]},{"id":161,"name":"Italian Taralle","cat":"Desserts","submittedBy":"Angie Dellos","description":"A holiday cookie in the shape of a horseshoe.","time":"-","serves":"","ingredients":[["6","Eggs"],["1/2 cup (may substitute melted Crisco)","Vegetable Oil"],["1/2 cup","Sugar"],["pinch","Salt"],["1 tsp.","Anise Flavoring"],["enough to make a medium dough","Flour"],["(may substitute applesauce)","Jam"],["","Raisins"],["chopped","Walnuts"],["(if needed)","Breadcrumbs"],["as desired","Powdered Sugar"]],"steps":["Mix dough ingredients.","Roll out into a thin rectangle.","Place 1 tablespoon onto dough approx. 1\" apart.","Fold dough over and cut with a cookie cutter in the shape of a horseshoe.","Close edges tight by pressing with a fork along the fold.","Filling:  Mix jam, applesauce, raisins, nuts, chocolate chips.  (If filling is too soft, add breadcrumbs to thicken.)  Bake at 350 degrees until golden brown."]},{"id":162,"name":"Aunt Lorraine's Italian BBQ Ribs","cat":"Meat","submittedBy":"Bob Coughlin","description":"These ribs have a wonderful flavor and literally fall off the bone!  Best served with French fries, baked beans, a salad and a generous supply of lime-green \"Eagle Soda\" from Sammy Rossi's.","time":"-","serves":"","ingredients":[["6-8 racks (4 more if Danny Schofield is attending)","Pork Baby Back Ribs"],["Two parts oil to","Oil"],["one part vinegar","Red Wine Vinegar"],["","Lemon Juice"],["","Salt and Pepper"],["","Garlic"],["","Parsley"],["","Basil"],["(may substitute another type)","Bulls-Eye Barbeque Sauce"]],"steps":["Instructions:\\r Prepare \u201cmod-de-nod\u201d: Brush each side of rack with marinade until completely covered.","Place on a shallow cooking pan (i.e., cookie sheet).","Cook for 30 minutes at 300 degrees, turning ribs over after 15 minutes.","After a good portion of the fat has cooked off, removed ribs from oven.","Brush ribs with barbecue sauce, and place on gas grill for approximately 5 minutes each side.","Remove and place all ribs in a tin-foil \"enclosure\" (completely sealed).","Place tin foil basket on grill with top down (on low heat), or bake in oven \\r 200-250 degrees for 10 minutes to allow ribs to \"steam\".\\r"]},{"id":163,"name":"Grandma Smith's New England Fish Chowder","cat":"Soups","submittedBy":"Coleen (Smith) Coughlin","description":"This recipe came from my grandmother Smith who got it from her mother, and it has been handed down to four generations of my family in York, Maine.","time":"-","serves":"","ingredients":[["1 lb.","Haddock"],["2-3 medium-size","Potatoes"],["1","Onions"],["3/4 stick","Butter"],["2 cans","Evaporated Milk"]],"steps":["In a 4-6 quart saucepan, melt butter and saut\u00e9 a few rounds of onion for 3 minutes.  Chop potatoes in bite-size chunks and add to pan.  Add water to just cover the potatoes.  Cook for 5 minutes on medium heat.  Add fresh haddock, salt and pepper to taste.  Cook until haddock becomes flaky (about 10 -15 minutes).  Removed from heat.  Add 2 cans evaporated milk.  Once the chowder is cool, remove from pan and leave in refrigerator overnight for","best flavor.","Low-fat option: (This is the way I cooked it at my daughter Olivia's baptism, and Bob's family loved it.)  Substitute 1 can of evaporated milk with evaporated skim milk.  After the chowder has set for one day in the refrigerator, take the hardened butter off the top of the chowder and discard."]},{"id":164,"name":"Taco Dip","cat":"Appetizers","submittedBy":"Sue Shea","description":"Everyone asks for this at parties.  It's easy and good!  Serve hot with tortilla chips.","time":"-","serves":"","ingredients":[["1 (8 oz.) pkg., softened","Cream Cheese"],["1 can, Hormel with no beans (may substitute 1 can refried beans)","Chili"],["1 jar, as hot as desired","Salsa"],["1 large package, shredded","Cheddar Cheese"]],"steps":["In a pie pan, layer ingredients in the order listed above.","Bake 235 degrees for 30 minutes."]},{"id":165,"name":"Broccoli and Rice","cat":"Non-Meat","submittedBy":"Karen Bennett","description":"Double or triple recipe for family gatherings.","time":"-","serves":"","ingredients":[["2 cups","Rice"],["1 (10 oz.), frozen","Broccoli"],["1 can (may substitute celery soup)","Cream of Chicken Soup"],["1 (8 oz.) pkg., Velvetta","Cheese"]],"steps":["Prepare rice.","Set aside.","Cook broccoli enough to defrost.","Strain and set aside.","In a large pan, melt margarine and cheese.","Add cream soup, salt and pepper.","Mix cheese, rice and broccoli together.","Place in a casserole dish.  \\r Bake 350 degrees for 30 minutes or until brown on top.\\r"]},{"id":166,"name":"Cut-out Sugar Cookies","cat":"Desserts","submittedBy":"Karen Bennett","description":"I make these in different shapes all year rouond.  I also make them for family weddings, showers, etc.","time":"-","serves":"","ingredients":[["1&1/2 cups","Sugar"],["2 sticks","Margarine"],["1","Eggs"],["1/2 tsp.","Salt"],["1/2 tsp.","Baking Soda"],["1 tsp.","Baking Powder"],["1 tsp.","Vanilla"],["1/2 cup","Sour Cream"],["3 cups (maybe more)","Flour"],["3-4 Tbsp.","Butter"],["as needed","Powdered Sugar"],["as needed","Milk"]],"steps":["Combine and mix all ingredients (except sour cream and flour).","Add sour cream to mixture.","Add flour in small amounts until dough can be formed into a ball.","Refrigerate for 1 hour.","Using a small amount at a time, roll out the dough and cut out the desired shapes.","Bake 350 degrees for 5-8 minutes.  (Temperature may vary, so make sure they don't get too brown.)  Cool on rack.","Decorate with Frosting: Melt butter.","Add powdered sugar slowly to milk making sure frosting isn't too loose.","Add melted butter.","Add more sugar and milk, depending on how much you need, until frosting is creamy.","Spread with a knife.","Let dry for a few hours.","Food coloring may be added to frosting for variety.\\r"]},{"id":167,"name":"Bruschetta","cat":"Appetizers","submittedBy":"Karen Randesi","description":"I took a class in Florence, Italy called \"Foods of the Region\", and learned to make many good Italian dishes.  But my roommates and I resorted to this appetizer VERY often while we were deciding what to make for dinner.  (Sometimes,  we didn't get past this appetizer!)","time":"-","serves":"","ingredients":[["to taste","Salt"],["freshly ground","Pepper"],["1 clove","Garlic"],["8 Tbsp.","Olive oil"],["4 slices Italian","Stale Bread"]],"steps":["While toasting the bread, fry garlic.","Rub the garlic on the toasted bread and sprinkle with salt, pepper and oil.","Add slice of fresh tomato, a sun-dried tomato, or a piece of Mozzarella cheese to top.","Serve warm."]},{"id":168,"name":"Peanut Butter Popcorn Balls","cat":"Desserts","submittedBy":"Keith Shea","description":"","time":"-","serves":"","ingredients":[["1 cup","Peanut Butter"],["1 cup","Sugar"],["1 tsp.","Vanilla"],["1/2 cup","Light Corn Syrup"],["1/2 cup","Honey"],["6 quarts","Popped popcorn"]],"steps":["Combine ingredients and cook to a soft ball (235 degrees).","Pour over popcorn.","Form into balls!"]},{"id":169,"name":"Taco Salad","cat":"Salads","submittedBy":"Pat Shea","description":"","time":"-","serves":"","ingredients":[["1 bag","Salad Mix"],["1 lb.","Ground Beef"],["1 pkg.","Taco Seasoning Mix"]],"steps":["Brown meat and add taco seasoning as directed on package.","Cool.","Crush several handfuls of Tortilla chips into the salad mix.","Add meat and dressing.","Add extras, such as tomatoes, black olives, peppers, shredded cheddar cheese, etc., as desired."]},{"id":170,"name":"Italian Biscuit","cat":"Desserts","submittedBy":"Marie Shea","description":"This is my mother's (Anna Roma) recipe.","time":"-","serves":"","ingredients":[["1 tsp.","Vanilla"],["1 tsp.","Almond Extract"],["3/4 cup","Sugar"],["3 cups","Flour"],["2 tsp.","Baking Powder"],["1/2 cup, chopped","Walnuts"]],"steps":["Beat first four ingredients.","Combine remainder of ingredients to make dough.","Make into 3 rolls.","Place on greased cookie sheet.","Bake 350 degrees for 20-25 minutes.","Remove from oven.","Slice each roll (about \u00bd\" wide).","Place on a cookie sheet and re-bake 350-375 degrees, (depending on your oven), until brown.\\r  ;"]},{"id":171,"name":"Dark Chocolate Cake","cat":"Desserts","submittedBy":"Marie Shea","description":"","time":"-","serves":"","ingredients":[["2&1/4","Sugar"],["2/3 cup","Crisco"],["2 Tbsp.","Margarine"],["3","Eggs"],["2 tsp.","Vanilla"],["3/4 cup","Cocoa"],["2&1/2 cups","Flour"],["1/2 tsp.","Salt"],["2 tsp.","Baking Powder"]],"steps":["Cream together sugar, Crisco, and margarine.","Add eggs and vanilla.","Set aside.","Sift cocoa, flour, salt and baking powder.","Set aside.","Bring 2 cups of water to a boil.","Remove from heat.","Add baking soda.","Add water mixture alternately with flour mixture to the creamed mixture.","Place into a greased and floured 9x13\" pan.","Bake 300 degrees for 45-60 minutes.  (In my oven, this cake is always done in 45 minutes.)"]},{"id":172,"name":"Brunch Casserole","cat":"Meat","submittedBy":"Terry Coughlin Sr.","description":"In the words of his daughter, Anne: This recipe carries with it a very \u201cwarm\u201d memory.  My dad and the Coughlin men (his son, brother, nephew, and brother-in-law) enjoyed this for brunch the morning they left to meet up with the rest of the Coughlin men in Boston, for a bonding trip to Ireland!  A nice, warm send-off.","time":"-","serves":"","ingredients":[["1 loaf","Bread"],["2 cups, shredded","Cheddar Cheese"],["1&1/2 lb., cooked, cubed or crumbled","Sausage"],["1 can","Cream of Chicken Soup"],["1/2 cup","Milk"],["6 beaten","Eggs"]],"steps":["Remove crust from bread and cube.","Layer bottom of pan with bread cubes.","Layer cheese and sausage.","Mix soup and milk with beaten eggs.","Pour over casserole.","Refrigerate overnight.","Bake 350 degrees for 1 hour."]},{"id":173,"name":"Barbecued London Broil","cat":"Meat","submittedBy":"Sue Greco","description":"","time":"-","serves":"","ingredients":[["3-4 lbs. Lbs.","London Broil"],["1&1/2 cups (may substitute soybean oil)","Olive oil"],["3/4 cup, low sodium","Soy Sauce"],["1/4 cup","Worcestershire Sauce"],["1/2 cup","White Vinegar"],["1/2 cup","Lemon Juice"],["1&1/4 tsp.","Salt"],["1 tsp.","Pepper"],["2 tsp.","Garlic Powder"]],"steps":["Marinate steak overnight in refrigerator.","Pierce steak with large fork to allow marinade to seep in.","Turn meat in marinade at least once.  (More often is better.)  Barbecue London Broil until center is cooked to medium well.","Brush steak with marinade while it is being barbecued.  (Discard remaining marinade.)  Slice and serve.\\r"]},{"id":174,"name":"Spinach Dip","cat":"Appetizers","submittedBy":"Sue Greco","description":"","time":"-","serves":"","ingredients":[["1 10 oz. pkg., frozen, chopped, thawed, and squeezed","Spinach"],["1 cup","Mayonnaise"],["1/2 cup, thinly sliced","Scallions"],["1/2 cup, fresh,choppedcup, fresh, chopped","Parsley"],["1/4 cup, plain","Yogurt"],["1/4 tsp.","Salt"],["1/8 tsp.","Pepper"],["1 lb. Round rye or Shepherder","Bread"]],"steps":["Mix all ingredients (except bread) and chill in refrigerator.","Carefully slice off top of bread round, and hollow out the center.","Use the hollowed-out pieces for dipping.","Pour chilled dip into hollow of bread round.","Place cut-up bread on the serving plate around the bread round.","Replace top of bread round until ready to serve or when transporting.","When ready to serve, cut up an extra loaf of bread into pieces for dipping.","Store in refrigerator."]},{"id":175,"name":"Lemon Twists","cat":"Desserts","submittedBy":"Marie Shea","description":"","time":"-","serves":"","ingredients":[["1&1/3 sticks","Margarine"],["1&1/2 cups","Sugar"],["1&1/2 tsp., peel","Lemon"],["2","Eggs"],["2","Egg Yolks"],["4 cups","Flour"],["1/2 tsp.","Salt"]],"steps":["Cream margarine and sugar.","Add eggs and beat.","Add flour mixture and mix.","Refrigerate dough to make it easier to handle.","Break off a piece (about the size of an egg) of dough with your hands.","Roll into 6\u201d in length.","Place the ends together and twist.","Brush cookies with egg white that has been slightly beaten.","Bake 350 degrees for 10-12 minutes.\\r"]},{"id":176,"name":"Applesauce Pumpkin Bread","cat":"Desserts","submittedBy":"Marie Shea","description":"","time":"-","serves":"","ingredients":[["2/3 cup","Shortening"],["2&2/3 cup","Sugar"],["4 Applesauce","Eggs"],["1 cup","Applesauce"],["1 cup","Pumpkin"],["3&1/3 cups","Flour"],["2 tsp.","Baking Soda"],["1/2 tsp.","Baking Powder"],["1&1/2 tsp.","Salt"],["1 tsp.","Cinnamon"],["1/2 tsp.","Mace"],["1/2 tsp.","Nutmeg"],["2/3 cup","Apple Juice"],["1 cup, chopped","Walnuts"]],"steps":["Cream Crisco and sugar together.","Add eggs one at a time, beating after each one.","Stir in applesauce and pumpkin.","Add dry ingredients alternately with apple juice.","Stir in walnuts.","Grease two 9x15x3\" loaf pans.","Bake 350 degrees for 1 hour.\\r"]},{"id":177,"name":"Pasta Salad","cat":"Salads","submittedBy":"Mary Pisani","description":"","time":"-","serves":"","ingredients":[["1 lb., Penne","Pasta"],["2 diceddiced","Tomatoes"],["1 can, black small","Olives"],["1/2 cup, grated Romano","Cheese"],["1 diced","Green Pepper"],["1 pkg.","Good Seasons Salad Mix"]],"steps":["Add all ingredients together and mix with dressing.","Serve."]},{"id":178,"name":"Zucchini Casserole","cat":"Non-Meat","submittedBy":"Mary Pisani","description":"","time":"-","serves":"","ingredients":[],"steps":["Cook zucchini and onion in very little water.","Mix sour cream and soup together and add to mixture.","Melt butter, and add to stuffing.","Layer half the zucchini mixture in bottom of 2-quart casserole.","Layer half the stuffing mixture.","Repeat.","Bake 350 degrees for 25 minutes."]},{"id":179,"name":"Amaretto Mousse Cheesecake","cat":"Desserts","submittedBy":"Annette Shea","description":"In the words of Annette's husband, Mike: Annette likes this recipe for two reasons.  It's a \"no-bake\u201d recipe (ideal for the summertime when you don't want the oven on), and everybody loves it (especially me!).  I think there's a third reason\u2014she's Italian through and through, and Italians just can't resist Amaretto!","time":"-","serves":"","ingredients":[["1 tsp.","Lemon Juice"],["3 8-oz. pkgs., softened","Cream Cheese"],["1/3 cup","Amaretto Liqueur"],["1 tsp.","Vanilla"],["3/4 cup, whipped","Heavy Cream"],["2 cups","Graham Cracker Crumbs"],["1/2 cup, melted","Margarine"],["1 envelope","Knox Unflavored Gelatin"],["1/2 cup, cold","Water"],["1&1/4 cups","Sugar"],["1 5-oz can","Evaporated Milk"]],"steps":["Combine the graham cracker crumbs with the margarine, press into the bottom of a spring-form pan, and chill.","In a small saucepan, sprinkle gelatin over the cold water and let stand for 1 minute.","Stir over low heat until dissolved (about 3 minutes).","Set aside.","In the large bowl of your electric mixer, beat cream cheese with sugar, until fluffy (about 2 minutes).","Gradually add milk and lemon juice.","Beat at medium-high speed until mixture is very fluffy (about 2 minutes).","Gradually beat in gelatin mixture, Amaretto, and vanilla until blended.","Fold in whipped cream.","Pour into crust, and chill 8 hours.","You may garnish with trickles of chocolate sauce and berries if you wish.","Enjoy\u2014now that\u2019s Italian!"]},{"id":180,"name":"St. Anthony's Field Days Barbecue Chicken","cat":"Meat","submittedBy":"Mike Shea","description":"I'm sure the smell and taste of this recipe will remind you of bygone days spent at one of the year\u2019s biggest community events on the North Side of Endicott \u2014the St. Anthony's Field Days.  I found this recipe published many years ago by the \"Sun Bulletin\" (when it was a tabloid that had not yet been devoured by the larger, sinister \"Evening Press\").  The recipe, as published, was for making gallons of the marinade for use at the field days.  This provided me with the first and only opportunity in my life to put conversion tables and mathematics to use for a noble purpose\u2013I really did like that chicken (sorry Bob Coughlin, but I had Aunt MeeMee\u2019s chicken every week, and it just didn\u2019t cut it for me).","time":"-","serves":"","ingredients":[["1","Egg Whites"],["2/3' cup","Oil"],["2/3 cup","Vinegar"],["1 tsp.","Salt"],["2 tsp.","Poultry Seasoning"],["1 tsp.","Garlic Powder"],["1/2 tsp.","Pepper"],["5-6 or 15-20pieces","Chicken Halves"]],"steps":["Break egg into a large bowl.","Whip it thoroughly.","Add oil and whip thoroughly again.","Add the vinegar and whip thoroughly again (yawn\u2026).","Add dry ingredients and whip again (zzzz\u2026.).","Marinate the chicken in this mixture (covered in the \"fridge\") for at least 1 hour (overnight is better).","Grill the chicken as you normally would grill chicken (about 20-30 min. for pieces; about 60 min. for halves), with this caveat: The marinade is very prone to causing flare-ups, so watch the chicken carefully.","Experiment with your grill so that the meat is above the coals enough that flare-ups are prevented while still allowing the chicken to cook in a reasonable amt. of time.","The chicken should be turned (with tongs, never a fork!) every 5-10 min. until done (baste with leftover marinade if you are not having flare-up troubles).","Remove chicken.","Close your eyes.","Take a bite, but be careful \u2013 when you open them back up, you may find yourself standing in the parking lot in back of St.","Anthony of Padua Church."]},{"id":181,"name":"City Chicken","cat":"Meat","submittedBy":"Jackie Weston","description":"This is a \"season-as-you-like\" recipe with which you can\u2019t go wrong.  The amount of meat you wish to prepare and the size of the bowl in which you marinate it, will determine the amount of the other ingredients you'll need.\\r\\n","time":"-","serves":"","ingredients":[["","Chicken"],["","Veal"],["","Pork 'n Beans"],["","Vinegar"],["","Salt and Pepper"],["","Parsley"],["","Eggs"],["","Breadcrumbs"],["","Vegetable Oil"]],"steps":["Cut bite-sized pieces of chicken, veal and pork.","Place into a bowl.","Pour equal parts of lemon juice and vinegar to cover the meat.","Season to taste with salt, pepper, garlic powder and parsley.","Mix thoroughly.","Cover and marinate for at least 2 hours, or overnight.","Place meat on wooden sticks (about 4-5 per stick).","Dip into beaten egg seasoned to taste with salt and pepper.","Dip into bread crumbs to coat.","Fry in oil.","Remove when browned, and place into a baking dish.","Bake 350 degrees 45-60 minutes.","These can be served as an appetizer or as a main dish."]},{"id":194,"name":"Mexican Dip","cat":"Appetizers","submittedBy":"Rose Greco","description":"","time":"","serves":"","ingredients":[["1 8 oz. pkg. softened","Cream Cheese"],["1 cup","Sour Cream"],["1 14 oz. can","Diced Green Chilies"],["1/4 tsp.","Garlic Salt"],["1/4 cup, cooked, crumbled (may substitute bacon bits)","Bacon"]],"steps":["In a bowl, blend together cream cheese and sour cream until smooth.","Fold in remaining ingredients.","Chill.","Serve with chips."]},{"id":195,"name":"Super Salsa","cat":"Appetizers","submittedBy":"Angie Dellos","description":"Award-winning.  Will keep in refrigerator for several days.","time":"","serves":"","ingredients":[["1/2 juice only","Lemon"],["3 large Roma (Italian plum) or 1 large beefsteak tomato","Tomatoes"],["1/8 medium size","Onions"],["1-3 slices (depending on how hot & spicy you like salsa","Jalapeno Pepper"],["1-2 cloves, fresh","Garlic"],["1/8 (optional)","Green Bell Pepper"],["1 tsp. (or to taste)","Salt"],["3-4 fresh sprigs (may substitute parsley)","Cilantro (Mexican Parsley)"]],"steps":["Chop garlic and jalapeno chili pepper in food processor.","Add onion and pulsate in food processor.","Add the remainder of ingredients to processor.","Use pulsating motion to break up big pieces of tomato.","Place in bowl.","Serve with tortilla chips."]},{"id":196,"name":"Angel Hair Pasta with Shrimp","cat":"Miscellaneous","submittedBy":"Rose Greco","description":"","time":"","serves":"","ingredients":[["1 lb. medium size, peeled","Shrimp"],["1 1/2 cups","Water"],["1/2 small","Onions"],["2 Tbls.","Oil"],["1 (28 oz.) can (may substitute pureed tomatoes or homemade sauce)","Tomato"],["1 lb.","Angel Hair Pasta"]],"steps":["While you are boiling salted water to cook pasta, peel shrimp and save the skins.","Set shrimp aside.","Simmer the skins in 1/2 cup of water for 10 minutes.","Strain.","Set water aside and discard the skins.\\r  \\r  To make sauce:  Saute onion in oil.","Add tomato.","Cook for about ten to fifteen minutes.","Add the water from the shrimp skins to the sauce.","Add shrimp to sauce the last three or four  minutes of cooking.  (Shrimp will harden and turn rubbery if cooked too long.)  Cook pasta.","Strain.","Top with shrimp sauce.;"]},{"id":198,"name":"Pasta Sauce with Meatballs and Sausage","cat":"Pasta","submittedBy":"Diane Randesi","description":"When my children were little, they wouldn\u2019t eat anything that had unidentifiable little \u201cthings\u201d in it.  This is when I discovered that I could still make sauce with onions, peppers and tomatoes as long as I \u201cliquefied\u201d or pureed it, as in this recipe.  That way, they got the flavor and nutrition of vegetables without the thought of actually eating such things!  I did the same with soup (p. 15).  After I cooked the vegetables in the soup, I liquefied them in the food processor (instead of chopping them) and added the liquid back into the soup.  (My kids are all grown, but I still do it!)  This red sauce is basic and can be made without meat.  Best served the day after.","time":"","serves":"","ingredients":[["1 lb.","Ground Chuck"],["2","Eggs"],["3 Tbsp.","Parsley"],["3 Tbsp.","Parmesan Cheese"],["to taste","Salt and Pepper"],["1 slice (wet with water)","Bread"],["6 large links, each cut in half","Hot Italian Sausage"],["3 large (28 oz.) cans (whole tomatoes)","Tomato"],["3 (6 oz.) cans","Tomato Paste"]],"steps":["Empty 1 can of tomatoes at a time into blender and liquefy.","Pour into large saucepan.","Add tomato paste directly from the can to the saucepan.","Simmer.","Meanwhile, in a skillet with a little oil, fry onion, green pepper, crushed garlic, salt and pepper.","When limp, add to blender (with about 1 cup of water) and liquefy.","Add this mixture to pureed tomatoes in the saucepan.","Stir with wooden spoon.","Drop in whole bay leaves.","Simmer (partially covered) for 1\u00bd hours or more.","Add water as needed (depending on how thick you like sauce).  \\r \\r To make a meat sauce: \\r Prepare as above.","While the tomato sauce is simmering, mix meatball ingredients with your hands.","Roll into 1\u00bd\u201d balls, and brown in a small amount of oil.  (One pound should make about 12 meatballs.)  Add each meatball to simmering sauce and cook at least 1\u00bd hours.","Option: If you prefer loose meat in the sauce, mix meatball ingredients, and fry loose in a small amount of oil.","Add loose meat to simmering tomato sauce & cook.","Option: Hot sausage may be added to sauce in the same way.","After browning, cook in the sauce for at least 1\u00bd hours.","Cook macaroni (Spaghetti, Ziti, Penne, Rotelli, Rigatoni, whatever).","Drain.","Top with sauce, meatballs, sausage, and Parmesan cheese.\\r"]},{"id":199,"name":"Pasta Fajioli","cat":"Pasta","submittedBy":"Angie Dellos","description":"Pronounced (pasta-fa-zool) meaning \u201cpasta and beans\u201d.  As a child, I did not like beans!  So, when we had pasta and beans, my mom would always separate out some of the pasta (without the beans) just for me.  Use the same sauce as on Page 46 (without the tuna), or use your own home-made spaghetti sauce, or use bottled sauce.","time":"","serves":"","ingredients":[["1/2 lb.","Navy Beans"],["3 cups","Water"],["1 tsp.","Salt"],["1 cup","Tomato Sauce"],["to taste","Parmesan Cheese"],["to taste","Red Pepper"]],"steps":["Wash beans.","Discard the imperfect ones and all other foreign objects in the beans.","Place beans in a 3-qt. saucepan with water.","Bring to a boil and simmer for 2 minutes.","Discard water.","Add 3 cups clean cold water and 1 tsp. salt.","Return to heat and simmer 1\u00bd hours or until beans are tender.","If the beans become dry, add more warm water.","Continue cooking, stirring occasionally.","When cooked, set aside.","In a separate pot, cook noodles.","Bring water to a boil with 1 tsp. salt.","Add noodles and cook (al dente).","Drain\u2014(save 1 cup of this water.)  Add pasta to beans.","Dilute 1 cup of tomato sauce with 1 cup of the pasta water.","Add to pasta and beans.","Stir.","Top with Parmesan cheese and red pepper flakes.\\r \\r Note: As the pasta and beans stand, they will absorb all the liquid.","Add more water to keep loose.","Enjoy.","Better the second day!\\r"]},{"id":200,"name":"Ham Patties","cat":"Meat","submittedBy":"Bette Ann DiFulvio","description":"","time":"","serves":"","ingredients":[["1 1/2 slice (about 1/2 lb.)","Ham"],["2 medium peeled","Potato"],["1 small","Zucchini"],["1 small","Yellow Squash"],["1 small","Onions"],["3 small","Eggs"],["1 cup seasoned","Breadcrumbs"],["1/4 cup","Milk"],["1 large","Eggs"],["as needed to  coat patty","Flour"]],"steps":["Shred ham, potato, zucchini, squash and onions.","Add 3 eggs and bread crumbs.","Mix well into patties.","Chill.","Drop each patty into mixture of 1 egg and milk, then into flour and fry in oil.","Drain.","Serve with sour cream and chives"]},{"id":201,"name":"Sausage Roll","cat":"Meat","submittedBy":"Lillian Pisani","description":"","time":"","serves":"","ingredients":[["1 lb., loose, well cooked","Sausage"],["3","Eggs"],["grated (amt. as desired)","Parmesan Cheese"],["to taste","Parsley"],["to taste","Salt and Pepper"]],"steps":["Roll dough into a quarter of an inch thick rectangle.","In a mixing bowl, add eggs, cheese, parsley, salt and pepper to warm cooked sausage.","Spread mixture onto dough.","Roll up.","Set aside (to raise longer\u2014about 1 hour) before you bake it.","Bake 350 degrees until brown (30-35 minutes).  ;"]},{"id":202,"name":"Veal Scaloppini","cat":"Meat","submittedBy":"Angie Dellos","description":"Serve with boiled rice seasoned with butter, and a tossed salad.  Serves 4.","time":"","serves":"","ingredients":[["1 lb.","Veal"],["3 Tbsp.","Vegetable Oil"],["1 small, chopped","Onions"],["to taste","Salt and Pepper"],["1 Tbsp.","Flour"],["","Parsley"],["1 Tbsp. minced","Parsley"],["1 clove","Garlic"],["1 Tbsp.","Tomato Paste"]],"steps":["Cut veal into 3\u201d squares.","Pour oil into frying pan.","Add onion and veal and cook until light brown.","Season with salt and pepper.","Turn meat over occasionally.","Sprinkle flour over the veal.","When it is blended, add sherry, parsley and garlic.","Cook a few minutes until sherry is absorbed.","Dilute the tomato paste with a cup of hot water and pour over the meat.","Cover pan, and allow to simmer slowly for about \u00bd hour."]},{"id":203,"name":"Speidies","cat":"Meat","submittedBy":"Diane Randesi","description":"I\u2019m not sure if it is just an \u201cEndicott thing\u201d, but I have yet to meet a Californian who has ever heard of speidies.  Pronounced (speed-dees), these are marinated bite-sized pieces of lamb barbecued on a skewer.  When I was a teenager, it was common after a football or basketball game to look for a bar/restaurant where speidies were being cooked on a grill outside.  You could just walk up, ask for a speidie, pay whatever it cost, and walk away with a sandwich of speidie meat.  The cook would take a slice of Italian bread and slide it from the bottom of the skewer to the top taking the meat with it.  The cooked marinated meat was delicious by itself, but I always liked it best with green salad stuffed into the sandwich as well.","time":"","serves":"","ingredients":[["3 lbs. (may substitute chicken or beef","Lamb"],["1/2 cup","White Wine"],["1 juice and peel","Lemon"],["2/3 cup","Cooking Oil"],["2/3 cup","Wine Vinegar"],["2 cloves, chopped","Garlic"],["2 tsp.","Oregano"],["2 tsp.","Basil"],["2 tsp. salt, 1 tsp. pepper","Salt and Pepper"],["Sprig (may also use Sprig of Mint","Parsley"]],"steps":["Combine all ingredients (except meat) for the marinade.  (Set aside part of this mixture to use later for basting.)  Cut meat into bite-size pieces and place in a bowl with the marinade.","Cover, and refrigerate overnight.","When ready to cook, place pieces of marinated meat on skewers and barbecue.","Discard marinade.","When meat is cooked, baste with the marinade that was set aside earlier.","Use the leaf end of a celery stalk to baste, or simply sprinkle with a shaker of the mixture.","Remove meat from skewers.","Enjoy with Italian bread and tossed salad with oil & vinegar dressing!"]},{"id":204,"name":"Maggie's Zucchini Patties","cat":"Non-Meat","submittedBy":"Rose Greco","description":"Great for a crowd.","time":"","serves":"","ingredients":[["1 cup","Breadcrumbs"],["1 cup, grated","Romano Cheese"],["1/2 cup","Flour"],["2 medium-size, grated","Zucchini"],["to taste","Garlic Powder"],["1/4 tsp.","Pepper"],["1/4 tsp.","Baking Soda"],["to cover bottom of frying pan","Oil"]],"steps":["Combine bread crumbs, cheese and flour.","Mix.","Dough will be stiff.","Add zucchini, garlic powder, pepper and baking powder.","Mix.","Drop by spoonfuls into frying pan of hot oil.","Remove.","Eat while hot.\\r"]},{"id":205,"name":"Rice or Mashed Potato Croquettes","cat":"Non-Meat","submittedBy":"Rose Greco","description":"My mother used to make these.","time":"","serves":"","ingredients":[["","Rice"]],"steps":["Mix cooked rice (or leftover mashed potatoes), 2 eggs, butter,\\r grated cheese and seasonings.","Form into a 1\u00bd\" round ball (or croquette).","Make a hole in the middle of each croquette.","Insert a piece of Provolone or Mozzarella cheese.","Smooth over opening to enclose cheese.","Dip croquette in 1 beaten egg, roll in bread crumbs, and fry until brown.","Drain.","Best eaten while hot.\\r"]},{"id":206,"name":"Scalloped Corn","cat":"Non-Meat","submittedBy":"Cheryl McDermott","description":"This is my mother\u2019s (Marie Shea) recipe.  Because our family has always been one of the largest, it has become traditional for us to share in the responsibility of a festive meal, by dividing up the menu.  This is one of our favorite dishes and has become a standard for me to prepare.","time":"","serves":"","ingredients":[["12 stick","Margarine"],["1 1/2 cups","Milk"],["2 1/2 Tbsp.","Flour"],["3","Eggs"],["1/2 tsp.","Salt"],["pinch","Sugar"],["(optional)","Pepper"],["to cover top of casserole dish","Breadcrumbs"]],"steps":["Preheat oven to 350 degrees.","In a saucepan, melt margarine and add shaken flour and milk.*  Bring just to a boil and sprinkle with salt and pepper.","Beat eggs and add them plus the corn to the saucepan.","Top with bread crumbs.","Bake in a 9x12\u201d greased casserole dish for approximately 1 hour. \\r \\r *Tip: When shaking flour and milk  (in an airtight container), start by turning completely over \u2013 shake gently.","Be careful when opening.","If opened too quickly, it will end up all over you!\\r"]},{"id":209,"name":"Holiday Nuggets","cat":"Desserts","submittedBy":"Lillian Pisani","description":"","time":"","serves":"","ingredients":[["1/2 cup, softened","Unknown"],["1/2 cup, softened","Unknown"],["1/2 cup","Unknown"],["1 Tbsp.","Unknown"],["1 Tbsp.","Unknown"],["2 cups","Unknown"],["1/2 tsp.","Unknown"],["12 cup, chopped","Unknown"]],"steps":["In a mixing bowl, cream butter, margarine and sugar.","Blend in vanilla and almond.","Gradually add flour and salt.","Stir in nuts.","Shape into one and one quarter inch balls.","Place on ungreased cookie sheets.","Flatten slightly with fingers.","Bake 325 degrees for 25 min.","Cool.","Sprinkle with powdered sugar and colored, crystallized sugar.","Makes 3\u00bd dozen."]},{"id":210,"name":"Texas Cheescake","cat":"Miscellaneous","submittedBy":"Lillian Pisani","description":"","time":"","serves":"","ingredients":[["2 sticks","Unknown"],["1 cup","Unknown"],["4 Tbsp.","Unknown"],["2 cups","Unknown"],["2 cups","Unknown"],["1/2 tsp.","Unknown"],["2","Unknown"],["1/2 cup","Unknown"],["1 tsp.","Unknown"],["","Unknown"],["1 stick","Unknown"],["4 Tbsp.","Unknown"],["6 Tbsp.","Unknown"],["1 lbs.","Unknown"],["1 tsp.","Unknown"],["plenty","Unknown"]],"steps":["Bring margarine, cocoa and milk to a boil.","Add salt.","Beat in eggs, sour cream and baking soda.","Pour into large greased 9x15\u201d cookie sheet.","Bake 350 degrees for 20-25 minutes.  \\r \\r Frosting: Bring margarine, cocoa and milk to a boil.","Remove from heat and add powdered sugar and vanilla.","Beat well and spread over cake as soon as it comes out of the oven.","Sprinkle with plenty of chopped nuts.\\r"]},{"id":211,"name":"Cream Puff Ring","cat":"Desserts","submittedBy":"Lillian Pisani","description":"","time":"","serves":"","ingredients":[],"steps":["Boil margarine and water.","Add flour and salt.","Remove from stove.","Beat in one egg at a time.","Drop dough in \u201cpuffs\u201d close together around the edge of a baking dish forming a ring.","Bake at 450 degrees for 10 minutes.","Reduce heat to 400 degrees, and cook for another 25 minutes.","Remove and cool.","After it is cooled, slice off the entire top half of the ring.","Set aside.  (It is likely to break apart, but can easily be salvaged piece by piece after the ring is filled\u2014 Any breakage will be hidden by the topping of powdered sugar).","Spread the bottom half of shell with filling mixture.","Spread Cool Whip on top of filling.","Top with the shell you sliced off earlier.","Sprinkle with powdered sugar.","A pretty dessert, especially when displayed on a pedestal cake platter.\\r     ;;;;"]},{"id":231,"name":"Beer Bread","cat":"Miscellaneous","submittedBy":"Alice Kocik","description":"","time":"","serves":"","ingredients":[["2 3/4 cups self-raising flour (not \"cake\" flour)","Flour"],["1 bottle, 12 oz. freshly opened, chilled or room temperature","Beer"]],"steps":["Heat oven to 375 degrees.","Lightly grease a 9 x 5 x 3 inch loaf pan.","Put flour in a medium bowl.","Add beer and stir with a rubber spatula just until mixed and flour is moistened completely.","Scrape into prepared pan.","Bake 50-55 minutes until top is lightly browned, sides pull away from pan, and pick inserted near center comes out clean.","Cool in pan on a wire rack 5 minutes, then turn out on rack to cool.","To serve, cut in 1/2-inch thick slices with a serrated bread knife.","Makes one loaf.","Store airtight at room temperature up to 3 days or freeze up to 3 months."]},{"id":235,"name":"All in One Chicken","cat":"Meat","submittedBy":"Angie Dellos","description":"","time":"","serves":"","ingredients":[["1 Fryer, cut into pieces","Chicken"],["1/2 Cup","Breadcrumbs"],["1/2 Cup","Oil"],["as desired","Parsley"],["as desired","Salt and Pepper"],["1 clove, crushed","Garlic"],["1/4 Cup","Wine Vinegar"]],"steps":["In a two or three-quart pyrex cake pan, mix all ingredients, except chicken pieces, into a soft paste.","Roll chicken pieces into the paste, cover, and bake in a slow oven (300 degrees) for 2 1/2 hours."]},{"id":236,"name":"test recipe","cat":"Appetizers","submittedBy":"Jeff Randesi","description":"Dsecription","time":"1 hour","serves":"2","ingredients":[["a a","Almond Extract"],["b b","Baby Carrots"],["c c","Cabbage"],["d d","Dates"]],"steps":["test"]},{"id":239,"name":"Taco Soup","cat":"Soups","submittedBy":"Diane Randesi","description":"","time":"","serves":"","ingredients":[["1 can - chilli","Fat Fee Turkey"],["1 can","Black Beans"],["1 can","Pinto Beans"],["1 can, chopped","Tomatoes"],["3 cans, low fat","Chicken Broth"],["2 Tbsp.","Taco Seasoning Mix"],["2 sliced","Zucchini"],["2 sliced","Yellow Squash"],["1 can","Baby Carrots"],["1 can ortega sliced chilies","Chili"],["1 chopped","Yellow Onion"]],"steps":["Place all ingredients into a stock pot.","Bring to a boil, then simmer for 30 minutes.","When cool, puree in blender.","Great taste."]},{"id":240,"name":"Veggie Soup","cat":"Soups","submittedBy":"Diane Randesi","description":"This is a Weight-Watcher recipe.  You can eat all you want of this without worrying about adding weight!","time":"","serves":"","ingredients":[["1 can","Stewed Tomatoes"],["3","Carrots"],["1/2 large","Yellow Onion"],["3 big handfuls, shredded","Cabbage"],["3 ribs","Celery"],["2-3 cloves","Garlic"],["1/2 lb. 1\" pieces (or use canned)","Green Beans"],["1 large can and 1 small can","Chicken Broth"],["1 can, drained","Garbanzo Beans"],["1","Bay leaves"]],"steps":["Chop carrots, celery, and garlic coursely.","In a stock pot, saute for five minutes in light oil or Pam.","Add broth and remaining ingredients.","Simmer covered for 15 minutes.","Done."]},{"id":241,"name":"Veggie Salad","cat":"Salads","submittedBy":"Diane Randesi","description":"A Weight-Watcher recipe.  Munch all day all you want!","time":"","serves":"","ingredients":[["2 bunches, cut up","Broccoli Flowerets"],["1 head, cut up","Cauliflower"],["6 ribs, cut up","Celery"],["1 cut up","Red Onion"],["1 cut up","Green Bell Pepper"],["2 cans, slivered","Mushrooms"],["1/2 cup","Rice Vinegar"],["1/4 cup","Oil"],["10 packages","Equal Sugar Substitute"],["2 Tbsp.","Pork Baby Back Ribs"]],"steps":["Combine all ingredients.","Mix.","Done."]},{"id":242,"name":"Rasberry Glazed Turkey","cat":"Meat","submittedBy":"Ann Romanowski","description":"This is an easy weekday meal, and a great change of pace from the usual chicken and other fare.  (The best part is it's ready in 30 minutes._","time":"","serves":"","ingredients":[["1/2 cup (or use \"Allfruit\")","Rasberry Preserves"],["6 Tbsp.","Rasberry Vinegar"],["1/2 cup","Dijon Mustard"],["4","Turkey Breast Tenderloins"]],"steps":["In a saucepan over high heat, bring jam, vinegar, and mustard to a boil.","Cook, stirring, 3 minutes, until mixture thickens.","Reserve 1/2 cup glaze.","With remaining glaze, baste turkey tenderloins and broil about 5 minutes.","Turn and coat the other side with glaze and broil until done.","Serve with reserved glaze.","Goes well with rice and a veggie."]},{"id":243,"name":"Almond Wild Rice","cat":"Non-Meat","submittedBy":"Anne Romanowski","description":"This makes a great side dish for company, but can also be a meal in itself.","time":"","serves":"","ingredients":[["5 cups, divided","Chicken Broth"],["1 cup (or golden raisins)","Raisins"],["6 Tbsp., divided","Butter or Margarine"],["1 cup, uncooked","Wild Rice"],["1 cup, uncooked","Brown Rice"],["1 cup, slivered","Almonds"],["1/2 cup","Parsley"],["1/4 tsp.","Salt"],["1/4 tsp.","Pepper"]],"steps":["In a small saucepan, bring 1/2 c. broth to a boil.","Remove from heat, add raisins and set aside (do not drain).","In a large saucepan, bring 2 1/2 cups broth and 2 Tbsp. butter to a biol.","Add wild rice; cover, and simmer for length of time stated on the box (approx. one hour) or until rice is tender.","Drain if necessary.","Meanwhile, in another saucepan, combine 2 Tbsp. butter and the other 2 cups broth and bring to a boil.","Add brown rice and cover.","Reduce heat and simmer for 35-40 minutes or until rice is tender (drain if necessary).","In a small skillet, saute the almonds in remaining butter until lightly browned.","In a large serving bowl, combine wild rice, brown rice, raisins, almonds, parsley, salt and pepper.","Mix well and serve.","May be re-heated."]},{"id":244,"name":"The Pantheon's Spinach Pie","cat":"Non-Meat","submittedBy":"Anne Romanowski","description":"The Pantheon is an Endicott diner that serves excellent Greek dishes, especially their spinach pie.  Lots of IBMers eat there, and after doing so for many years, my mom asked them for their spinach pie recipe...here it is!!)","time":"","serves":"","ingredients":[["1/2 lb. (freezer section of any grocery store)","Phyllo"],["1 lb., frozen","Spinach"],["1/2 lb.","Feta Cheese"],["1 medium","Onions"],["1/4 cup","Olive oil"],["1/2 Tbsp.","Dill Weed"],["2 Jumbo, scrambled with a fork in a bowl","Eggs"],["1/8 cup, grated","Romano Cheese"],["dash","Salt and Pepper"],["2 sticks melted","Margarine"]],"steps":["Brown onions in olive oil.","Meanwhile, thaw, rinse, and squeeze moisture out of the chopped spinach.","Mix teogether in a bowl the spinach, feta cheese, browned onion, dill, eggs, romano, salt and pepper.","Layer 1/4 lb. phyllo in buttered 9x12 pan, brushing each layer with melted butter as you go along (use a pastry brush).","Work quickly, as the phyllo dries out quickly once you open the package.","Pour spinach mixture into the pan over the bottom crust.","Cover with remaining phyllo, layering with butter as you go.","Sprinkle the top of the dish with cold water.","Bake 350 degrees for about 45 minutes or until golden brown (start checking after around 30 minutes)."]},{"id":245,"name":"Herbed Cheese Stuffed Mushrooms","cat":"Appetizers","submittedBy":"Anne Romanowski","description":"These are a great opener for a dinner party.","time":"","serves":"","ingredients":[["12 oz., fresh","Mushrooms"],["3 oz.","Cream Cheese"],["1/2 cup","Parmesan Cheese"],["1 Tbsp.","Parsley"],["1-1/2 tsp.","Rosemary"],["1-1/2 tsp.","Thyme"],["1/4 tsp. (like Lea & Perrins)","Worcestershire Sauce"],["pinch of each (also pinch of nutmeg)","Salt and Pepper"]],"steps":["Pluck stems and wash mushrooms.","Mix other ingredients together with a fork (will be very crumbly).","Pinch mixture together into a small clump and stuff each mushroom with cheese mixture.","Bake in a 9x9 pan for 20 minutes at 350 degrees.","Serve hot."]},{"id":246,"name":"Cool Dessert","cat":"Desserts","submittedBy":"Diane Randesi","description":"","time":"","serves":"","ingredients":[["1-1/2 sticks","Margarine"],["1-1/2 cups","Flour"],["2/3 cup","Walnuts"],["1 cup","Powdered Sugar"],["8 oz.","Cream Cheese"],["24 ounces (one container)","Cool Whip"],["2-3","Banana"],["3 cups","Milk"],["1 each, vanilla and chocolate","Instant Pudding"],["1 grated","Chocolate squares"]],"steps":["Mix margarine, flour and walnuts together and spread into the bottom of a 9x13 pan.","Bake 350 degrees for 30 minutes.","Cool.","Mix powerded sugar, cream cheese and 12 oz. cool whip (half the container) together.","Spread over cooled crust.","Slice 2-3 bananas over the top.","Prepare pudding and spread over bananas.","Top with remaining half of the cool whip.","Sprinkle with grated chocolate"]},{"id":247,"name":"Asparagus Appetizer","cat":"Appetizers","submittedBy":"Diane Randesi","description":"A delicious appetizer or vegetable side dish.  Six servings.","time":"","serves":"","ingredients":[["18 stalks, cooked","Asparagus"],["3 slices","Prosuitto"],["3 Tbsp.","Cream Cheese"],["pinch","Parsley"],["1/4 cup","Oil"],["1 Tbsp.","Red Wine"],["1/2 tsp.","Dijon Mustard"],["1 clove","Garlic"],["1 Tbsp.","Chives"],["to taste","Salt and Pepper"]],"steps":["Cut each prosuitto slice in half.","Spread cream cheese and parsley over top of 1/2 piece of prosuitto.","Wrap prosuitto around three cooked asparagus.","Continue until you have six wrapped bundles.","Combine remaining ingredients and pour over tops of asparagus.","Cover and keep regrigerated until ready to serve."]},{"id":248,"name":"Three Choices for Carrot Side Dishes","cat":"Non-Meat","submittedBy":"Angie Dellos","description":"When you're looking to add carrots for a side dish, try preparing them in one of these three ways.","time":"","serves":"","ingredients":[["","Carrots"],["","Butter"],["","Nutmeg"],["","Parsley"],["","Onions"],["","Brown Sugar"]],"steps":["1.","Boil carrots in salted water for 10-25 minutes depending on how soft/hard you like them.","Season with butter, salt and pepper, a shake of nutmeg and a sprinkle of parsley.  2.","Cook 2 tablespoons of butter with 2 tablespoons of finely chopped onions until golden brown.","Add cooked carrots.   3.","Melt 1/2 cup butter in a heavy pan.","Add 1/2 cup brown sugar.","Stir until melted.","Add carrots and cook slowly until carrots are glazed."]},{"id":249,"name":"Stuffed Peppers","cat":"Meat","submittedBy":"Angie Dellos","description":"","time":"","serves":"","ingredients":[["6 peppers","Green Pepper"],["1-1/2 lbs.","Ground Chuck"],["3 eggs","Eggs"],["1-1/2 cups, cooked","Rice"],["to taste","Salt and Pepper"],["1/2 cup","Parmesan Cheese"],["2 crushed","Garlic"],["3 Tbsp.","Parsley"],["1 medium, chopped","Onions"],["1 large can, (or homemade)","Tomato Sauce"],["2 Tbsp.","Oil"]],"steps":["In a frying pan, fry onion in oil and add tomato sauce.","Heat thoroughly.","Cover bottom of a glass 3-quart baking dish with tomato sauce mixture.","Meanwhile, cut each green pepper in half lengthwise.","Mix ground chuck, eggs, rice, salt, pepper, parmesan cheese, garlic, parsley and onions.","Fill each half with the mixture.","Place each stuffed pepper onto the sauce in the baking dish with the filled side up.","Pour the remaining sauce over the stuffed peppers and cover with foil.","Bake 350 degrees for 1 hour or more."]},{"id":250,"name":"Zucchini and Cheese Lasagna","cat":"Non-Meat","submittedBy":"Angie Dellos","description":"","time":"","serves":"","ingredients":[["3 large, unpeeled","Zucchini"],["4","Eggs"],["1-1/2 cups","Breadcrumbs"],["1 cup","Parmesan Cheese"],["1 tsp.","Oregano"],["1/2 tsp.","Basil"],["1/4 tsp.","Garlic Salt"],["1/2 tsp.","Pepper"],["1/2 cup","Oil"],["1 32 oz. bottle (or homemade)","Tomato Sauce"],["2 lbs. drained","Ricotta Cheese"],["1/4 cup fresh or 1 tsp. dry","Parsley"],["2 cups, shredded","Mozzarella Cheese"]],"steps":["Cut three large zucchini in 1/2\" slices.","In a bowl, mix 2 eggs and 1 Tbsp. cold water.","In a separate bowl, mix breadcrumbs, 1/4 cup parmesan cheese, oregano, basil, garlic salt, black pepper.","One by one, dip zucchini pieces first in egg mixture, then in breadcrumb mixture to coat.","Fry in oil.","Remove from frying pan.","Place 1 cup tomato sauce in a 9x13 glass pan.","Add a layer of fried zucchini.","In a separate bowl, mix ricotta, 2 eggs and parsley.","Spoon half of this mixture on top of the zucchini.","Add a layer (1 cup) of mozzarella cheese.","Start again with a layer of sauce, a layer of zucchini, a layer of ricotta mixture, and a layer (remaining 1 cup) of mozzarella cheese.","Top with sauce and another layer of zucchini.","Bake covered in preheated oven at 350 degrees for 1 hour."]},{"id":251,"name":"Country Style Spare Ribs","cat":"Meat","submittedBy":"Angie Dellos","description":"","time":"","serves":"","ingredients":[["1 lb.","Country Style Spare Ribs"],["1 cup","Catsup"],["enough to cover ribs in pot","Water"],["1 chopped","Onions"],["1/4 cup","Vinegar"],["1/4 cup","Worcestershire Sauce"],["1 tsp.","Brown Sugar"],["1 tsp.","Salt"],["1 tsp.","celery seed"]],"steps":["Boil ribs in water for 1 hour.","Remove from pan and place in baking dish.","In a bowl, mix catsup, onion, vinegar, worchester, brown sugar, salt and celery seed together.","Pour this mixture over the ribs.","Cover with foil and bake at 350 degrees for 1 hour.  (Remove foil the last 15 minutes of baking.)"]}];
const INTRO = [{"page":"i","title":"Title Page","content":"The Greco  \nFamily  \n\u201cCooks\u201dBook  \n \n\u2026\u2026\u2026..plus fond memories of food,  \nfun, \nand family customs \n \n \n \nCompiled and written by \nDiane Randesi \nDrawings by Steve Randesi"},{"page":"ii","title":"Publication Info","content":"ii\n \n \n \n \n \n \n \nDefinitions (shown in boxes) obtained, in part, from www.cooking.com. \nPrinting and binding  by my friends Dave, Peggy, and Rick Eklund of Advantage Grafix (a family-\nowned printing business) in San Jose, CA \n \nPrinted in the United States of America \n December, 1998 \n               Revised:  August, 1999  \nAdditional copies of this book are available for $12 each (plus $4 for first-class shipping) from: \nDiane Randesi \n1235 Laurie Avenue \nSan Jose, CA   95125 \n408/266-6285 \nfax: 408/446-9134 (Attention: Diane) \nemail:  drandesi@sprynet.com"},{"page":"iii","title":"Contents","content":"iii\n \nCONTENTS \n \n \nAbout the Author   iv \n \nDedication/Acknowledgements v \n \nThe Tree       vi \n \nPreface       vii \n \nAbout the Main Characters    ix \n \n1:   Appetizer       1 \n \n2:   Soup        9 \n \n3:   Salad       19 \n \nEaster Season/Lent     27 \n \n4:   Pasta     31 \n \n5:    Meat and Poultry      51 \n \n6:   Non-Meat    73 \n \n7:   Fish      89 \n \nChristmas Season/Advent     95 \n \n8:   Dessert       99 \n \n9:   Miscellaneous      157 \n  \n Glossary of Terms   165 \n \nIndex     167"},{"page":"iv","title":"About the Author","content":"iv\n \nAbout the Author \nI was born in Johnson City, New York, on January 21, 1947.  I grew up in \nEndicott, New York, the home of the Endicott Johnson Shoe Company and \nInternational Business Machines (IBM).  I was the middle of three children.  My \nrecollection of my childhood is memories centered around family and family \nevents, such as birthdays and holidays.  Most of the activities in my early years \ncentered around Brownies and Girl Scouts, which were associated with the \nCatholic Church.  Nine months after I was born, my husband, Steve, was born in \nthe same hospital.  We discovered last year that our birth certificates look the \nsame and are even signed by the same person!  It must have been destiny because \nwe met in Kindergarten, were childhood sweethearts, attended the 9th and 12th \ngrade proms together, and then married in 1969 in Saint Anthony\u2019s Church.  In \n1971, we, along with my brother John and his wife, Gail, embarked on an \nadventure that took us on a camping trip across the country where we would end \nup in California to experience life in another part of the United States.  We \nintended it to be for one year, but that year extended to 27 years.  We settled in \nNorthern California; John and his family settled in Southern California; my \nyounger brother, David, followed a few years later and also lives with his family \nin Southern California.  My parents moved from Poughkeepsie, New York to \nNorthern California in 1978.   \nSteve and I have a wonderful family\uf8e7 Karen, age 21, Jeff, age 20, and Joey, age \n17.  Karen is teaching 2nd grade as part of a service project in Mobile, Alabama, \nJeff is attending college at Cal Poly, San Luis Obispo, California, and Joey is a \nsenior at Bellarmine College Prep High School in San Jose.  They are terrific \npeople, and we are enormously proud of each one of them.  Steve has been part \nowner of his own business since 1979, where I work when it fits into my \nschedule!  (It\u2019s great to be in with the boss!)  I spend time volunteering when I\u2019m \nnot working, and I enjoy doing projects using my hands.  My adult life has been \npretty much centered around the children, and now that we are soon to be \u201calone \nin the nest\u201d (except for our beagle, Mocha), I need to \u201cget a life.\u201d  When we \nretire, we would like to travel and do work in the service of others.  Cooking is \none of my least favorite things to do.  I\u2019d much rather compile and write a \ncookbook than actually cook, but I\u2019m starting to get inspired."},{"page":"v","title":"Dedication & Acknowledgements","content":"v\n \nThe Randesi Family: From left to right, Joey, Karen, Steve, Diane and Jeff \n \n         DEDICATION/ACKNOWLEDGEMENTS \n \nDedicated to my husband, Steve, who encouraged me to do this book\u2014 who did the \nillustrations for it\u2014 and who had to listen tirelessly at every step of the way\u2014 he is \nalways there and encouraging me no matter what I want to pursue.  I have loved and \nappreciated him for every one of the almost 30 years we\u2019ve been married. \n \n\u2026And to my children, Karen, Jeff and Joey, because I always wanted to dedicate my first \nbook to my children.  I\u2019m working on a second book designed just for them, with love.  I \nthought that it would be my first book.  This endeavor came first because it was easier.  \nThe next one will take longer\u2014 maybe forever.  \n \nThank you to my cousin, Maryann (English) Haggerty, and to my good friends, \nCassandra Dotzler, Linda Snider, and Skip Vaccarello, who agreed to proofread this book \nwith an independent, critical eye, and whose corrections, suggestions, and comments I \nappreciate. \n \nRefer to \u201cThe Tree\u201d (page vi) if you are lost as to who belongs to which family.  I \npurposely only included the family through my first cousins, once removed.  These are \nthe family members with whom I am closest and with whom I corresponded in order to \ncompile the recipes.  Many of the children of the Roma family have children of their \nown.  To those children, I hope one of you will be inspired to write The Greco Family \n\u201cCooks\u201d Book Volume II sometime in the future, and perhaps start where I left off."},{"page":"vi","title":"The Family Tree","content":"(The Family Tree \u2014 a visual diagram of the Greco family \u2014 appears on this page in the original hardcopy edition.)"},{"page":"vii\u2013viii","title":"Preface","content":"vii\n \nPREFACE \n \nI have long thought about how important family has been (and is) throughout my life.  I \nfind myself relating the same stories over and over again as circumstances arise.  I also \nhave been feeling the need to preserve some of the traditions of MY past because I fear \nthey might be lost.  Although I try to continue doing the things I remembered and \nenjoyed the most, times and circumstances change, and we must make our own traditions \nin our own families.  In addition, some of us live in different parts of the country, which \nchanges what is customary, such as getting together on holidays, birthdays, etc.  We live \nin California, and my children have been brought up in a much different environment.  \nWhereas we were from a small town where most everyone we knew was Catholic, and a \nlot of them were Italian, my children have grown up where there are few Italians and \nwhere they have been exposed to a wide variety of religious beliefs.  In addition, many of \nus (not me) married into families with different backgrounds that have completely \ndifferent customs and, of course, must share both in bringing up their children.  \nTherefore, it occurs to me that as we each make our own customs in our own families, \neventually some of the past could completely disappear except for what has been written \ndown.  Therefore, this is my attempt at keeping these traditions alive.  The accounts of \nthe family and the holidays (p. 27 and p. 95) are written from MY perspective as I \nremember them when I was a little girl.  Some of you will remember things just as I have \n(especially those closest in age to me), but some of you will wonder, where did she get \nthat from?  Some of you will no doubt, remember more and different things and could \nprobably add your own memories.  \n \nThis is the time to state some disclaimers.  Some recipes may be \u201coriginals,\u201d but they \nare mostly just \u201cfavorite\u201d recipes of different family members.  I\u2019ve tried to check \nspellings of Italian words to the best of my ability.  Also, I\u2019ve tried to check that the \ningredients match the information in the descriptions.  I can\u2019t be sure I\u2019ve caught \neverything.  I can tell you, it was a challenge to write and rewrite some of the \ndescriptions because I was given recipes that included phrases like \u201ca little pepper,\u201d a \n\u201chandful of breadcrumbs,\u201d \u201cwork the dough until it is medium\u201d, \u201cit\u2019s a feeling you get \nwhen it\u2019s just right,\u201d \u201cuse as much as needed,\u201d and \u201cyou can just tell when you\u2019ve added \nenough.\u201d  In some cases, I had to keep the recipes just the way they were.  You\u2019ll figure it \nout, if you are brave enough to try some of them.  Then, you\u2019ll know what that \u201camount\u201d \nor \u201cfeeling\u201d is.  It\u2019s empowering!   \n \nThe pronunciation of the Italian words are the way I remember my family saying them\u2014\nthey\u2019re not necessarily \u201ccorrect Italian\u201d, but it\u2019s the dialect they spoke, and the way I \nwant to remember them.  I apologize for any mistakes in recipes\u2014 I tried to understand \nthem and state them the way I understood them.  If you have a question on anything, at\n\nviii\n \nleast you know who to call\u2014 (not me!), but rather the \u201csource.\u201d  Preserving the past is \none reason for writing the book, but the main reason is to give tribute to the Greco \nfamily\uf8e7 my aunts and uncle who have graced the family with many, many good meals to \ngo along with good times and wonderful memories.  The family members who still live in \nEndicott get together often for coffee, birthdays, weddings, anniversaries, communions, \nconfirmations, whatever.  When I\u2019m with them, I realize how important they have been in \nmy life, and how many of the things they said and did have shaped my life.  Many of the \nactivities and traditions I\u2019ve had growing up in an Italian-American family revolve \naround food (for better or for worse).  This book is my attempt to capture a collection of \ntheir recipes to remind you and me, forever, of the wonderful, nurturing family we are.   \n \nThe journey has been better than I imagined.  I have corresponded with the entire family, \ntalked to cousins on the phone, and sent emails back and forth frequently.  None of it was \ndifficult; it was completely natural\u2014 that\u2019s family\u2014 when you can go without seeing or \ntalking to each other for a long time, but when you do, it\u2019s like yesterday\u2014 no barriers, \ncomplete trust, no need to impress or pretend.  Wouldn\u2019t it be nice to treat everyone like \n\u201cfamily\u201d?  Page vi will help you keep everyone straight.  The younger members of the \nfamily may need to refer to it when they see a recipe and don\u2019t recognize the name! \n \nFor the rare readers of this book who are not members of our family, I have made \nreferences to purchase certain ingredients at Jim Roma\u2019s Bakery.  Jim Roma is my first \ncousin, who owns and operates a very popular bakery in Endicott, New York.  Actually, \nanyone living in or around Endicott will know that you can purchase delicious bread, \nsandwiches, pizza, cookies, etc. at that bakery/restaurant.  I think when my Uncle Carl \nand Aunt Anna owned the bakery, they sold mostly bread and dough, but Jim has \nexpanded it to include much more.  Jim has employed practically every family member \nwho wanted a job, at one time or another, while they were growing up.  \n \nI, in no way, intended to leave out the men who, of course, play a major role in the \nfamily.  I could say more about my dad, John Dellos, and my uncles, Carl Roma, Nick \nEnglish, Louie DiFulvio, and Joe Pisani.  I could definitely say more about my husband, \nSteve, my children, my brothers and their wives, and my cousins who married into the \nfamily.  I also have equally fond memories of my dad\u2019s side of the family (the Dellos') \nand my husband\u2019s side of our family (the Randesis), but those would all be different \nbooks!  I had to draw the line somewhere and decided to keep it to the Grecos as much  \nas possible.  Sorry if I offend anyone.  That\u2019s me\uf8e7 in the words of my cousin\uf8e7  a \n\u201crecovering pleaser\u201d"},{"page":"ix\u2013xviii","title":"About the Main Characters","content":"ix \n \n. \nABOUT THE MAIN CHARACTERS \n \nThis family history begins with Grandma and Grandpa Greco.  They were married in the \nAbruzzi region of Italy in 1903.  Together, they had seven children.  The oldest of the \ngirls was Aunt Anna, followed by Aunt Minnie, Aunt Kay, Aunt Julia, my mother \n(Angie) and Aunt Lily.  The one boy (who must have been spoiled with all those sisters), \nUncle Sammy, was born after Aunt Julia and before my mother.  \n \n  \n  \n \nThe oldest children, Aunt Anna and Aunt Minnie (Domenica), were born in Italy. \nGrandpa came to America with Grandma\u2019s brother, Nick, and lived in New York City for \nfive years.  He returned to Italy for a short time, then revisited the United States to make \narrangements for Grandma and their two girls to join him, which they did in 1911.  Upon \ntheir return, however, they settled in Mt. Pocono, Pennsylvania because they felt it was a \nbetter place to raise a family.  (My great Uncle Nick remained in New York City to raise \nhis family\u2014  See my NewYork Cousin Millie\u2019s recipe on p. 102).  In America, Grandpa \nworked for the railroad.  Grandma was a \u201cstay-at-home\u201d mom. \nProvinces of Italy: \n \nA  Aosta Valley \nB  Piedmont \nC  Lombardy \nD  Trentino-Alto   \n     Adige \nE  Veneto \nF  Friulli-Venetia julia \nG  Liguria \nH  Emilia-Romagna \nI  Tuscany \nJ  The Marches \nK  Latium \nL  Umbria \nM Abruzzi \nN  Campania \nO  Molise \nP  Apulia \nQ  Basilicata \nR  Calabria \nS  Sicily \nT  Sardinia\n\nx \n \n \n \nGrandma (Maria) and Grandpa (Dominic) Greco \n \n \nAunt Julia, Aunt Kay (Catherine), Uncle Sam, and my mother, Angie, were born in Mt. \nPocono.  My Uncle Sam likes to boast that he was born in \u201cParadise\u201d, Pennsylvania.   \nAfter 11 years (in 1923), they migrated to Endicott, New York where they bought a \nhouse on Odell Avenue.  Aunt Lily (Lillian) was born in that very home on Odell Avenue \nwhere my Aunt Julia lives today.  My Grandpa Greco died of cancer when he was only \n57 years old, leaving Grandma to raise a family of six girls and one boy. The youngest, \nAunt Lily, was only 13 years old when Grandpa Greco died.\n\nxi \n \nGrandma Greco at her 75th Birthday \n \nGrandma Greco was born in 1882.  I remember her from a very early age.  It was \ncommon for my mother to take us for a walk from 31 Odell Avenue, where we lived, to \n319 Odell Avenue where Grandma Greco lived.  Many of our evenings, especially in the \nsummertime, were spent on the porch at Grandma Greco\u2019s house.  There were always \npeople there, many times one or more of my aunts and cousins, but usually Grandma and \nAunt Julia who lived there, too.  I remember sitting on the porch eating tart green apples \nfrom the tree out back.  They were small apples, but not so small to justify the large \namount we ate, while we passed around the salt shaker after every bite.  There were never \nenough salt shakers!  Grandma would be on the rocking chair listening to the \nconversation and reminding us how sick we could get if we ate too many apples!   \nI remember her combing her very long white hair.  Unless you saw her combing it, you\u2019d \nnever know how long it was because she wore it in a bun at the nape of her neck.  She \nalways wanted you to try some of her canned fruit, or something from her garden, of \nwhich she was so proud.  She didn\u2019t speak much English.  She would ask me questions in \nItalian, and I would answer to what I thought she asked.  I only knew a few phrases in \nItalian, like \u201cdough-sta-ma-ma?\u201d (Where\u2019s your Mother?), to which I always answered, \n\u201cla goz\u201d (home) because I wouldn\u2019t have known how to say anything else!  She would \nget irritated that I often answered to a different question than she asked.  Mostly we \ncommunicated by just smiling, shaking heads, or shrugging shoulders.  She always took\n\nxii \n \nme out back to show me something in her garden or to give me something from the \ngarden to take home.  She liked it when you ate her canned fruit and expressed approval.   \n \nOnce she sent me to Roma\u2019s Bakery to buy a loaf of dough.  On the way back, I was \nswinging the bag, and the dough flew out of its paper bag into the bushes.  I tried to \nretrieve as much of the dough as possible, picking out the pebbles that it picked up when \nit landed.  I returned with a very small loaf of dough and a hole in the bag.  Grandma \nseemed to be asking me a lot of questions in Italian in a loud voice\u2014 she was definitely \nupset, but I pretended I had no idea what she was saying.  I really did feel badly, but \ndidn\u2019t know how to explain.  She threw her hands up in disgust and said, \u201cva-teen-a-va\u201d.  \nI think that meant \u201cget out of here\u201d!   \n \nGrandma liked to visit with her neighbors.  They would either walk to each others\u2019 \nhouses and sit on the porch, or talk across the lawn, each sitting on their own porch.  The \nnext-door neighbor would call out, \u201cMod-e\u201d (Maria), and Grandma would go outside and \ntalk for a while. (I think they had phones then, but they\u2019d rather shout out for each other \nand talk in person, I guess.)  Grandma was very kind.  She taught me how to use her \nsewing machine, which accelerated by footpower.  I lived with Grandma for one summer \nafter high school, and I wished very much that I knew more of the Italian language so that \nI could communicate better.  She understood English, I think, but she didn\u2019t respond in \nEnglish.   \n \nAt one time or another, family members would return to live (temporarily) at Grandma\u2019s \nhouse.  My mother lived there with my brother, John, while my father was in the service.  \nAunt Kay and her family lived there for a time; Aunt Lily and her family did also.  That \nhouse on 319 Odell Avenue continues through the generations to be available to family.  \nAunt Julia, who remodeled the downstairs and lives there now, has rented the upstairs out \nto several members of the family at one time or another.  In fact, my cousin, Mary Beth, \nwho lived in the upstairs apartment for a time with her family, converted one bedroom \ninto a nursery for her first child, Amy\uf8e7 the very bedroom where Mary Beth\u2019s mother, \nAunt Lily (Amy\u2019s grandma), was born!   \n \nGrandma\u2019s house was (and still is) a gathering place for all the family and their friends.  \nIt was also the place we gathered after Sunday mass.  St. Anthony\u2019s Church was right \ndown the street, and it was natural to go to Grandma\u2019s after Sunday morning mass.  The \ncoffee was on all morning at her house\u2014 the smell was of spaghetti sauce, which was \nalways cooking on the stove to be eaten around noon, by anyone who was there.  \nGrandma\u2019s house was also the gathering place on Christmas Eve for many years, where \nthe families of all the Greco children ate and exchanged gifts before going to Midnight \nMass.  Grandma was 89 years old when she died.\n\nxiii \n \nAll of the aunts\u2019 children (the entire family of first cousins listed on page vi, except Joey \nPisani,) were born in Endicott or in the hospital in nearby Johnson City.  Joey was born in \nCanton, Ohio.  In Endicott, we all lived within a few blocks of each other.  Aunt Lily \nmoved to Ohio for a short time, but later moved back to Endicott where she and her \nfamily live today.  Uncle Sammy moved his family to Southern California when his \nyoungest twins were about 7 years old.  He was really the first to venture out and away.  \nMy mother (Angie) and father lived in Poughkeepsie, N.Y. for a while, then moved to \nNorthern California to live closer to their children and grandchildren. \n \nThe Greco family members are positive, happy, unpretentious people.  I like to be around \nthem.  When the sisters are together, they giggle a lot.  They have always depended on \neach other for everyday support.  Profiled individually: \n\u2014  \nAunt Anna Roma lived a few blocks from Grandma \nGreco on Oak Hill Avenue.  I remember walking \nback and forth to each house.  Her children were \nolder than I was, so when we were at her home, I \nenjoyed watching teenagers coming and going\u2014 it \nwas a very different scene than my own home \nexperience.  She and my Uncle Carl owned Roma's \nBakery, which was also on Oak Hill Avenue.  \nAlmost daily, I would walk to the bakery to buy \nbread or dough.  I was so proud that our family \nowned a bakery.  A baby picture of their first \ngranddaughter (my cousin Yvonne) was part of the \nadvertisement on the wrapper of the Italian white \nbread that they sold.  How famous we felt!  Aunt \nAnna died of cancer when I was 12 years old.  Her \nfuneral was the first I had ever been part of.  There \nwere hundreds of people every day that came to see \nmy aunt at the funeral parlor.  The receiving line was \nlong.  I said a lot of rosaries during those three days \nof the wake and funeral.  It left a very strong \nmemory with me.  I\u2019ve been to very few funerals \nsince.  Aunt Anna was only 56 when she passed \naway.  Her daughter, Mana, still lives in the brick \nhouse on Oak Hill Avenue that I remember so well.  \n \n \n \n                Aunt Anna\n\nxiv \n \nAunt Minnie DiFulvio  (Her real name is Domenica, which means Sunday.)  I always \nthought it was strange to name your child \u201cSunday\", but it\u2019s a common Italian name. \nSince her daughter, Ann Marie, is my age, I spent a lot of time at the DiFulvio\u2019s.  I \nremember Uncle Louie playing the accordion.  I spent many overnights and happy times \nat their house.  I thought of them as living \u201cin the country\u201d because their home was not in \nthe few blocks where the rest of the family lived.  Instead, it was about \u00bd mile away, up \nwhat I thought was a huge hill surrounded by a lot of land.  They were also the only \nfamily with a dog (Tippy).  I loved being at Aunt Minnie\u2019s.  She worked in the Endicott \nJohnson shoe factory\u2014 I thought it was cool that she was a \u201cworking woman\u201d.  I\u2019m told \nthat all the sisters worked, but for some reason, I only remember Aunt Minnie and Aunt \nJulia working outside the home.  Maybe because of it, I always thought Aunt Minnie and \nUncle Louie were more relaxed about rules, etc.  I always felt a little more freedom there.  \nAunt Minnie is still very much \u201cwith it\u201d.  She is an amazing 87 years old.  Like the \nothers, she always greets you with a nice smile, and never has a complaint about \nanything!  The summer before last, we had a \u201cladies only\u201d reunion in Boston (p. xvi).  \nAunt Minnie easily kept up with the youngest of us, as we walked and talked around \nBoston on an incredible weekend of fun and laughter.  Aunt Minnie still lives in the same \nhouse on Milan Avenue with her son, Louie, and his family. \n \n \nFrom left to right: Aunt Lily, Aunt Julia, Aunt Minnie, Aunt Kay & Mom (Angie) in 1980\n\nxv \n \nAunt Kay English (Her real name is Catherine.)  Because I was working in Endicott, and \nmy parents lived in Poughkeepsie at the time, I lived with Aunt Kay for two years just \nbefore I got married.  We had coffee together every morning, and dinner together with \nUncle Nick almost every evening.  I loved Aunt Kay\u2019s mild, easy manner.  One was \nalways comfortable around her.  I loved that she worked at the hospital as a volunteer.  \nShe cooked simply, but it was always delicious, whether it was cooking what my Uncle \nNick had just brought home from a fishing trip or the usual macaroni dishes.  She had \nmacaroni with tomato sauce every Sunday afternoon for her family and for whomever \nelse might have been visiting.  She liked to make homemade macaroni like ravioli, and \nshe was good at it!  Aunt Kay\u2019s house was always open for coffee any time, and the \nsisters would alternate among each other\u2019s homes.  She passed away at age 72.  Her death \nwas a surprise to me.  She hadn\u2019t been sick.  My parents and I got on the first plane back \nto New York from California to attend her funeral.  As funerals go, they are always sad, \nbut our belief is that you celebrate the person passing to another life that is eternally \nhappy.  Therefore, it is a time to celebrate (sort of) and a time to quietly reminisce with \nfamily and friends.  Food generously pours in from everyone wishing to express and \nshare their sympathy and to help share the burden of entertaining the crowds who visit \nand mourn.  I miss her a lot. \n\u2014  \nAunt Julia Greco lived with Grandma.  Although she never married, I think she had \nmore than a few suitors in her time because she was (and is) very attractive.  She has \nalways been interested in health issues; she exercised, traveled a lot, and had many \ngirlfriends.  She was (and is) very active in Saint Anthony\u2019s Church; she was my Girl \nScout leader for a few years and chaperoned retreats, etc.  I remember her keeping a \nVERY clean house, driving Grandma and others around town, and lending my brother, \nJohn, her car, which she was teased about because she kept it so clean and put so few \nmiles on it.  Of course, it is Aunt Julia whom we all know best for giving the kids a \nChristmas gift every single year until they graduated from high school.  She continues \nthis tradition through the generations, even today\u2014 she did it with my own children until \nthey graduated from high school.  In California, it was a custom in our family for the \nchildren to open Aunt Julia\u2019s present first (before dinner) on Christmas Eve.  She \nobviously enjoys giving to this day.  I love and appreciate her generosity.  Although the \nhouse in which she lives has changed in appearance through her tasteful remodeling, she \nkeeps up the tradition of the original Greco home on Odell Avenue.  \n\u2014  \nUncle Sammy Greco  I remember Uncle Sammy when we lived on Odell Avenue, and he \nwould stop over to say hello on his way home from work.  He was a tailor and had a shop \non Oak Hill Avenue (same street as Roma\u2019s Bakery).  He invariably had pumpkinseeds in \nhis pocket and would always offer you some.  He was constantly cracking the seeds and \nleaving the shells behind.  We laughed because it was our perception that he would stop\n\nxvi \n \noff at one or more of his sisters\u2019 homes on his way home and sample some of whatever \nthey were preparing for dinner.  We always wondered if Aunt Rose was ever upset that \nhe must have been full by the time he sat down to his own dinner at night!  Uncle Sammy \nalways talked about going to California, but I remember the day he actually said he was \npacking up and leaving.  It was traumatic\u2014 he had five children\u2014 I remember thinking he \nwas really brave!  (It was 20 years later that we followed in his footsteps!)  During \nWWII, he enlisted in the Marines and received the Purple Heart Medal after he was \nwounded in the Battle at Iwo Jima.  To this day, he stays in touch with his military \nbuddies.  He still eats pumpkinseeds, sews, and enjoys dabbling in construction jobs for \nhis family, while Aunt Rose works at a hospital and is active in rescuing cats and other \nanimals for the Humane Society.  They live happily near all their children in Southern \nCalifornia. \n\u2014  \n \n \nFrom left to right top row:  Diane Randesi, Ann Delorey, Joyce Delorey, Mary Beth Schofield, \nAnn Marie VanOostendorp, Chery McDermott, Teresa Delorey.  Bottom row: Marie Shea, \nAunt Minnie DiFulvio, Aunt Julia Greco, Angie Dellos and Aunt Lily Pisani.  Photo taken at a \n1996 \u201cGirls Only\u201d Family Reunion in Boston.\n\nxvii \n \nMy mother, Angie (her real name is Angelina, which appropriately means \u201cLittle \nAngel\u201d) Dellos   My mother truly deserves a book of her own.  Lord knows I would not \nrun out of kind words for her throughout an entire book.  My perception of my mother \nwas (and is) that she is rather quiet, at least compared to me.  I always wished I had her \ndemeanor, but I\u2019ve learned to accept that I just don\u2019t.  My mother is more of a listener \nthan a talker, and honestly, never complains about anything.  I remember her in many, \nmany fond ways too numerous to mention in a cookbook.  But, at least where food is \nconcerned, she was (and is) one of the best cooks\uf8e7 just ask my husband!  She wouldn\u2019t \nsay so, but I\u2019ve never had an Italian dish at a restaurant better than what she can throw \ntogether in minutes.  She starts most dishes with a little garlic and a little onion in olive \noil\u2026 and, she ends most dishes with \u201ca little\u201d Parmesan cheese.  A little of this and a \nlittle of that, and she has a good meal going.  She still saves leftovers and makes the best \nmeals out of them.  She still sets the table for herself and my dad (and anyone else who\u2019s \nthere) and presents her food in the most appetizing way, unlike so many of us who are \neating on the run so much of the time.  She reads cookbooks the way you read a text \nbook\u2014 taking every recipe seriously, but always ending up with the standard favorites.  \nShe cuts recipes out of the newspaper and makes notes next to them if they are worth \nkeeping.  She\u2019s very creative with food, but very modest about it.   \n \nWe had macaroni every Sunday afternoon and were allowed to buy one quart of  Ma\u2019s \nRoot Beer soda from Tedeschi\u2019s (the market across the street from our house).  It was just \nenough for all five of us to have one glass each.  That\u2019s it.  No more soda for the rest of \nthe week\u2014 it was milk with every meal\u2014 it was a meal every single night.  My mother \nmade chocolate cake (p. 122) once a week, usually on Friday after she cleaned the house.  \nMy brothers and I remember coming home from school on Friday afternoon to a \nspanking clean house with the smell of chocolate cake (God forbid if you cut into it \nwithout asking)\u2014 the clean sheets were cool (from being hung outside to dry) and tucked \ninto the sides of the bed\u2014 it was a wonderful feeling!  Monday night dinner was typically \nchicken soup (p. 15).  Tuesday night was left-over macaroni from Sunday.  Common \nother meals during the week were pasta e fagioli (pronounced pasta-fa-zool, p. 50), veal \ncutlet, peppers and eggs, and pasta with tuna sauce (p. 46).  Once in a while, we had \ncereal for supper.  To this day, cereal is one of my favorite dinners.  Because we always \nhad full, complete meals, I thought of \u201ccereal for dinner\u201d as a treat, I guess!  Anyway, I \nam very fortunate and happy that my mother lives within 10 miles of me in Northern \nCalifornia so I still have plenty of opportunity to enjoy her\u2014 and her meals. \n \n*****\n\nxviii \n \n \nAunt Julia, Mom (Angie), Aunt Lily, Uncle Sam, Aunt Minnie in 1998 \n \n \nAunt Lily Pisani (Her real name is Lillian.)  I loved Aunt Lily\u2019s black hair and her white \nteeth.  She had (and has) a sexy, crooked eyetooth, which I secretly wished for because I \nthought her smile was so beautiful!  She moved to Ohio for a time after she married my \nUncle Joe.  I remember their wedding\u2014 he was so handsome, and she had the biggest and \nshiniest diamond ring I ever saw!  Uncle Joe was a shoe salesman who used to send my \ncousin, Ann Marie, and I, shoes because we wore the sample size.  He sent us our First \nCommunion shoes, of which we were so proud, and a pair of cowgirl boots, which were \nalso favorites.  When Ann Marie and I were 10 years old, we spent a summer with Aunt \nLily in Canton, Ohio.  She and Uncle Joe were wonderful to us.  We were the kids they \ndidn\u2019t have\uf8e7 yet.  They totally spoiled us\u2014 they let us buy a box of 24 chocolate candy \nbars once a week at the grocery store; they let us bake cakes, and allowed us to take the \nbus to town by ourselves.  We often took walks at night to the Grotto where we would all \npray for Aunt Lily to get pregnant, stopping for ice cream on the way back.  She \neventually did have that baby girl, Mary Beth, who is 10 years younger than I, so I think \nthose trips to the Grotto worked!  Aunt Lily is the baby of the family, and gets the prize \nfor submitting the most recipes for this book.  I was asked by a cousin to please include \neverything that she submitted because it\u2019s all good!  I knew that."}];

async function setupDatabase() {
  const client = await pool.connect();
  try {
    // Create tables
    await client.query(`
      CREATE TABLE IF NOT EXISTS recipes (
        id SERIAL PRIMARY KEY,
        name TEXT NOT NULL,
        category TEXT NOT NULL,
        submitted_by TEXT DEFAULT '',
        time_to_prepare TEXT DEFAULT '',
        serves TEXT DEFAULT '',
        description TEXT DEFAULT '',
        ingredients JSONB DEFAULT '[]',
        steps JSONB DEFAULT '[]',
        created_at TIMESTAMPTZ DEFAULT NOW(),
        updated_at TIMESTAMPTZ DEFAULT NOW()
      )
    `);
    await client.query(`
      CREATE TABLE IF NOT EXISTS intro_pages (
        id SERIAL PRIMARY KEY,
        page_number TEXT NOT NULL,
        title TEXT NOT NULL,
        content TEXT NOT NULL,
        display_order INTEGER NOT NULL
      )
    `);

    // Seed recipes if empty
    const { rows } = await client.query('SELECT COUNT(*) FROM recipes');
    if (parseInt(rows[0].count) === 0) {
      console.log('Seeding', RECIPES.length, 'recipes...');
      for (const r of RECIPES) {
        await client.query(
          `INSERT INTO recipes (name, category, submitted_by, time_to_prepare, serves, description, ingredients, steps)
           VALUES ($1,$2,$3,$4,$5,$6,$7,$8)`,
          [r.name || r.n, r.cat || r.category, r.submittedBy || r.s || '',
           r.time || r.t || '', r.serves || r.sv || '', r.description || r.d || '',
           JSON.stringify(r.ingredients || r.i || []), JSON.stringify(r.steps || r.st || [])]
        );
      }
      console.log('Recipes seeded successfully');
    } else {
      console.log('Recipes already seeded:', rows[0].count);
    }

    // Seed intro if empty
    const introCheck = await client.query('SELECT COUNT(*) FROM intro_pages');
    if (parseInt(introCheck.rows[0].count) === 0) {
      console.log('Seeding intro pages...');
      for (let i = 0; i < INTRO.length; i++) {
        const sec = INTRO[i];
        await client.query(
          'INSERT INTO intro_pages (page_number, title, content, display_order) VALUES ($1,$2,$3,$4)',
          [sec.page, sec.title, sec.content, i + 1]
        );
      }
      console.log('Intro pages seeded successfully');
    }

    console.log('Database ready');
  } catch (err) {
    console.error('Database setup error:', err.message);
  } finally {
    client.release();
  }
}

// ── Auth check endpoint ──
app.post('/api/auth', (req, res) => {
  const { password } = req.body;
  if (password === COOKBOOK_PASSWORD) {
    res.json({ success: true });
  } else {
    res.status(401).json({ success: false, error: 'Incorrect password' });
  }
});

// ── Health check ──
app.get('/api/health', async (req, res) => {
  try {
    await pool.query('SELECT 1');
    res.json({ status: 'ok', database: 'connected' });
  } catch (err) {
    res.status(500).json({ status: 'error', message: err.message });
  }
});

// ── GET all recipes ──
app.get('/api/recipes', async (req, res) => {
  try {
    const { category, search } = req.query;
    let query = 'SELECT * FROM recipes';
    const params = [];
    const conditions = [];
    if (category && category !== 'all') {
      params.push(category);
      conditions.push(`category = $${params.length}`);
    }
    if (search) {
      params.push(`%${search}%`);
      conditions.push(`(name ILIKE $${params.length} OR submitted_by ILIKE $${params.length})`);
    }
    if (conditions.length) query += ' WHERE ' + conditions.join(' AND ');
    query += ' ORDER BY category, name';
    const result = await pool.query(query, params);
    res.json(result.rows);
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// ── GET single recipe ──
app.get('/api/recipes/:id', async (req, res) => {
  try {
    const result = await pool.query('SELECT * FROM recipes WHERE id = $1', [req.params.id]);
    if (!result.rows.length) return res.status(404).json({ error: 'Not found' });
    res.json(result.rows[0]);
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// ── POST create recipe ──
app.post('/api/recipes', requireAuth, async (req, res) => {
  try {
    const { name, category, submitted_by, time_to_prepare, serves, description, ingredients, steps } = req.body;
    if (!name) return res.status(400).json({ error: 'Name is required' });
    const result = await pool.query(
      `INSERT INTO recipes (name, category, submitted_by, time_to_prepare, serves, description, ingredients, steps)
       VALUES ($1,$2,$3,$4,$5,$6,$7,$8) RETURNING *`,
      [name, category || 'Miscellaneous', submitted_by || '', time_to_prepare || '',
       serves || '', description || '', JSON.stringify(ingredients || []), JSON.stringify(steps || [])]
    );
    res.status(201).json(result.rows[0]);
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// ── PUT update recipe ──
app.put('/api/recipes/:id', requireAuth, async (req, res) => {
  try {
    const { name, category, submitted_by, time_to_prepare, serves, description, ingredients, steps } = req.body;
    const result = await pool.query(
      `UPDATE recipes SET name=$1, category=$2, submitted_by=$3, time_to_prepare=$4,
       serves=$5, description=$6, ingredients=$7, steps=$8, updated_at=NOW()
       WHERE id=$9 RETURNING *`,
      [name, category, submitted_by || '', time_to_prepare || '',
       serves || '', description || '', JSON.stringify(ingredients || []),
       JSON.stringify(steps || []), req.params.id]
    );
    if (!result.rows.length) return res.status(404).json({ error: 'Not found' });
    res.json(result.rows[0]);
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// ── DELETE recipe ──
app.delete('/api/recipes/:id', requireAuth, async (req, res) => {
  try {
    const result = await pool.query('DELETE FROM recipes WHERE id=$1 RETURNING id', [req.params.id]);
    if (!result.rows.length) return res.status(404).json({ error: 'Not found' });
    res.json({ deleted: true, id: req.params.id });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// ── GET intro pages ──
app.get('/api/intro', async (req, res) => {
  try {
    const result = await pool.query('SELECT * FROM intro_pages ORDER BY display_order');
    res.json(result.rows);
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// ── Serve frontend ──
app.get('*', (req, res) => {
  res.sendFile(path.join(__dirname, 'index.html'));
});

